// Practice Bank — Days 16–30 (Modal Verbs + Advanced Grammar)
// 300 Hindi→English questions per day × 15 days = 4,500 questions total
// Format mirrors practiceData.js / practiceData-days31-75.js

export const DAY_16_EXTRA = [
  // ── CAN ──────────────────────────────────────────────────────────────────
  { id:'d16-extra-001', hindi:'मैं तैर सकता हूँ।', english:'I can swim.', alternatives:['i am able to swim.'], hint:'Can + base verb (ability)', explanation:'Can expresses present ability. Never add -s or -ing after can. "I can swims" is a common Indian English error. Use "am able to" as a formal alternative.', difficulty:'easy', type:'translation', tags:['can','modal-verb','ability'], usageNote:'Use can for ability (present), permission (informal), and polite requests.', office:'I can prepare the report by Friday.', conversation:'A: Can you swim? B: Yes, I can swim very well.' },
  { id:'d16-extra-002', hindi:'क्या तुम गाड़ी चला सकते हो?', english:'Can you drive?', alternatives:['are you able to drive?','do you know how to drive?'], hint:'Can + subject + base verb (question)', explanation:'In questions, can comes before the subject. Never say "You can drive?" as a question in formal English. "Can you drive?" is correct and natural.', difficulty:'easy', type:'translation', tags:['can','question','driving'], usageNote:'Questions with can are polite and common in daily conversation.', office:'Can you drive the company vehicle to the airport?', conversation:'A: Can you drive? B: Yes, I got my license last year.' },
  { id:'d16-extra-003', hindi:'वह तीन भाषाएँ बोल सकती है।', english:'She can speak three languages.', alternatives:['she is able to speak three languages.','she knows three languages.'], hint:'Can + base verb (no -s for third person)', explanation:'Modal verbs like can never change form. "She cans" or "she can speaks" are wrong. The base verb follows directly. This is a frequent mistake by Hindi speakers.', difficulty:'easy', type:'translation', tags:['can','languages','ability'], usageNote:'Can + base verb stays the same for all persons (I/you/he/she/they can).', office:'She can speak English, Hindi, and French fluently.', conversation:'A: How many languages does she know? B: She can speak three languages.' },
  { id:'d16-extra-004', hindi:'मैं आज उपस्थित नहीं हो सकता।', english:"I can't attend today.", alternatives:['i cannot attend today.','i am unable to attend today.'], hint:"Can't / cannot + base verb (negative)", explanation:"Can't is the contracted form of cannot. Both are equally correct. In formal writing, cannot (one word) is preferred. 'I am not able to attend' is also acceptable.", difficulty:'easy', type:'translation', tags:['can','negative','attendance'], usageNote:"Use can't or cannot for present inability. Never write 'can not' as two separate words in standard usage.", office:"I can't attend the 10 AM meeting today due to a prior commitment.", conversation:"A: Will you join the call? B: I can't attend today, but I'll review the recording." },
  { id:'d16-extra-005', hindi:'क्या वह इस समस्या को हल कर सकता है?', english:'Can he solve this problem?', alternatives:['is he able to solve this problem?'], hint:'Can + subject + base verb (question, third person)', explanation:'Questions with can are formed by inverting can and the subject. The base verb follows. Never use "does" with can: "Does he can solve?" is wrong.', difficulty:'medium', type:'translation', tags:['can','question','problem-solving'], usageNote:'Use can for questions about ability or possibility.', office:'Can he solve the software bug before the deadline?', conversation:'A: This is a complex problem. B: Can he solve this problem? He is an expert.' },
  { id:'d16-extra-006', hindi:'तुम यह कर सकते हो!', english:'You can do it!', alternatives:['you are capable of doing it!','you can make it!'], hint:'Can + base verb (encouragement)', explanation:'You can do it! is a standard English phrase for encouragement. It expresses belief in someone\'s ability. "You are able to do it" is more formal but less natural.', difficulty:'easy', type:'translation', tags:['can','encouragement','motivation'], usageNote:'Can is used for expressing confidence in someone\'s ability.', office:'You can do it! This presentation will be excellent.', conversation:'A: I am nervous about the interview. B: You can do it! You are well prepared.' },
  { id:'d16-extra-007', hindi:'मैं पियानो बजा सकता हूँ।', english:'I can play the piano.', alternatives:['i know how to play the piano.','i am able to play the piano.'], hint:'Can + play + instrument (use "the" before instrument name)', explanation:'When talking about playing musical instruments, use "the" before the instrument name. "I can play piano" (without the) is an Indian English error.', difficulty:'easy', type:'translation', tags:['can','music','instruments'], usageNote:'Always say "play the piano/guitar/violin" — the definite article is required with instruments.', office:'I can play the piano at the office cultural event.', conversation:'A: Do you have any talent? B: I can play the piano and the guitar.' },
  { id:'d16-extra-008', hindi:'वह बहुत तेज़ दौड़ सकता है।', english:'He can run very fast.', alternatives:['he is able to run very fast.'], hint:'Can + base verb + adverb', explanation:'"Very fast" is an adverbial phrase placed after the verb. "He can very fast run" is an incorrect word order. Adverbs typically follow the verb or verb phrase.', difficulty:'easy', type:'translation', tags:['can','speed','adverb'], usageNote:'Place adverbs like "very fast" after the main verb, not between can and the verb.', office:'He can complete tasks very fast under pressure.', conversation:'A: Who should run the errand? B: Ask Rajan — he can run very fast.' },
  { id:'d16-extra-009', hindi:'क्या मैं यहाँ बैठ सकता हूँ?', english:'Can I sit here?', alternatives:['may I sit here?','is it okay if I sit here?'], hint:'Can I + base verb (permission request)', explanation:'"Can I sit here?" is common for seeking permission in informal contexts. "May I sit here?" is more formal and polite, especially in professional settings.', difficulty:'easy', type:'translation', tags:['can','permission','polite'], usageNote:'"May I" is more formal than "Can I" for permission. Both are widely accepted.', office:'Can I sit in the conference room for my call?', conversation:'A: Can I sit here? B: Of course, please go ahead.' },
  { id:'d16-extra-010', hindi:'बच्चे खूब खेल सकते हैं।', english:'Children can play a lot.', alternatives:['kids can play for a long time.'], hint:'Can + base verb (general ability)', explanation:'Can here expresses general capability of children. "A lot" goes after the verb phrase. "Children can a lot play" is incorrect word order.', difficulty:'easy', type:'translation', tags:['can','children','ability'], usageNote:'Can expresses general ability applicable to a group.', office:'Children can learn a lot in an engaging classroom environment.', conversation:'A: Are the children tired? B: No, children can play a lot without getting tired.' },
  { id:'d16-extra-011', hindi:'मैं खाना बना सकती हूँ।', english:'I can cook food.', alternatives:['i know how to cook.','i am able to cook.'], hint:'Can + base verb (skill)', explanation:'"Cook food" is correct. In British/American English, you can also say "I can cook" without "food". "I can do cooking" is an Indian English error — use the base verb directly.', difficulty:'easy', type:'translation', tags:['can','cooking','skill'], usageNote:'Use can + base verb for skills: can cook, can drive, can swim.', office:'I can cook for the team lunch on Friday.', conversation:'A: Who will make dinner? B: I can cook food — I know several recipes.' },
  { id:'d16-extra-012', hindi:'क्या तुम मेरी मदद कर सकते हो?', english:'Can you help me?', alternatives:['could you help me?','would you help me?'], hint:'Can you + base verb (request)', explanation:'"Can you help me?" is a direct, polite request. "Could you help me?" is even more polite and preferred in formal/office settings. Never say "Can you help to me?" — no "to" is needed.', difficulty:'easy', type:'translation', tags:['can','request','help'], usageNote:'For polite requests in office, prefer "Could you help me?" over "Can you help me?"', office:'Can you help me review this document before the meeting?', conversation:'A: Can you help me with this form? B: Sure, what do you need?' },
  { id:'d16-extra-013', hindi:'वे अंग्रेज़ी में लिख सकते हैं।', english:'They can write in English.', alternatives:['they are able to write in English.'], hint:'Can + write + in + language', explanation:'"Write in English" uses the preposition "in" before the language. "Write English" (without "in") is also acceptable but less formal. "Write on English" is incorrect.', difficulty:'easy', type:'translation', tags:['can','writing','language'], usageNote:'Say "write in English/Hindi" to specify the language of writing.', office:'They can write detailed reports in English.', conversation:'A: Can your team communicate in English? B: Yes, they can write in English fluently.' },
  { id:'d16-extra-014', hindi:'मैं नहीं गा सकता।', english:"I can't sing.", alternatives:['i cannot sing.','i am unable to sing.'], hint:"Can't + base verb (negative)", explanation:'"I can\'t sing" expresses inability. Do not say "I can\'t singing" — can\'t is always followed by the base verb. "I have no singing ability" is a wordy alternative.', difficulty:'easy', type:'translation', tags:['can','negative','singing'], usageNote:"Can't is conversational; cannot is formal. Both follow the same base verb rule.", office:"I can't sing but I can present the annual day program.", conversation:"A: Will you perform at the event? B: I can't sing, but I can play the guitar." },
  { id:'d16-extra-015', hindi:'वह तेज़ टाइप कर सकती है।', english:'She can type fast.', alternatives:['she is a fast typist.','she can type quickly.'], hint:'Can + base verb (skill, speed)', explanation:'"Type fast" is natural. "She can do typing fast" is an Indian English error. Use can + base verb directly. Fast and quickly are both acceptable adverbs here.', difficulty:'easy', type:'translation', tags:['can','typing','office-skill'], usageNote:'Office skill: She can type fast is a concise, professional way to describe typing ability.', office:'She can type fast, which makes her great for data entry roles.', conversation:'A: We need someone for the documentation. B: Ask Priya — she can type fast.' },
  { id:'d16-extra-016', hindi:'क्या आप हिंदी बोल सकते हैं?', english:'Can you speak Hindi?', alternatives:['do you speak Hindi?','are you able to speak Hindi?'], hint:'Can you + base verb + language', explanation:'"Can you speak Hindi?" asks about present ability. "Do you speak Hindi?" is also correct and more commonly used in general conversation. Both are grammatically valid.', difficulty:'easy', type:'translation', tags:['can','language','hindi'], usageNote:'Both "Can you speak?" and "Do you speak?" are natural for asking about language ability.', office:'Can you speak Hindi for the new recruits from North India?', conversation:'A: Can you speak Hindi? B: Yes, I can speak it fluently.' },
  { id:'d16-extra-017', hindi:'हम सब साथ मिलकर यह काम कर सकते हैं।', english:'We can all do this work together.', alternatives:['we can all work on this together.'], hint:'We can + all + base verb (teamwork)', explanation:'"All" is placed after the subject pronoun (we all can / we can all). Both positions are grammatically correct. "Together" emphasizes collective effort.', difficulty:'medium', type:'translation', tags:['can','teamwork','together'], usageNote:'"We can all" or "all of us can" — both express collective ability naturally.', office:'We can all contribute to this project if we coordinate well.', conversation:'A: This task looks difficult. B: We can all do this work together — no need to worry.' },
  { id:'d16-extra-018', hindi:'मैं उसे पहचान सकता हूँ।', english:'I can recognize him.', alternatives:['I am able to recognize him.','I can identify him.'], hint:'Can + base verb (mental/perceptual ability)', explanation:'"Recognize" is a state verb — it describes perception, not a continuous action. Do not say "I can be recognizing him." Use the base verb form directly after can.', difficulty:'medium', type:'translation', tags:['can','recognition','perception'], usageNote:'State verbs (recognize, know, understand) are used in base form after can, never in -ing form.', office:'I can recognize the client from the profile photo sent earlier.', conversation:'A: Do you know him? B: Yes, I can recognize him from the conference last year.' },
  { id:'d16-extra-019', hindi:'क्या मैं आपसे एक सवाल पूछ सकता हूँ?', english:'Can I ask you a question?', alternatives:['may I ask you a question?','could I ask you something?'], hint:'Can I + base verb + object (permission)', explanation:'"Can I ask you a question?" is perfectly natural in both informal and semi-formal settings. "May I ask?" is more formal. "I can ask you a question?" as a statement-question is incorrect.', difficulty:'easy', type:'translation', tags:['can','permission','question'], usageNote:'In interviews and formal settings, "May I ask...?" shows more deference than "Can I ask...?"', office:'Can I ask you a question about the project timeline?', conversation:'A: Can I ask you a question? B: Of course, go ahead.' },
  { id:'d16-extra-020', hindi:'मैं खुद यह कर सकता हूँ।', english:'I can do this myself.', alternatives:['I can handle this on my own.','I can manage this myself.'], hint:'Can + base verb + reflexive pronoun', explanation:'"Myself" adds emphasis that no help is needed. It follows the object. "I can do this by myself" (using "by") is an equally common and correct alternative.', difficulty:'easy', type:'translation', tags:['can','independence','reflexive'], usageNote:'"By myself" (= alone) and "myself" (= without help) are interchangeable in this context.', office:'I can do this report myself — you do not need to assign anyone else.', conversation:'A: Do you need help? B: No, I can do this myself, thank you.' },
  { id:'d16-extra-021', hindi:'वह पेड़ पर चढ़ सकता है।', english:'He can climb a tree.', alternatives:['he is able to climb trees.'], hint:'Can + climb + object', explanation:'"Climb a tree" is the natural phrasing. "Climb on a tree" is incorrect in standard English. After can, always use the base verb without any auxiliary.', difficulty:'easy', type:'translation', tags:['can','climbing','physical-ability'], usageNote:'After can, always use the base verb: climb (not climbs, not climbing).', office:'He can climb the ladder quickly during the warehouse audit.', conversation:'A: Can he reach the top shelf? B: Yes, he can climb a tree — a ladder is no problem.' },
  { id:'d16-extra-022', hindi:'मैं जल्दी सीख सकती हूँ।', english:'I can learn quickly.', alternatives:['I am a quick learner.','I can pick things up fast.'], hint:'Can + base verb + adverb (speed)', explanation:'"Learn quickly" is the standard order. "I can quickly learn" is also grammatically correct (adverb before verb). Both are acceptable in modern English.', difficulty:'easy', type:'translation', tags:['can','learning','adverb'], usageNote:'"I can learn quickly" or "I am a quick learner" are both effective in interviews.', office:'I can learn quickly and adapt to new software systems.', conversation:'A: Do you have experience with this tool? B: No, but I can learn quickly.' },
  { id:'d16-extra-023', hindi:'क्या तुम रात को काम कर सकते हो?', english:'Can you work at night?', alternatives:['are you able to work night shifts?'], hint:'Can you + base verb + time expression', explanation:'"At night" is the correct preposition phrase for working during night hours. "In the night" is used in poetry/literary contexts, not everyday business English.', difficulty:'easy', type:'translation', tags:['can','work','night'], usageNote:'"At night" is standard. "In the night" sounds literary; avoid it in professional contexts.', office:'Can you work at night for the US client time zone?', conversation:'A: Can you work at night? B: Yes, I can manage night shifts occasionally.' },
  { id:'d16-extra-024', hindi:'वह बहुत अच्छी तरह से नाच सकती है।', english:'She can dance very well.', alternatives:['she is an excellent dancer.','she dances very well.'], hint:'Can + base verb + adverb phrase', explanation:'"Very well" is an adverb phrase placed at the end. "She can dance very good" is incorrect — use "well" (adverb), not "good" (adjective) to modify a verb.', difficulty:'easy', type:'translation', tags:['can','dance','adverb'], usageNote:'Use "well" (not "good") to modify verbs: she dances well / she can cook well.', office:'She can present very well in front of large audiences.', conversation:'A: Is she talented? B: She can dance very well — she trained for eight years.' },
  { id:'d16-extra-025', hindi:'मैं यह बोझ उठा सकता हूँ।', english:'I can lift this load.', alternatives:['I am able to carry this weight.','I can carry this.'], hint:'Can + base verb + object', explanation:'"Lift this load" is standard. In office/professional contexts, "I can handle this workload" is the metaphorical equivalent showing the same can + base verb structure.', difficulty:'easy', type:'translation', tags:['can','physical','strength'], usageNote:'Can + lift/carry are common for physical tasks. In offices, "handle" replaces "lift" metaphorically.', office:'I can lift this responsibility — please assign me to the new project.', conversation:'A: That box looks heavy. B: Do not worry, I can lift this load easily.' },
  { id:'d16-extra-026', hindi:'हम दोनों साथ जा सकते हैं।', english:'We can both go together.', alternatives:['both of us can go together.'], hint:'We can + both + base verb', explanation:'"We can both go together" is natural. "Both" can also be placed before "we": "Both of us can go together." Do not say "We both can to go" — no "to" after can.', difficulty:'easy', type:'translation', tags:['can','together','plural'], usageNote:'"Both" can appear before or after the subject with can. Never use "to" after can.', office:'We can both attend the client meeting together for better coverage.', conversation:'A: Who should go to the event? B: We can both go together — it will save time.' },
  { id:'d16-extra-027', hindi:'क्या वे जल्दी आ सकते हैं?', english:'Can they come early?', alternatives:['are they able to come early?','is it possible for them to come early?'], hint:'Can + subject + base verb (question)', explanation:'"Can they come early?" is a yes/no question about ability or possibility. The inversion (can before subject) is mandatory in formal questions. "They can come early?" is informal only.', difficulty:'easy', type:'translation', tags:['can','question','time'], usageNote:'Invert can and subject for questions: Can they / Can she / Can we.', office:'Can they come early to help set up the presentation?', conversation:'A: The clients are already here. B: Can they come early? They were scheduled for 11 AM.' },
  { id:'d16-extra-028', hindi:'मुझे समझ नहीं आता कि वह क्या कह रहा है।', english:"I can't understand what he is saying.", alternatives:["I don't understand what he is saying.","I am unable to understand him."], hint:"Can't + understand + what-clause", explanation:'"Can\'t understand" expresses inability to comprehend. "I can\'t understand him" is also correct. Note that "understand" is a state verb — do not say "I am not understanding" in standard English.', difficulty:'medium', type:'translation', tags:['can','understanding','communication'], usageNote:'State verbs (understand, know, believe) are not used in continuous tenses in standard English.', office:"I can't understand what he is saying — could you interpret for me?", conversation:"A: Did you get what he explained? B: No, I can't understand what he is saying. It's too fast." },
  { id:'d16-extra-029', hindi:'वह बिना रुके घंटों बोल सकता है।', english:'He can talk for hours without stopping.', alternatives:['he can speak for hours at a stretch.'], hint:'Can + base verb + duration phrase', explanation:'"For hours without stopping" is the duration phrase. The sentence shows impressive ability. "Without stopping" is a gerund phrase used as an adverbial modifier.', difficulty:'medium', type:'translation', tags:['can','speaking','endurance'], usageNote:'"For hours" = duration; "without stopping" = manner. Together they emphasize sustained ability.', office:'He can present for hours without stopping and keep the audience engaged.', conversation:'A: Is he a good speaker? B: He can talk for hours without stopping.' },
  { id:'d16-extra-030', hindi:'मैं अंधेरे में भी रास्ता ढूंढ सकता हूँ।', english:'I can find my way even in the dark.', alternatives:['I can navigate even in darkness.'], hint:'Can + base verb + even + prepositional phrase', explanation:'"Even in the dark" emphasizes ability under difficult conditions. "Even" adds contrast/surprise. "I can find way in dark" (missing articles) is a common Indian English mistake.', difficulty:'medium', type:'translation', tags:['can','navigation','challenge'], usageNote:'Articles "my" and "the" are essential: "find my way" and "in the dark."', office:'I can find a solution even in the most challenging situations.', conversation:'A: The power is out! B: Do not worry, I can find my way even in the dark.' },
  { id:'d16-extra-031', hindi:'क्या तुम मुझे समझा सकते हो?', english:'Can you explain it to me?', alternatives:['can you make me understand?','could you explain this to me?'], hint:'Can you + base verb + object + to + me', explanation:'"Explain it to me" is the correct structure. "Explain me" without "to" is a very common Indian English error. Always say "explain something to someone," never "explain someone something."', difficulty:'medium', type:'translation', tags:['can','explain','request'], usageNote:'Explain always needs "to": explain it to me / explain the concept to the class.', office:'Can you explain the new process to me before tomorrow\'s meeting?', conversation:"A: I didn't understand the instructions. B: Can you explain it to me one more time?" },
  { id:'d16-extra-032', hindi:'वह अकेले पूरे प्रोजेक्ट को संभाल सकती है।', english:'She can manage the entire project alone.', alternatives:['she can handle the whole project by herself.'], hint:'Can + manage + object + alone', explanation:'"Manage the entire project alone" shows strong capability. "Alone" and "by herself" are both correct. "She can manage entire project alone" (missing "the") is incorrect.', difficulty:'medium', type:'translation', tags:['can','project-management','independence'], usageNote:'Use "the entire" or "the whole" before a countable noun. Never drop the article.', office:'She can manage the entire project alone — she has done it before.', conversation:'A: Who should lead this? B: She can manage the entire project alone.' },
  { id:'d16-extra-033', hindi:'मैं मराठी और तमिल दोनों पढ़ सकता हूँ।', english:'I can read both Marathi and Tamil.', alternatives:['I am able to read Marathi as well as Tamil.'], hint:'Can + read + both X and Y', explanation:'"Both...and" is a correlative conjunction connecting two items. "I can read both Marathi and Tamil" is grammatically tight and clear. "I can read Marathi and also Tamil" is also acceptable.', difficulty:'medium', type:'translation', tags:['can','reading','languages'], usageNote:'"Both X and Y" emphasizes that two things are equally true — useful in interviews.', office:'I can read both Marathi and Tamil, which helps with our regional clients.', conversation:'A: Which Indian scripts do you know? B: I can read both Marathi and Tamil.' },
  { id:'d16-extra-034', hindi:'क्या तुम यह फ़ाइल खोल सकते हो?', english:'Can you open this file?', alternatives:['are you able to open this file?'], hint:'Can you + open + object (tech request)', explanation:'"Open this file" is a common tech-related request. "Can you open this file?" is natural in office settings. "Could you open this file?" is slightly more formal.', difficulty:'easy', type:'translation', tags:['can','technology','office'], usageNote:'In IT/office contexts, "Can you open / Can you access / Can you share" are all standard.', office:'Can you open this file on your laptop? Mine is not working.', conversation:'A: I need to see the spreadsheet. B: Can you open this file? I will share my screen.' },
  { id:'d16-extra-035', hindi:'मैं बिना चश्मे के पढ़ नहीं सकता।', english:"I can't read without my glasses.", alternatives:["I cannot read without glasses.","I am unable to read without spectacles."], hint:"Can't + base verb + without (negative ability)", explanation:'"Without my glasses" is a prepositional phrase expressing condition. "I can\'t read without glasses" (without "my") is also acceptable. "Spectacles" is more formal than "glasses."', difficulty:'easy', type:'translation', tags:['can','reading','glasses'], usageNote:'"Glasses" is more common in everyday English; "spectacles" is formal/British.', office:"I can't read the small print on this contract without my glasses.", conversation:"A: Can you read the whiteboard? B: I can't read without my glasses. I left them at home." },
  { id:'d16-extra-036', hindi:'वे सुबह से शाम तक काम कर सकते हैं।', english:'They can work from morning to evening.', alternatives:['they can work from dawn to dusk.'], hint:'Can + work + from X to Y (time range)', explanation:'"From morning to evening" expresses a time range. "From dawn to dusk" is a more literary alternative. "They can work morning to evening" (missing "from") is slightly informal.', difficulty:'easy', type:'translation', tags:['can','work-hours','endurance'], usageNote:'"From X to Y" is the standard preposition pair for time ranges.', office:'They can work from morning to evening to meet the project deadline.', conversation:'A: Are they hardworking? B: They can work from morning to evening without complaint.' },
  { id:'d16-extra-037', hindi:'मैं यह गाना गुनगुना सकता हूँ।', english:'I can hum this song.', alternatives:['I know how to hum this song.'], hint:'Can + hum + object', explanation:'"Hum" means to sing without words. "I can hum this song" is natural. "I can hum of this song" is incorrect — no preposition needed between "hum" and its object.', difficulty:'easy', type:'translation', tags:['can','music','singing'], usageNote:'Direct object after hum: hum a song, hum a tune — no preposition.', office:'I can hum this jingle for the advertisement voiceover.', conversation:"A: Do you know this tune? B: Yes, I can hum this song, though I don't know all the lyrics." },
  { id:'d16-extra-038', hindi:'क्या तुम समय पर पहुँच सकते हो?', english:'Can you arrive on time?', alternatives:['can you be there on time?','are you able to reach on time?'], hint:'Can you + arrive + on time', explanation:'"Arrive on time" means to be punctual. "Reach on time" is common in Indian English and is understood. However, "arrive on time" is the internationally standard phrasing.', difficulty:'easy', type:'translation', tags:['can','punctuality','time'], usageNote:'"Arrive on time" is globally standard. "Reach on time" is Indian English but widely understood.', office:'Can you arrive on time for the client presentation at 9 AM?', conversation:"A: Can you arrive on time? B: Yes, I'll be there fifteen minutes early." },
  { id:'d16-extra-039', hindi:'वह पानी के अंदर सांस रोक सकता है।', english:'He can hold his breath underwater.', alternatives:['he is able to hold his breath under water.'], hint:'Can + hold + breath + underwater', explanation:'"Hold his breath" is an idiomatic expression. "Hold breath under water" is Indian English — use "underwater" as one word or "hold his breath under water" as two words. Both are acceptable.', difficulty:'medium', type:'translation', tags:['can','physical','swimming'], usageNote:'"Hold one\'s breath" is idiomatic. The possessive (his/her/my) must match the subject.', office:'He can hold his breath in tense situations and deliver results calmly.', conversation:'A: Is he a good diver? B: He can hold his breath underwater for over two minutes.' },
  { id:'d16-extra-040', hindi:'मैं एक्सेल में जटिल फ़ॉर्मूले बना सकती हूँ।', english:'I can create complex formulas in Excel.', alternatives:['I can build complex formulas in Excel.','I know how to use Excel formulas.'], hint:'Can + create + complex + object + in + tool', explanation:'"Create formulas in Excel" is the standard phrasing in tech/office settings. "Make formulas" is also acceptable. "I can do complex formulas" is an Indian English simplification that still communicates the meaning.', difficulty:'medium', type:'translation', tags:['can','excel','office-skill'], usageNote:'"Create / build / use" are all valid verbs for Excel skills in a professional resume or interview.', office:'I can create complex formulas in Excel for the monthly financial analysis.', conversation:"A: Can you handle our data? B: I can create complex formulas in Excel — that won't be a problem." },
  { id:'d16-extra-041', hindi:'क्या बच्चे यह सब समझ सकते हैं?', english:'Can children understand all of this?', alternatives:['are children able to understand all this?'], hint:'Can + subject + base verb + all of this', explanation:'"All of this" refers to the full content. "Can children understand all this?" is also correct — "of" can be omitted. Never say "Can children understand all these?" for a singular complex topic.', difficulty:'medium', type:'translation', tags:['can','children','comprehension'], usageNote:'"All of this" refers to a body of content; "all of these" refers to specific multiple items.', office:'Can the new employees understand all of this documentation on day one?', conversation:'A: The manual is very detailed. B: Can children understand all of this? It seems very complex.' },
  { id:'d16-extra-042', hindi:'तुम अकेले यह नहीं कर सकते।', english:"You can't do this alone.", alternatives:['you cannot do this by yourself.','you are unable to do this alone.'], hint:"Can't + base verb + alone (negative ability)", explanation:'"You can\'t do this alone" can express either inability or a gentle warning. Context determines meaning. "You cannot handle this alone" is more formal.', difficulty:'easy', type:'translation', tags:['can','teamwork','negative'], usageNote:'"You can\'t do this alone" can be advisory or factual depending on tone.', office:"You can't manage this entire project alone — let's form a team.", conversation:"A: I want to handle this myself. B: You can't do this alone. You will need some support." },
  { id:'d16-extra-043', hindi:'मैं घर पर रहकर काम कर सकता हूँ।', english:'I can work from home.', alternatives:['I am able to work remotely.','I can do my work from home.'], hint:'Can + work + from home (remote work)', explanation:'"Work from home" is now standard global terminology (WFH). "Do work from home" and "work remotely" are synonymous. "Work at home" is less common but not incorrect.', difficulty:'easy', type:'translation', tags:['can','remote-work','office'], usageNote:'"Work from home" is the standard phrase; "work remotely" is formal/corporate.', office:'I can work from home on days when I have no client meetings.', conversation:'A: The office is far from your house. B: That is fine — I can work from home three days a week.' },
  { id:'d16-extra-044', hindi:'वह बिना सोचे जवाब दे सकती है।', english:'She can answer without thinking.', alternatives:['she can respond instantly.','she can reply without hesitation.'], hint:'Can + answer + without + gerund', explanation:'"Without thinking" is a gerund phrase acting as an adverb. It describes the manner of answering. "She can answer without to think" is incorrect — use the gerund, not the infinitive, after without.', difficulty:'medium', type:'translation', tags:['can','quick-thinking','ability'], usageNote:'"Without + gerund" (without thinking, without stopping) is always used after without — never an infinitive.', office:'She can answer client queries without thinking — she knows the product inside out.', conversation:"A: She is impressive! B: She can answer without thinking — years of experience, I suppose." },
  { id:'d16-extra-045', hindi:'क्या तुम कल मेरे लिए यह काम कर सकते हो?', english:'Can you do this work for me tomorrow?', alternatives:['could you do this for me tomorrow?','would you be able to do this tomorrow?'], hint:'Can you + base verb + for me + time (request)', explanation:'"For me" positions the beneficiary. "Can you do this work for me tomorrow?" is a natural, direct request. For greater politeness in professional settings, use "Could you...?" instead.', difficulty:'medium', type:'translation', tags:['can','request','tomorrow'], usageNote:'"Could you?" is more polite than "Can you?" for asking favors at work.', office:'Can you do this work for me tomorrow? I have back-to-back meetings all day.', conversation:"A: Can you do this work for me tomorrow? B: Sure, I'll take care of it." },
  { id:'d16-extra-046', hindi:'मैं खुद अपने निर्णय ले सकता हूँ।', english:'I can make my own decisions.', alternatives:['I am capable of making my own decisions.','I can decide for myself.'], hint:'Can + make + possessive + decisions', explanation:'"Make decisions" is the standard collocation — not "take decisions" which is Indian English. Both are understood, but "make a decision" is globally preferred in business communication.', difficulty:'medium', type:'translation', tags:['can','decision-making','independence'], usageNote:'"Make a decision" is global standard; "take a decision" is common in Indian and British English.', office:'I can make my own decisions regarding client communications.', conversation:"A: Do you always ask your manager? B: No, I can make my own decisions when it's within my authority." },
  { id:'d16-extra-047', hindi:'क्या आप इसे दोबारा समझा सकते हैं?', english:'Can you explain this again?', alternatives:['could you explain this once more?','would you mind repeating that?'], hint:'Can you + explain + this + again', explanation:'"Can you explain this again?" is polite. "Could you please explain this again?" adds more politeness. "Repeat that" is slightly more casual. In formal settings, "Would you mind clarifying this?" is excellent.', difficulty:'easy', type:'translation', tags:['can','clarification','polite'], usageNote:'"Could you explain?" is more polite than "Can you explain?" in formal/educational contexts.', office:'Can you explain this data point again? I want to make sure I understand it correctly.', conversation:'A: I did not follow the last part. B: Can you explain this again, please?' },
  { id:'d16-extra-048', hindi:'वह बहुत जल्दी हिसाब लगा सकता है।', english:'He can calculate very quickly.', alternatives:['he can do calculations very fast.','he is very good at calculations.'], hint:'Can + calculate + very quickly', explanation:'"Calculate very quickly" is the correct word order. "Very quickly" is an adverb phrase. "He can very quickly calculate" is also grammatically correct (split adverb placement).', difficulty:'easy', type:'translation', tags:['can','math','speed'], usageNote:'Adverb placement: "calculate very quickly" (after verb) is most natural in spoken English.', office:'He can calculate very quickly, which makes him excellent at financial analysis.', conversation:"A: Does he need a calculator? B: No, he can calculate very quickly in his head." },
  { id:'d16-extra-049', hindi:'मैं इस फ़ॉर्म को ऑनलाइन भर सकता हूँ।', english:'I can fill out this form online.', alternatives:['I can complete this form online.','I am able to fill in this form online.'], hint:'Can + fill out + form + online', explanation:'"Fill out a form" is standard in American English. "Fill in a form" is more common in British English. Both are correct. "Fill up a form" is Indian English — avoid in international contexts.', difficulty:'easy', type:'translation', tags:['can','forms','online'], usageNote:'"Fill out" (AmE) and "fill in" (BrE) are both correct. Avoid "fill up" in formal contexts.', office:'I can fill out this form online and email it to HR.', conversation:'A: The form needs to be submitted. B: I can fill out this form online. It will only take a minute.' },
  { id:'d16-extra-050', hindi:'क्या कोई मेरी मदद कर सकता है?', english:'Can anyone help me?', alternatives:['is there anyone who can help me?','can somebody assist me?'], hint:'Can + anyone + base verb (general request)', explanation:'"Can anyone help me?" is a general appeal for assistance. "Somebody" and "anyone" are both correct in questions. "Can someone help me?" is slightly more polite and natural.', difficulty:'easy', type:'translation', tags:['can','help','general'], usageNote:'In questions: "anyone" (general) and "someone" (expecting yes) have subtle differences. Both are natural.', office:'Can anyone help me with the projector setup before the meeting?', conversation:"A: I'm struggling with this error. B: Can anyone help me? It's been an hour." },
  { id:'d16-extra-051', hindi:'वह एक हाथ से लिख सकता है।', english:'He can write with one hand.', alternatives:['he is able to write with a single hand.'], hint:'Can + write + with + one hand', explanation:'"With one hand" is a prepositional phrase showing manner. "By one hand" is incorrect. "He can write one hand" (missing "with") is a common Indian English error.', difficulty:'easy', type:'translation', tags:['can','writing','physical'], usageNote:'"With one hand" is the only correct preposition phrase for this ability. Never "by one hand."', office:'He can write with one hand while typing with the other — multitasking expert!', conversation:'A: How does he manage? B: He can write with one hand quite efficiently.' },
  { id:'d16-extra-052', hindi:'क्या हम यहाँ बात कर सकते हैं?', english:'Can we talk here?', alternatives:['may we speak here?','is it okay if we talk here?'], hint:'Can we + base verb + here (permission/ability)', explanation:'"Can we talk here?" asks if it is possible or permissible to speak in this location. It can be a request for permission or a check on suitability. "May we speak here?" is more formal.', difficulty:'easy', type:'translation', tags:['can','conversation','permission'], usageNote:'"Can we talk?" is casual; "May we speak?" is formal. The difference is register, not correctness.', office:'Can we talk here privately, or should we move to a conference room?', conversation:'A: I need to tell you something. B: Can we talk here, or is this a bad time?' },
  { id:'d16-extra-053', hindi:'मैं घोड़े पर सवारी कर सकता हूँ।', english:'I can ride a horse.', alternatives:['I know how to ride horses.','I am able to ride a horse.'], hint:'Can + ride + a + horse', explanation:'"Ride a horse" is the standard phrasing. "Do horse riding" is Indian English — acceptable informally but "ride a horse" is standard globally. After can, always use the base verb ride.', difficulty:'easy', type:'translation', tags:['can','horse-riding','sport'], usageNote:'"Ride a horse" is standard. "Do horse riding" is understood but not ideal in formal contexts.', office:'I can ride a horse, which is useful for the countryside team-building event.', conversation:"A: Have you ever been to a horse ranch? B: Yes! I can ride a horse — it's one of my hobbies." },
  { id:'d16-extra-054', hindi:'वे बहुत अच्छे से खाना बना सकते हैं।', english:'They can cook very well.', alternatives:['they are excellent cooks.','they can cook really well.'], hint:'Can + cook + very well', explanation:'"Cook very well" is standard. "Cook good" (using adjective instead of adverb) is incorrect. Always use "well" (adverb) to describe how someone performs an action.', difficulty:'easy', type:'translation', tags:['can','cooking','adverb'], usageNote:'Adverb rule: "do/cook/drive well" — use well, not good, to modify a verb.', office:'They can cook very well, so the team lunch is always a treat.', conversation:'A: Who catered the office party? B: The staff team — they can cook very well.' },
  { id:'d16-extra-055', hindi:'क्या तुम यह पत्र लिख सकते हो?', english:'Can you write this letter?', alternatives:['are you able to draft this letter?','could you write this letter?'], hint:'Can you + write + object', explanation:'"Write this letter" is the standard phrasing. "Draft" is more formal and specific to business correspondence. "Compose" is also formal and used for formal letters.', difficulty:'easy', type:'translation', tags:['can','writing','letter'], usageNote:'"Write" is general; "draft" and "compose" are more formal synonyms for professional correspondence.', office:'Can you write this letter to the vendor regarding the payment delay?', conversation:'A: Can you write this letter for me? B: Yes, give me an hour and I will send it over.' },
  { id:'d16-extra-056', hindi:'वह बहुत तेज़ निर्णय ले सकती है।', english:'She can make quick decisions.', alternatives:['she is a quick decision-maker.','she can decide quickly.'], hint:'Can + make + quick + decisions', explanation:'"Make quick decisions" is the correct collocation. "Take quick decisions" is Indian English. "She can make decisions quickly" is also correct — the adverb can move.', difficulty:'medium', type:'translation', tags:['can','decision-making','leadership'], usageNote:'"Make decisions" is globally standard. "Take decisions" is common in Indian and British English.', office:'She can make quick decisions under pressure, which makes her ideal for crisis management.', conversation:'A: How does she handle emergencies? B: She can make quick decisions without panicking.' },
  { id:'d16-extra-057', hindi:'मैं इस मशीन को चला सकता हूँ।', english:'I can operate this machine.', alternatives:['I know how to run this machine.','I can handle this equipment.'], hint:'Can + operate + object (machinery)', explanation:'"Operate" is the formal/technical verb for machines. "Run a machine" is also standard. "Handle equipment" is broader. "Drive a machine" is incorrect unless it is a vehicle.', difficulty:'medium', type:'translation', tags:['can','machinery','technical'], usageNote:'For machines: operate/run. For vehicles: drive. Never mix them up.', office:'I can operate this machine and train the new team members.', conversation:'A: Do we need to hire a technician? B: No, I can operate this machine myself.' },
  { id:'d16-extra-058', hindi:'क्या आप अंग्रेज़ी में ईमेल लिख सकते हैं?', english:'Can you write emails in English?', alternatives:['are you able to compose emails in English?'], hint:'Can you + write + emails + in + language', explanation:'"Write emails in English" is the natural phrasing. "Compose" is more formal. "Write emails on English" (wrong preposition) is a common Indian English error — always use "in" for languages.', difficulty:'easy', type:'translation', tags:['can','email','professional'], usageNote:'Preposition for language: write/speak/read "in English" — never "on English."', office:'Can you write emails in English to our international clients?', conversation:'A: We need someone for client correspondence. B: Can you write emails in English? C: Yes, fluently.' },
  { id:'d16-extra-059', hindi:'वह हर मुश्किल को पार कर सकता है।', english:'He can overcome every difficulty.', alternatives:['he can overcome any challenge.','he can face every obstacle.'], hint:'Can + overcome + every + noun', explanation:'"Overcome" means to successfully deal with a problem. "Every" suggests all without exception. "He can overcome every difficulty" is inspirational language used in interviews.', difficulty:'medium', type:'translation', tags:['can','resilience','motivation'], usageNote:'"Overcome every difficulty/challenge" is powerful interview language showing resilience.', office:'He can overcome every difficulty — he has proved this multiple times.', conversation:'A: This project has so many problems! B: Do not worry — he can overcome every difficulty.' },
  { id:'d16-extra-060', hindi:'मैं यह काम बिना किसी की मदद के कर सकता हूँ।', english:'I can do this work without anyone\'s help.', alternatives:['I can handle this independently.','I can manage this on my own.'], hint:"Can + do + work + without + anyone's help", explanation:'"Without anyone\'s help" is a formal negative genitive phrase. "I can do this independently" is more concise and equally strong for professional use. "Without no one\'s help" is a double negative error to avoid.', difficulty:'medium', type:'translation', tags:['can','independence','self-reliance'], usageNote:'"Without anyone\'s help" and "independently" are both strong for professional communication.', office:"I can do this work without anyone's help — I have the full skill set required.", conversation:"A: Do you need assistance? B: I can do this work without anyone's help, thank you." },
  { id:'d16-extra-061', hindi:'क्या तुम इस गाने की धुन बजा सकते हो?', english:'Can you play the tune of this song?', alternatives:['can you play this melody?','can you play this song on your instrument?'], hint:'Can you + play + the + tune', explanation:'"Play the tune" uses "the" because it refers to a specific melody. "Play tune of this song" (missing "the") is incorrect. In music, play the tune/melody/rhythm are all standard.', difficulty:'medium', type:'translation', tags:['can','music','tune'], usageNote:'Use "the" before specific musical elements: play the tune, play the melody, set the beat.', office:'Can you play the tune of the company jingle for the advertisement recording?', conversation:'A: Can you play the tune of this song? B: Yes, give me a moment to set up.' },
  { id:'d16-extra-062', hindi:'हम सब इस नई चुनौती का सामना कर सकते हैं।', english:'We can all face this new challenge.', alternatives:['all of us can meet this new challenge.'], hint:'We can + all + face + object', explanation:'"Face a challenge" is the standard collocation. "Meet a challenge" is also correct. "Do a challenge" is informal (from social media). "Tackle a challenge" is strong for professional contexts.', difficulty:'medium', type:'translation', tags:['can','challenge','teamwork'], usageNote:'"Face / meet / tackle a challenge" are all professional collocations. Choose based on register.', office:'We can all face this new challenge if we work as a unified team.', conversation:'A: The target looks impossible. B: We can all face this new challenge together.' },
  { id:'d16-extra-063', hindi:'वह इतनी जल्दी यह नहीं कर सकती।', english:"She can't do this so quickly.", alternatives:["she cannot do this that quickly.","she is unable to do this so fast."], hint:"Can't + do + this + so quickly", explanation:'"So quickly" refers to the speed being unreasonable. "That quickly" is also natural. "She can\'t do this so fast" is equally correct. "She cannot do this so quick" (adjective) is an error.', difficulty:'medium', type:'translation', tags:['can','negative','speed'], usageNote:'"So quickly/fast" (adverbs) are correct. "So quick" is informal but becoming accepted; "so quickly" is formal standard.', office:"She can't complete the audit so quickly — we need to give her more time.", conversation:"A: Can she finish this today? B: She can't do this so quickly. She needs a few more days." },
  { id:'d16-extra-064', hindi:'मैं रात भर जाग कर काम कर सकता हूँ।', english:'I can work through the night.', alternatives:['I can stay up all night working.','I can work overnight.'], hint:'Can + work + through the night', explanation:'"Work through the night" means to work without sleeping. "Work overnight" is more concise. "Work all the night" is incorrect — never use "all the" before "night" in this context.', difficulty:'medium', type:'translation', tags:['can','dedication','work-hours'], usageNote:'"Through the night" and "overnight" are both standard for all-night work.', office:'I can work through the night if necessary to meet the launch deadline.', conversation:'A: The deadline is at 6 AM. B: Do not worry, I can work through the night.' },
  { id:'d16-extra-065', hindi:'क्या वह इस स्थिति को नियंत्रित कर सकता है?', english:'Can he control this situation?', alternatives:['is he able to handle this situation?','can he manage this situation?'], hint:'Can + subject + control/handle + object', explanation:'"Control a situation" and "handle a situation" are both correct collocations. "Manage a situation" is also fine. "Do control the situation" is incorrect — do not use "do" with modals.', difficulty:'medium', type:'translation', tags:['can','leadership','crisis'], usageNote:'"Control / handle / manage a situation" — all valid; choose based on formality of context.', office:'Can he control this situation before it escalates further?', conversation:'A: Things are getting out of hand. B: Can he control this situation? He is the senior manager.' },
  { id:'d16-extra-066', hindi:'तुम जितना सोचते हो उससे ज़्यादा कर सकते हो।', english:'You can do more than you think.', alternatives:['you are more capable than you believe.'], hint:'You can + do + more than + subject + verb', explanation:'"More than you think" is a common motivational structure. "You can do more than what you think" (with "what") is also acceptable. This is a great phrase for mentoring or coaching.', difficulty:'medium', type:'translation', tags:['can','motivation','self-belief'], usageNote:'"More than you think" is a standard comparative clause. "What" can optionally be added without changing meaning.', office:'You can do more than you think — this stretch assignment will prove it.', conversation:'A: I do not think I am good enough. B: You can do more than you think. Trust yourself.' },
  { id:'d16-extra-067', hindi:'मैं एक घंटे में यह पूरा कर सकता हूँ।', english:'I can finish this in an hour.', alternatives:['I can complete this within an hour.','I can wrap this up in an hour.'], hint:'Can + finish + this + in an hour', explanation:'"In an hour" specifies the time frame. "Within an hour" also works. "Finish" and "complete" are interchangeable. "Wrap up" is informal but very natural in spoken English.', difficulty:'easy', type:'translation', tags:['can','time-management','efficiency'], usageNote:'"In an hour" = at the end of an hour; "within an hour" = before an hour passes. Both common.', office:'I can finish this report in an hour if there are no interruptions.', conversation:'A: How long will this take? B: I can finish this in an hour — maybe less.' },
  { id:'d16-extra-068', hindi:'वह बिना किसी गलती के कोड लिख सकता है।', english:'He can write code without any mistakes.', alternatives:['he can code error-free.','he can write flawless code.'], hint:'Can + write + code + without + any mistakes', explanation:'"Without any mistakes" is the negative existence phrase. "Error-free" is a compound adjective (hyphenated). "Flawless" is a formal adjective. All three are valid for professional tech contexts.', difficulty:'medium', type:'translation', tags:['can','coding','precision'], usageNote:'"Write code" is standard; "code" used as a verb ("he can code") is modern and informal.', office:'He can write code without any mistakes, which reduces our debugging time significantly.', conversation:'A: Does he make many errors? B: He can write code without any mistakes — he is very precise.' },
  { id:'d16-extra-069', hindi:'क्या तुम आज शाम मेरे घर आ सकते हो?', english:'Can you come to my house this evening?', alternatives:['can you visit me this evening?','are you free to come over this evening?'], hint:'Can you + come to + place + this evening', explanation:'"Come to my house" is standard. "Come over" is informal and casual. "Visit me" is also natural. "Come at my house" is incorrect — always use "to" not "at" with come.', difficulty:'easy', type:'translation', tags:['can','invitation','evening'], usageNote:'"Come to (a place)" is standard. "Come at" (a place) is incorrect. "Come over" is casual.', office:'Can you come to my house this evening to review the business proposal?', conversation:'A: Can you come to my house this evening? B: Yes, what time shall I be there?' },
  { id:'d16-extra-070', hindi:'मैं नई भाषाएँ जल्दी सीख सकता हूँ।', english:'I can learn new languages quickly.', alternatives:['I pick up new languages quickly.','I have a talent for learning languages fast.'], hint:'Can + learn + new languages + quickly', explanation:'"Learn new languages quickly" is a great skill to mention. "Pick up languages" is idiomatic — to pick up means to learn informally/naturally. Both are excellent in interviews.', difficulty:'medium', type:'translation', tags:['can','languages','learning'], usageNote:'"Pick up a language" (idiomatic) = learn it naturally through exposure.', office:'I can learn new languages quickly — I picked up German in six months.', conversation:'A: Do you know any other languages? B: I can learn new languages quickly — I am studying Japanese now.' },
  { id:'d16-extra-071', hindi:'वह हर तरह के लोगों से अच्छे से मिल सकती है।', english:'She can get along well with all kinds of people.', alternatives:['she can deal well with everyone.','she connects well with people of all types.'], hint:'Can + get along + with + all kinds of people', explanation:'"Get along with" is a phrasal verb meaning to have a good relationship. "Get along well with" emphasizes the quality of the relationship. "Get on well with" is the British English equivalent.', difficulty:'hard', type:'translation', tags:['can','interpersonal','soft-skills'], usageNote:'"Get along with" (AmE) and "get on with" (BrE) both mean to have a good relationship with someone.', office:'She can get along well with all kinds of people — a key strength for client-facing roles.', conversation:'A: Is she good with clients? B: She can get along well with all kinds of people — she is excellent.' },
  { id:'d16-extra-072', hindi:'क्या हम यहाँ रुक सकते हैं?', english:'Can we stop here?', alternatives:['may we pause here?','shall we stop at this point?'], hint:'Can we + stop + here', explanation:'"Can we stop here?" can mean either physically stopping or pausing a discussion/presentation. Context distinguishes the meaning. "Shall we stop here?" is more formal and British.', difficulty:'easy', type:'translation', tags:['can','pause','permission'], usageNote:'"Can we stop here?" (casual) vs. "Shall we stop at this point?" (formal meeting usage).', office:'Can we stop here for a moment? I have a question about this slide.', conversation:'A: Can we stop here? B: Sure, do you want to take a break or do you have a question?' },
  { id:'d16-extra-073', hindi:'तुम कुछ भी हासिल कर सकते हो।', english:'You can achieve anything.', alternatives:['you are capable of achieving anything.','nothing is beyond your reach.'], hint:'You can + achieve + anything (motivation)', explanation:'"Achieve anything" is a common motivational phrase. "Accomplish anything" is a formal synonym. "You can achieve everything" is less natural — "anything" is more idiomatic in this context.', difficulty:'easy', type:'translation', tags:['can','motivation','achievement'], usageNote:'"Achieve anything" is idiomatic. "Achieve everything" sounds slightly unnatural in this context.', office:'With this team, we can achieve anything we set our minds to.', conversation:'A: I do not think I can do this. B: You can achieve anything if you put in the effort.' },
  { id:'d16-extra-074', hindi:'मैं इस काम को जल्द खत्म कर सकता हूँ।', english:'I can finish this work soon.', alternatives:['I can wrap up this work soon.','I can complete this shortly.'], hint:'Can + finish + this work + soon', explanation:'"Finish this work soon" is natural. "Soon" means in a short time from now. "Shortly" is more formal. "Early" would mean before the deadline, which is a different meaning.', difficulty:'easy', type:'translation', tags:['can','efficiency','time'], usageNote:'"Soon" = in a short while; "shortly" = formal soon; "early" = before expected time.', office:'I can finish this work soon — I just have one more section to complete.', conversation:'A: When will you be done? B: I can finish this work soon, maybe in twenty minutes.' },
  { id:'d16-extra-075', hindi:'वह किसी भी हालत में शांत रह सकता है।', english:'He can stay calm in any situation.', alternatives:['he can remain composed in any situation.','he can keep his cool in all circumstances.'], hint:'Can + stay + calm + in any situation', explanation:'"Stay calm" is the standard collocation. "Remain composed" is more formal. "Keep cool" is idiomatic and informal. "In any situation" covers all scenarios without exception.', difficulty:'medium', type:'translation', tags:['can','composure','leadership'], usageNote:'"Stay calm / remain composed / keep cool" — from informal to formal levels of expression.', office:'He can stay calm in any situation, making him ideal for crisis management roles.', conversation:'A: The client is furious! B: Do not panic. He can stay calm in any situation.' },
  { id:'d16-extra-076', hindi:'क्या तुम इस ईमेल का जवाब दे सकते हो?', english:'Can you reply to this email?', alternatives:['can you respond to this email?','could you answer this email?'], hint:'Can you + reply to + object', explanation:'"Reply to this email" is the standard phrasing. "Reply this email" (without "to") is a common Indian English error. "Respond to" is the formal alternative.', difficulty:'easy', type:'translation', tags:['can','email','office'], usageNote:'"Reply to" and "respond to" always require "to." Never say "reply this email."', office:'Can you reply to this email from the client before 5 PM today?', conversation:'A: There is a pending email. B: Can you reply to this email? I am in meetings all morning.' },
  { id:'d16-extra-077', hindi:'मैं बिना नेट के भी काम कर सकता हूँ।', english:'I can work without the internet too.', alternatives:['I can work offline as well.','I can manage without internet connectivity.'], hint:'Can + work + without + the internet + too', explanation:'"Without the internet" uses "the" because the internet is a specific, unique entity. "Work offline" is a concise technical equivalent. "Without internet" (no "the") is informal but widely used.', difficulty:'medium', type:'translation', tags:['can','offline','flexibility'], usageNote:'"The internet" (with "the") is standard, though "without internet" is now commonly used informally.', office:'I can work without the internet too — I have all the documents downloaded offline.', conversation:'A: The WiFi is down. B: No problem, I can work without the internet too.' },
  { id:'d16-extra-078', hindi:'वे पूरी रात जागकर परियोजना पूरी कर सकते हैं।', english:'They can complete the project by staying up all night.', alternatives:['they can finish the project working through the night.'], hint:'Can + complete + by + gerund phrase', explanation:'"By staying up all night" is a gerund phrase showing means/method. "By" + gerund = the way something is achieved. "They can complete the project staying up all night" (missing "by") is incomplete.', difficulty:'hard', type:'translation', tags:['can','project','dedication'], usageNote:'"By + gerund" explains how something is done: by working / by calling / by staying up.', office:'They can complete the project by staying up all night if absolutely necessary.', conversation:'A: The deadline is 6 AM. B: They can complete the project by staying up all night.' },
  { id:'d16-extra-079', hindi:'मैं आपको रास्ता दिखा सकती हूँ।', english:'I can show you the way.', alternatives:['I can guide you.','I can direct you to the location.'], hint:'Can + show + you + the way', explanation:'"Show you the way" is an idiomatic expression meaning to guide someone. "Guide" and "direct" are formal alternatives. "Show you way" (missing "the") is incorrect.', difficulty:'easy', type:'translation', tags:['can','directions','help'], usageNote:'"Show the way" is idiomatic. Literal and metaphorical uses: physically guide OR mentor/inspire.', office:'I can show you the way to the conference room — follow me.', conversation:'A: I am lost. B: Do not worry, I can show you the way.' },
  { id:'d16-extra-080', hindi:'क्या कोई भी इस सवाल का जवाब दे सकता है?', english:'Can anyone answer this question?', alternatives:['is anyone able to answer this?','does anyone know the answer to this?'], hint:'Can + anyone + answer + this question', explanation:'"Can anyone answer this question?" is used in classrooms and meetings. "Does anyone know the answer?" shifts to present knowledge rather than ability. Both are correct.', difficulty:'easy', type:'translation', tags:['can','questions','classroom'], usageNote:'"Can anyone?" focuses on ability; "Does anyone know?" focuses on knowledge. Slight nuance.', office:'Can anyone in the team answer this question from the client?', conversation:'A: Can anyone answer this question? B: I think I can — let me try.' },
  { id:'d16-extra-081', hindi:'वह एक ही समय में कई काम कर सकता है।', english:'He can do several things at the same time.', alternatives:['he can multitask.','he can handle multiple tasks simultaneously.'], hint:'Can + do + several things + at the same time', explanation:'"At the same time" is the standard phrase for simultaneous actions. "Multitask" is the professional buzzword. "Simultaneously" is formal. All are appropriate in office/interview contexts.', difficulty:'medium', type:'translation', tags:['can','multitasking','efficiency'], usageNote:'"Multitask" is the professional term. "At the same time" and "simultaneously" are detailed equivalents.', office:'He can do several things at the same time — data entry, calls, and reporting.', conversation:'A: Is he a multitasker? B: He can do several things at the same time without losing focus.' },
  { id:'d16-extra-082', hindi:'मैं हर किसी के साथ मिलजुलकर काम कर सकता हूँ।', english:'I can work collaboratively with everyone.', alternatives:['I can work well with anyone.','I am a team player.'], hint:'Can + work + collaboratively + with everyone', explanation:'"Work collaboratively" is the professional, interview-friendly phrase. "Work well with anyone" is natural in conversation. "I am a team player" is a classic interview response.', difficulty:'medium', type:'translation', tags:['can','teamwork','collaboration'], usageNote:'"Collaboratively" is a professional adverb perfect for resumes and interviews.', office:'I can work collaboratively with everyone, from interns to senior leadership.', conversation:'A: How do you handle diverse teams? B: I can work collaboratively with everyone.' },
  { id:'d16-extra-083', hindi:'क्या वह इस जगह को अच्छे से संभाल सकती है?', english:'Can she manage this place well?', alternatives:['is she capable of running this place well?'], hint:'Can she + manage + this place + well', explanation:'"Manage this place" refers to overseeing operations of a location. "Run this place" is more informal. "Handle this place" is also natural. All three work in different registers.', difficulty:'medium', type:'translation', tags:['can','management','responsibility'], usageNote:'"Manage" (formal), "run" (informal), "handle" (neutral) — use based on context.', office:'Can she manage this place well while the director is on leave?', conversation:'A: Who will be in charge? B: Can she manage this place well? She seems experienced.' },
  { id:'d16-extra-084', hindi:'मैं पाँच घंटे में दिल्ली पहुँच सकता हूँ।', english:'I can reach Delhi in five hours.', alternatives:['I can get to Delhi in five hours.','I can arrive in Delhi within five hours.'], hint:'Can + reach + place + in + time', explanation:'"Reach Delhi in five hours" is standard. "Reach to Delhi" is an Indian English error — do not add "to" after reach. "Arrive in Delhi" (not "arrive at Delhi" for a city) is the formal alternative.', difficulty:'medium', type:'translation', tags:['can','travel','time'], usageNote:'Prepositions: "reach Delhi" (no preposition), "arrive in Delhi" (for a city), "arrive at" (for specific places).', office:'I can reach Delhi in five hours by the first morning flight.', conversation:'A: Can you attend the morning meeting in Delhi? B: I can reach Delhi in five hours by car.' },
  { id:'d16-extra-085', hindi:'वह बहुत कठिन परिस्थितियों में भी काम कर सकती है।', english:'She can work even in very difficult conditions.', alternatives:['she can perform well under pressure.','she can manage in the toughest situations.'], hint:'Can + work + even in + difficult conditions', explanation:'"Even in very difficult conditions" uses "even" to emphasize contrast with expectations. "Under pressure" is the idiomatic business equivalent. "In the toughest situations" is also strong.', difficulty:'hard', type:'translation', tags:['can','resilience','work-ethic'], usageNote:'"Under pressure" is the professional idiom equivalent of "in difficult conditions."', office:'She can work even in very difficult conditions — a critical skill for fieldwork.', conversation:'A: The project site is very demanding. B: She can work even in very difficult conditions.' },
  { id:'d16-extra-086', hindi:'मैं इस नक्शे को पढ़ सकता हूँ।', english:'I can read this map.', alternatives:['I know how to read a map.','I can navigate using this map.'], hint:'Can + read + a/this map', explanation:'"Read a map" is the standard phrase for interpreting maps. "Navigate using a map" is more specific. "See a map" would only mean looking at it visually, not interpreting it.', difficulty:'easy', type:'translation', tags:['can','navigation','map'], usageNote:'"Read a map" = understand and use a map for navigation. Not just visually see it.', office:'I can read this map and find the client\'s office without GPS.', conversation:'A: Do you know where to go? B: I can read this map — we are five minutes away.' },
  { id:'d16-extra-087', hindi:'क्या तुम मुझे इसका अर्थ बता सकते हो?', english:'Can you tell me the meaning of this?', alternatives:['can you explain the meaning of this to me?','what does this mean?'], hint:'Can you + tell + me + the meaning of this', explanation:'"Tell me the meaning of this" is correct. "Tell me its meaning" is also fine. "Tell me the meaning of this" (with "of") is the most explicit and clear version for formal communication.', difficulty:'easy', type:'translation', tags:['can','meaning','clarification'], usageNote:'"Tell me the meaning" is direct; "explain the meaning to me" is more formal.', office:'Can you tell me the meaning of this technical term in the contract?', conversation:'A: Can you tell me the meaning of this word? B: Of course — it means to proceed officially.' },
  { id:'d16-extra-088', hindi:'वह एक ही नज़र में गलती ढूंढ सकता है।', english:'He can find a mistake in a single glance.', alternatives:['he can spot an error at a glance.','he can identify mistakes instantly.'], hint:'Can + find + mistake + in a single glance', explanation:'"At a glance" is the standard idiom for finding something quickly. "In a single glance" is slightly emphatic and more elaborate. Both express immediate perception of errors.', difficulty:'hard', type:'translation', tags:['can','attention-to-detail','editing'], usageNote:'"Spot errors at a glance" is powerful professional language for proofreaders and quality controllers.', office:'He can find a mistake in a single glance — extremely valuable for quality assurance.', conversation:'A: Is he a good proofreader? B: He can find a mistake in a single glance — he is exceptional.' },
  { id:'d16-extra-089', hindi:'मैं दस मिनट में तैयार हो सकती हूँ।', english:'I can get ready in ten minutes.', alternatives:['I can be ready in ten minutes.','I can prepare myself in ten minutes.'], hint:'Can + get ready + in + time', explanation:'"Get ready in ten minutes" is very natural in spoken English. "Be ready in ten minutes" emphasizes the resulting state. Both are correct. "Prepare in ten minutes" is slightly formal.', difficulty:'easy', type:'translation', tags:['can','time','daily-life'], usageNote:'"Get ready" (process) vs. "be ready" (state) — both are correct and commonly used.', office:'I can get ready in ten minutes — just give me a heads-up before the meeting.', conversation:'A: We need to leave soon. B: I can get ready in ten minutes. Just wait for me.' },
  { id:'d16-extra-090', hindi:'क्या तुम इस प्रोजेक्ट में मेरा साथ दे सकते हो?', english:'Can you support me in this project?', alternatives:['can you help me with this project?','can you be my partner on this project?'], hint:'Can you + support + me + in this project', explanation:'"Support me in this project" is formal and professional. "Help me with this project" is more casual. Both are acceptable. "Give support" is slightly wordy but understandable.', difficulty:'medium', type:'translation', tags:['can','collaboration','project'], usageNote:'"Support" is slightly more formal than "help" in professional/project contexts.', office:'Can you support me in this project by handling the vendor communications?', conversation:'A: This project is huge. B: Can you support me in this project? I could use your expertise.' },
  { id:'d16-extra-091', hindi:'वह बहुत तेज़ी से टेबल पर जगह बना सकती है।', english:'She can quickly make space on the table.', alternatives:['she can clear the table quickly.'], hint:'Can + quickly + make space + on the table', explanation:'"Make space" is idiomatic for creating room. "Clear the table" is the specific action verb phrase. "Make room" is also natural. Adverb "quickly" can appear before or after can + verb.', difficulty:'medium', type:'translation', tags:['can','space','daily-life'], usageNote:'"Make space / make room / clear space" — idiomatic equivalents for creating physical room.', office:'She can quickly make space on the table for the documents before the meeting.', conversation:'A: Where will we put all these files? B: She can quickly make space on the table.' },
  { id:'d16-extra-092', hindi:'मैं बैडमिंटन बहुत अच्छे से खेल सकता हूँ।', english:'I can play badminton very well.', alternatives:['I am very good at badminton.','I play badminton excellently.'], hint:'Can + play + sport + very well', explanation:'"Play badminton very well" uses "very well" as an adverb phrase. "I am very good at badminton" uses an adjective phrase instead. Both are natural and interchangeable.', difficulty:'easy', type:'translation', tags:['can','sports','badminton'], usageNote:'"Play X well" (adverb) and "be good at X" (adjective) express the same meaning.', office:'I can play badminton very well — happy to represent our company at the sports meet.', conversation:'A: Who should play in the tournament? B: I can play badminton very well — put my name down.' },
  { id:'d16-extra-093', hindi:'क्या वे सब एक ही कमरे में रह सकते हैं?', english:'Can they all stay in one room?', alternatives:['are they able to share one room?','can all of them fit in one room?'], hint:'Can + they all + stay + in one room', explanation:'"Stay in one room" refers to accommodation. "Share a room" means to live in the same room together. "Fit in one room" focuses on physical space capacity. Each has a slightly different emphasis.', difficulty:'easy', type:'translation', tags:['can','accommodation','space'], usageNote:'"Stay" (temporary residence), "share" (co-occupancy), "fit" (capacity) — choose based on meaning.', office:'Can they all stay in one room to reduce the hotel accommodation cost?', conversation:'A: The hotel only has one room available. B: Can they all stay in one room?' },
  { id:'d16-extra-094', hindi:'मैं इस समस्या को आसानी से सुलझा सकता हूँ।', english:'I can solve this problem easily.', alternatives:['I can resolve this issue easily.','this problem is easy for me to solve.'], hint:'Can + solve + this problem + easily', explanation:'"Solve a problem" is the standard collocation. "Resolve an issue" is more formal and common in business. "Fix a problem" is informal. "Easily" at the end is natural placement.', difficulty:'easy', type:'translation', tags:['can','problem-solving','confidence'], usageNote:'"Solve a problem" (academic/general), "resolve an issue" (business), "fix a problem" (informal/tech).', office:'I can solve this problem easily with the data we already have.', conversation:"A: Nobody can figure this out. B: I can solve this problem easily — give me ten minutes." },
  { id:'d16-extra-095', hindi:'वह बिना किसी भी शिकायत के घंटों काम कर सकती है।', english:'She can work for hours without any complaints.', alternatives:['she can work tirelessly for hours.','she works for hours without complaining.'], hint:'Can + work + for hours + without any complaints', explanation:'"Without any complaints" is a prepositional phrase showing manner. "Without complaining" (gerund) is equally correct. "Tirelessly" compresses the same idea into one adverb.', difficulty:'medium', type:'translation', tags:['can','work-ethic','endurance'], usageNote:'"Without any complaints" and "without complaining" are interchangeable. Adverb "tirelessly" is more formal.', office:'She can work for hours without any complaints — a real asset to the team.', conversation:"A: This will take all day. B: That's fine. She can work for hours without any complaints." },
  { id:'d16-extra-096', hindi:'क्या तुम इस दिन को याद कर सकते हो?', english:'Can you remember this day?', alternatives:['do you remember this day?','can you recall this day?'], hint:'Can you + remember + this day', explanation:'"Can you remember?" asks about the ability/capacity to recall. "Do you remember?" simply asks if the person currently has the memory. Both are correct and widely used.', difficulty:'easy', type:'translation', tags:['can','memory','recall'], usageNote:'"Can you remember?" focuses on ability; "do you remember?" focuses on current state of memory.', office:'Can you remember the decision we made about this client six months ago?', conversation:'A: Can you remember this day? B: Of course — it was our first day at the company.' },
  { id:'d16-extra-097', hindi:'मैं जो भी करता हूँ उसमें पूरा ध्यान लगा सकता हूँ।', english:'I can give full attention to whatever I do.', alternatives:['I can focus completely on everything I do.','I can be fully present in whatever I do.'], hint:'Can + give + full attention + to whatever + subject + verb', explanation:'"Give full attention" is the standard collocation. "Focus completely on" is equally valid. "Be fully present" is a mindfulness-inspired phrase becoming popular in professional contexts.', difficulty:'hard', type:'translation', tags:['can','focus','attention'], usageNote:'"Give full attention to" is slightly more formal than "focus completely on."', office:'I can give full attention to whatever I do — no multitasking distractions.', conversation:'A: Do you get distracted easily? B: No, I can give full attention to whatever I do.' },
  { id:'d16-extra-098', hindi:'वह किसी भी विषय पर बोल सकता है।', english:'He can speak on any topic.', alternatives:['he can talk about any subject.','he can address any topic.'], hint:'Can + speak + on any topic', explanation:'"Speak on a topic" uses the preposition "on." "Talk about a topic" uses "about." "Address a topic" is more formal and often used for presentations. All three are correct.', difficulty:'medium', type:'translation', tags:['can','public-speaking','versatility'], usageNote:'"Speak on" (presentation/formal), "talk about" (casual), "address" (formal/speech) — choose by register.', office:'He can speak on any topic — he is an excellent keynote speaker.', conversation:'A: What should we discuss at the conference? B: Do not worry — he can speak on any topic.' },
  { id:'d16-extra-099', hindi:'मैं अपने मन की बात कह सकती हूँ।', english:"I can speak my mind.", alternatives:['I can express my thoughts freely.','I am not afraid to share my opinions.'], hint:"Can + speak one's mind (idiom)", explanation:'"Speak one\'s mind" is an idiom meaning to say what you really think, honestly and directly. It is a powerful phrase in interviews showing assertiveness and communication skills.', difficulty:'medium', type:'translation', tags:['can','communication','confidence'], usageNote:'"Speak one\'s mind" is an idiom for honest, direct communication. Great for interview answers.', office:'I can speak my mind professionally, even when delivering difficult feedback.', conversation:"A: Are you always so direct? B: I can speak my mind when the situation requires it — I think it's important." },
  { id:'d16-extra-100', hindi:'वे किसी भी माहौल में अपने आप को ढाल सकते हैं।', english:'They can adapt themselves to any environment.', alternatives:['they can adjust to any environment.','they are adaptable to all environments.'], hint:'Can + adapt + themselves + to any environment', explanation:'"Adapt to" is the standard phrasal verb for adjustment. "Adapt themselves to" adds emphasis. In professional contexts, "adaptable" as an adjective is commonly used in resumes.', difficulty:'hard', type:'translation', tags:['can','adaptability','flexibility'], usageNote:'"Adapt to" is the standard form. "Themselves" is optional but adds emphasis on self-directed change.', office:'They can adapt themselves to any work environment — remote, on-site, or hybrid.', conversation:'A: The new office has a very different culture. B: They can adapt themselves to any environment.' },
  // ── 200 more CAN questions ────────────────────────────────────────────────
  { id:'d16-extra-101', hindi:'मैं बहुत जल्दी टाइप कर सकता हूँ।', english:'I can type very fast.', alternatives:['I type very quickly.','I am a fast typist.'], hint:'Can + type + fast/quickly', explanation:'"Type very fast" uses fast as an adverb (informal but standard). "Quickly" is the more formal adverb. Both are correct in professional contexts.', difficulty:'easy', type:'translation', tags:['can','typing','office-skill'], usageNote:'"Fast" as an adverb is standard in spoken English; "quickly" is preferred in formal writing.', office:'I can type very fast, so transcribing meetings will not be a problem.', conversation:'A: How long will the minutes take? B: I can type very fast — maybe fifteen minutes.' },
  { id:'d16-extra-102', hindi:'क्या तुम इसे मेरे लिए प्रिंट कर सकते हो?', english:'Can you print this for me?', alternatives:['could you print this for me?','would you print this for me?'], hint:'Can you + print + this + for me', explanation:'"Can you print this for me?" is a natural office request. Adding "please" makes it more polite. "Could you print this?" is slightly more formal and preferred in office settings.', difficulty:'easy', type:'translation', tags:['can','printing','office'], usageNote:'"Could you" is more polite than "can you" for making requests in professional settings.', office:'Can you print this for me before the 10 AM meeting?', conversation:'A: Can you print this for me? B: Sure, how many copies do you need?' },
  { id:'d16-extra-103', hindi:'वह किसी भी समस्या का हल निकाल सकता है।', english:'He can find a solution to any problem.', alternatives:['he can solve any problem.','he can come up with solutions for any issue.'], hint:'Can + find a solution + to any problem', explanation:'"Find a solution to" is the correct preposition. "Find a solution for" is also acceptable. "Come up with a solution" is idiomatic. "Find solution of" is an Indian English error.', difficulty:'medium', type:'translation', tags:['can','problem-solving','creativity'], usageNote:'"Find a solution to/for" — both prepositions are used. "Come up with a solution" is idiomatic.', office:'He can find a solution to any problem — a critical thinker and innovator.', conversation:'A: Nobody knows what to do. B: Ask Sharma — he can find a solution to any problem.' },
  { id:'d16-extra-104', hindi:'मैं बिना थके लंबी दूरी तक चल सकती हूँ।', english:'I can walk long distances without getting tired.', alternatives:['I can walk for miles without tiring.'], hint:'Can + walk + long distances + without + gerund', explanation:'"Without getting tired" uses a gerund after without. "Without tiring" is equally correct and more concise. The key is using the gerund form (not infinitive) after without.', difficulty:'medium', type:'translation', tags:['can','endurance','physical'], usageNote:'"Without getting tired" = without + gerund phrase. Never use infinitive: "without to get tired" is wrong.', office:'I can walk long distances without getting tired — useful for our field sales role.', conversation:'A: The venue is very far. B: That is okay, I can walk long distances without getting tired.' },
  { id:'d16-extra-105', hindi:'क्या हम इस बारे में बाद में बात कर सकते हैं?', english:'Can we discuss this later?', alternatives:['shall we talk about this later?','can we revisit this topic later?'], hint:'Can we + discuss + this + later', explanation:'"Discuss this later" is professional and concise. "Revisit this topic" is more formal. "Talk about this later" is casual. In meetings, "Can we take this offline?" is also common.', difficulty:'easy', type:'translation', tags:['can','meeting','deferral'], usageNote:'"Take this offline" is a meeting idiom meaning to discuss outside the main meeting.', office:'Can we discuss this later in a one-on-one rather than in the full team meeting?', conversation:"A: Can we discuss this later? B: Sure, let's catch up after lunch." },
  { id:'d16-extra-106', hindi:'वह दोनों हाथों से लिख सकती है।', english:'She can write with both hands.', alternatives:['she is ambidextrous.','she can use both hands to write.'], hint:'Can + write + with both hands', explanation:'"Write with both hands" describes ambidexterity. "Ambidextrous" is the single-word adjective. "She can write with both hands" is clear and concrete.', difficulty:'medium', type:'translation', tags:['can','ambidextrous','skill'], usageNote:'"Ambidextrous" is the technical term for someone who can use both hands equally well.', office:'She can write with both hands — an interesting skill mentioned in her profile.', conversation:'A: Is she right-handed? B: She can write with both hands! She is ambidextrous.' },
  { id:'d16-extra-107', hindi:'मैं इस कंपनी के लिए बहुत कुछ कर सकता हूँ।', english:'I can do a lot for this company.', alternatives:['I can contribute greatly to this company.','I have a lot to offer this company.'], hint:'Can + do + a lot + for this company', explanation:'"Do a lot for this company" expresses high potential. "Contribute greatly" is more formal and specific to professional contributions. "Have a lot to offer" is also excellent interview language.', difficulty:'medium', type:'translation', tags:['can','interview','contribution'], usageNote:'"Have a lot to offer" and "contribute greatly" are strong professional phrases for interviews.', office:'I can do a lot for this company with my technical background and leadership experience.', conversation:'A: Why should we hire you? B: I can do a lot for this company — let me show you my plan.' },
  { id:'d16-extra-108', hindi:'क्या तुम इस नंबर पर कॉल कर सकते हो?', english:'Can you call this number?', alternatives:['could you call this number?','would you dial this number for me?'], hint:'Can you + call + this number', explanation:'"Call this number" is standard. "Dial this number" is slightly more formal and technical. "Ring this number" is British English. All are correct.', difficulty:'easy', type:'translation', tags:['can','phone','office'], usageNote:'"Call" (general), "dial" (formal/technical), "ring" (British) — all mean to phone a number.', office:'Can you call this number and confirm our booking for the conference room?', conversation:"A: I'm busy right now. B: Can you call this number and give them our message?" },
  { id:'d16-extra-109', hindi:'वह छोटी सी उम्र में बड़े-बड़े काम कर सकता है।', english:'He can accomplish great things at a young age.', alternatives:['he can achieve big things despite his young age.'], hint:'Can + accomplish + great things + at a young age', explanation:'"Accomplish great things" is formal and motivational. "Achieve big things" is slightly less formal. "Do great things" is more colloquial. "At a young age" is the standard prepositional phrase.', difficulty:'hard', type:'translation', tags:['can','achievement','youth'], usageNote:'"Accomplish great things" is powerful language for motivational and professional contexts.', office:'He can accomplish great things at a young age — our youngest team lead ever.', conversation:'A: He is only 24! B: He can accomplish great things at a young age — watch him.' },
  { id:'d16-extra-110', hindi:'मैं इस बात को पक्के से कह सकता हूँ।', english:'I can say this with certainty.', alternatives:['I can state this confidently.','I can confirm this.'], hint:'Can + say + this + with certainty', explanation:'"With certainty" is a formal phrase expressing full confidence. "Confidently" compresses it into one adverb. "Confirm" is the business-specific equivalent. "With certainty" is excellent in formal presentations.', difficulty:'medium', type:'translation', tags:['can','confidence','certainty'], usageNote:'"With certainty" is formal; "confidently" is the adverb equivalent; "confirm" is business-specific.', office:'I can say this with certainty — our Q3 numbers will exceed the targets.', conversation:'A: Are you sure about this? B: I can say this with certainty — the data backs it up.' },
  { id:'d16-extra-111', hindi:'क्या कोई मेरे लिए दरवाज़ा खोल सकता है?', english:'Can someone open the door for me?', alternatives:['could someone get the door for me?','would someone mind opening the door?'], hint:'Can + someone + open + the door + for me', explanation:'"Open the door for me" is a common polite request. "Get the door" is a very natural informal phrase. "Would someone mind opening?" is the most polite and formal version.', difficulty:'easy', type:'translation', tags:['can','request','polite'], usageNote:'"Get the door" is an idiomatic expression meaning to open the door for someone.', office:'Can someone open the door for me? My hands are full with these files.', conversation:'A: Can someone open the door for me? B: Of course — let me get that for you.' },
  { id:'d16-extra-112', hindi:'वह बहुत जल्दी नई चीज़ें समझ लेता है।', english:'He can understand new things very quickly.', alternatives:['he grasps new concepts very quickly.','he is a fast learner.'], hint:'Can + understand + new things + very quickly', explanation:'"Understand new things quickly" shows cognitive ability. "Grasp" is more formal and specific to concepts. "Fast learner" is the colloquial phrase used in interviews.', difficulty:'medium', type:'translation', tags:['can','learning','intelligence'], usageNote:'"Grasp new concepts" is formal; "fast learner" is the standard interview phrase.', office:'He can understand new things very quickly — training him will take no time at all.', conversation:'A: The system is complex. B: He can understand new things very quickly — he will be fine.' },
  { id:'d16-extra-113', hindi:'मैं सभी की बात ध्यान से सुन सकती हूँ।', english:'I can listen to everyone carefully.', alternatives:['I can give everyone my full attention.','I can be an attentive listener.'], hint:'Can + listen to + everyone + carefully', explanation:'"Listen to everyone carefully" shows active listening skills. "Give full attention" is more descriptive. "Attentive listener" converts it to a noun phrase — great for resumes.', difficulty:'medium', type:'translation', tags:['can','listening','communication'], usageNote:'"Active listening" is a soft skill term. "Listen carefully" describes the same behavior.', office:'I can listen to everyone carefully during feedback sessions without interrupting.', conversation:"A: Are you a good listener? B: I can listen to everyone carefully — it's important to understand before responding." },
  { id:'d16-extra-114', hindi:'क्या वे आज के सारे काम खत्म कर सकते हैं?', english:"Can they finish all today's work?", alternatives:["can they complete all of today's tasks?","are they able to finish all the work today?"], hint:"Can + subject + finish + all + today's work", explanation:'"Finish all today\'s work" is correct but slightly informal. "Complete all of today\'s tasks" is more professional. "Are they able to?" is the more explicit ability question.', difficulty:'medium', type:'translation', tags:['can','productivity','tasks'], usageNote:'"Tasks" is more professional than "work" in business communication.', office:"Can they finish all today's work before the client review at 5 PM?", conversation:"A: Can they finish all today's work? B: I think so — they started early this morning." },
  { id:'d16-extra-115', hindi:'मैं तीस मिनट में खाना बना सकता हूँ।', english:'I can cook a meal in thirty minutes.', alternatives:['I can prepare a meal within thirty minutes.','I can have dinner ready in half an hour.'], hint:'Can + cook + a meal + in + time', explanation:'"Cook a meal in thirty minutes" specifies both the action and the time frame. "Prepare" is slightly more formal. "Have dinner ready" focuses on the result rather than the process.', difficulty:'easy', type:'translation', tags:['can','cooking','time-management'], usageNote:'"Cook a meal" (process) vs. "have dinner ready" (result) — both are natural and correct.', office:'I can cook a meal in thirty minutes — a useful skill for team lunches.', conversation:"A: It's getting late. B: I can cook a meal in thirty minutes if you're hungry." },
  { id:'d16-extra-116', hindi:'वह दो हफ़्तों में पूरा कोर्स कर सकती है।', english:'She can complete the entire course in two weeks.', alternatives:['she can finish the whole course in a fortnight.'], hint:'Can + complete + entire course + in two weeks', explanation:'"Complete the entire course" is formal. "Finish the whole course" is slightly casual but correct. "Fortnight" means two weeks (British English). Both time expressions are correct.', difficulty:'medium', type:'translation', tags:['can','learning','time'], usageNote:'"Fortnight" (2 weeks) is British/Indian English. "Two weeks" is globally understood.', office:'She can complete the entire course in two weeks if she dedicates a few hours daily.', conversation:'A: How long will the training take? B: She can complete the entire course in two weeks.' },
  { id:'d16-extra-117', hindi:'क्या तुम इस लिंक को मुझे भेज सकते हो?', english:'Can you send me this link?', alternatives:['could you forward this link to me?','would you mind sharing this link?'], hint:'Can you + send + me + this link', explanation:'"Send me this link" is natural. "Forward" is more specific to email/message forwarding. "Share this link" is modern and concise. All are appropriate in digital communication.', difficulty:'easy', type:'translation', tags:['can','digital','communication'], usageNote:'"Share" is now the most common verb for digital content in informal professional communication.', office:'Can you send me this link to the shared folder before the meeting?', conversation:'A: I need the reference document. B: Can you send me this link? I will share the folder URL.' },
  { id:'d16-extra-118', hindi:'वह घर पर ही सारा काम कर सकता है।', english:'He can do all the work from home.', alternatives:['he can work entirely from home.','he can manage all tasks remotely.'], hint:'Can + do all the work + from home', explanation:'"Do all the work from home" is clear and direct. "Work entirely from home" is more formal. "Manage tasks remotely" is the professional business equivalent.', difficulty:'easy', type:'translation', tags:['can','remote-work','flexibility'], usageNote:'"Remotely" and "from home" are interchangeable in modern work contexts.', office:'He can do all the work from home — we have set him up with the necessary tools.', conversation:"A: Does he need to come to the office? B: No, he can do all the work from home." },
  { id:'d16-extra-119', hindi:'मैं इसे बिना पढ़े नहीं समझ सकती।', english:"I can't understand this without reading it.", alternatives:["I cannot make sense of this without reading it."], hint:"Can't + understand + this + without + gerund", explanation:'"Without reading it" uses a gerund after without. "Make sense of" is an idiomatic alternative to "understand." "Without read it" (base verb after without) is incorrect.', difficulty:'medium', type:'translation', tags:['can','reading','comprehension'], usageNote:'"Without + gerund" is always correct. "Make sense of" = understand the meaning.', office:"I can't understand this proposal without reading it — please give me a few minutes.", conversation:"A: Do you get the gist? B: I can't understand this without reading it carefully." },
  { id:'d16-extra-120', hindi:'वे अंग्रेज़ी में ही बात कर सकते हैं।', english:'They can only speak in English.', alternatives:['they are only able to communicate in English.','English is the only language they can speak.'], hint:'Can + only + speak + in English', explanation:'"Only" limits the scope of their ability. Placement of "only" matters: "can only speak" (preferred in formal English) vs. "only can speak" (less natural). The meaning is the same.', difficulty:'medium', type:'translation', tags:['can','language','limitation'], usageNote:'Position "only" after can and before the verb for standard formal English placement.', office:'They can only speak in English — we will need a translator for the regional meetings.', conversation:"A: Do they know Hindi? B: No, they can only speak in English." },
  { id:'d16-extra-121', hindi:'मैं ज़रूरत पड़ने पर रात को भी काम कर सकता हूँ।', english:'I can also work at night if needed.', alternatives:['I can work nights when necessary.','I am available to work late if required.'], hint:'Can + also + work + at night + if needed', explanation:'"If needed" is a conditional clause showing willingness. "When necessary" is similar. "If required" is more formal. All three are appropriate in professional communication.', difficulty:'medium', type:'translation', tags:['can','flexibility','work-hours'], usageNote:'"If needed / if necessary / if required" — all express conditionality. "Required" is most formal.', office:'I can also work at night if needed to support the US team across time zones.', conversation:'A: The project needs late-night coverage. B: I can also work at night if needed.' },
  { id:'d16-extra-122', hindi:'क्या तुम इस डिवाइस को ठीक कर सकते हो?', english:'Can you fix this device?', alternatives:['can you repair this device?','are you able to fix this gadget?'], hint:'Can you + fix + this device', explanation:'"Fix" and "repair" are synonyms. "Fix" is more informal; "repair" is more formal. "Device" is broader than "gadget" (informal). In IT contexts, "troubleshoot" is also used.', difficulty:'easy', type:'translation', tags:['can','repair','technology'], usageNote:'"Fix" (informal), "repair" (formal), "troubleshoot" (IT-specific) — choose based on context.', office:'Can you fix this device before tomorrow\'s client demo?', conversation:"A: My laptop keeps crashing. B: Can you fix this device? I'll take a look." },
  { id:'d16-extra-123', hindi:'वह एक दिन में एक पूरी किताब पढ़ सकती है।', english:'She can read an entire book in a day.', alternatives:['she can finish a whole book in one day.'], hint:'Can + read + an entire book + in a day', explanation:'"An entire book" emphasizes completeness. "A whole book" is equally correct. "In a day" is the time frame. "In one day" adds slight emphasis. All versions are natural.', difficulty:'easy', type:'translation', tags:['can','reading','speed'], usageNote:'"Entire" and "whole" are interchangeable before nouns. "An entire" requires the article.', office:'She can read an entire book in a day — great for research-intensive projects.', conversation:"A: Has she read the report yet? B: She can read an entire book in a day — she'll be done soon." },
  { id:'d16-extra-124', hindi:'मैं किसी भी घड़ी की मरम्मत कर सकता हूँ।', english:'I can repair any watch.', alternatives:['I know how to fix any watch.','I can fix watches of any type.'], hint:'Can + repair + any + noun', explanation:'"Repair any watch" shows unlimited ability within the domain. "Fix" is less formal. "Any type of watch" specifies variety. All are correct.', difficulty:'easy', type:'translation', tags:['can','repair','craftsmanship'], usageNote:'"Any" = without restriction. "Any type of" is more specific but means the same.', office:'I can repair any watch — watchmaking is my lifelong hobby.', conversation:'A: This is a rare antique watch. B: I can repair any watch — leave it with me.' },
  { id:'d16-extra-125', hindi:'क्या वह अकेले यात्रा कर सकती है?', english:'Can she travel alone?', alternatives:['is she able to travel by herself?','can she go on solo trips?'], hint:'Can she + travel + alone', explanation:'"Travel alone" means without a companion. "By herself" adds the reflexive emphasis. "Solo trips" is informal but modern. All three are natural and correct.', difficulty:'easy', type:'translation', tags:['can','travel','independence'], usageNote:'"Alone," "by herself," and "solo" all describe unaccompanied travel. Formality varies.', office:'Can she travel alone to the branch office? We need someone there urgently.', conversation:"A: Can she travel alone? B: Yes, she has done it many times — she's very independent." },
  { id:'d16-extra-126', hindi:'मैं इस सॉफ़्टवेयर को सीख सकता हूँ।', english:'I can learn this software.', alternatives:['I can pick up this software.','I am able to learn this application.'], hint:'Can + learn + this software', explanation:'"Learn this software" = learn to use it. "Pick up" is idiomatic (= learn informally/quickly). "Application" is more formal than "software." All are correct.', difficulty:'easy', type:'translation', tags:['can','technology','learning'], usageNote:'"Pick up software" is a natural, confident phrase for interview/professional contexts.', office:'I can learn this software within a week with proper training.', conversation:'A: We use a proprietary CRM. B: I can learn this software — just point me to the training materials.' },
  { id:'d16-extra-127', hindi:'वह हर तरह की बातचीत में भाग ले सकता है।', english:'He can participate in all kinds of conversations.', alternatives:['he can engage in any type of discussion.'], hint:'Can + participate in + all kinds of + noun', explanation:'"Participate in" is the standard verb for joining activities/discussions. "Engage in" is more formal. "Take part in" is equally valid. All are correct.', difficulty:'medium', type:'translation', tags:['can','communication','versatility'], usageNote:'"Participate in," "engage in," and "take part in" are interchangeable formal phrases.', office:'He can participate in all kinds of conversations — from technical reviews to HR discussions.', conversation:'A: Is he good in discussions? B: He can participate in all kinds of conversations seamlessly.' },
  { id:'d16-extra-128', hindi:'मैं बिना देखे इस कीबोर्ड पर टाइप कर सकती हूँ।', english:'I can type on this keyboard without looking.', alternatives:['I can touch-type.','I can type without looking at the keyboard.'], hint:'Can + type + without + looking', explanation:'"Type without looking" is the descriptive phrase. "Touch-type" is the technical term for this ability. Both are correct and understood in professional contexts.', difficulty:'medium', type:'translation', tags:['can','typing','skill'], usageNote:'"Touch-type" is the professional term for typing without looking at the keys.', office:'I can type on this keyboard without looking, which improves my typing speed considerably.', conversation:'A: Can you keep your eyes on the screen? B: Yes, I can type without looking — I touch-type.' },
  { id:'d16-extra-129', hindi:'क्या तुम इस बैठक में हमारी तरफ से बोल सकते हो?', english:'Can you speak on our behalf in this meeting?', alternatives:['can you represent us in this meeting?','could you speak for us in this meeting?'], hint:'Can you + speak + on our behalf + in this meeting', explanation:'"On our behalf" means representing someone. "Represent us" is the single-verb equivalent. "Speak for us" is equally natural and slightly more casual.', difficulty:'hard', type:'translation', tags:['can','representation','meeting'], usageNote:'"On someone\'s behalf" is a formal phrase meaning to act/speak for someone else.', office:'Can you speak on our behalf in this meeting with the senior leadership?', conversation:'A: Can you speak on our behalf in this meeting? B: Yes, brief me beforehand.' },
  { id:'d16-extra-130', hindi:'वह किसी भी भाषा में दस्तावेज़ तैयार कर सकता है।', english:'He can prepare documents in any language.', alternatives:['he can draft documents in any language.'], hint:'Can + prepare + documents + in any language', explanation:'"Prepare documents" is standard. "Draft documents" is more formal and specific to business writing. "Write documents in any language" is also correct.', difficulty:'medium', type:'translation', tags:['can','multilingual','documentation'], usageNote:'"Draft" is more specific to creating the initial written version of a document.', office:'He can prepare documents in any language — a great asset for international projects.', conversation:'A: We need the contract in Spanish. B: He can prepare documents in any language.' },
  { id:'d16-extra-131', hindi:'मैं इस कमरे को एक घंटे में साफ कर सकती हूँ।', english:'I can clean this room in one hour.', alternatives:['I can tidy this room within an hour.'], hint:'Can + clean + this room + in one hour', explanation:'"Clean" and "tidy" are close synonyms. "Tidy" focuses on organizing; "clean" focuses on removing dirt. Both are appropriate. "In one hour" = by the end of one hour.', difficulty:'easy', type:'translation', tags:['can','cleaning','household'], usageNote:'"Clean" removes dirt; "tidy" organizes. "In one hour" vs. "within an hour" — both mean by hour\'s end.', office:'I can clean this room in one hour before the board meeting.', conversation:'A: The conference room is a mess. B: I can clean this room in one hour.' },
  { id:'d16-extra-132', hindi:'क्या आप मुझे इस काम के बारे में बता सकते हैं?', english:'Can you tell me about this job?', alternatives:['could you describe this position to me?','can you explain what this role involves?'], hint:'Can you + tell + me + about this job', explanation:'"Tell me about this job" is the natural question asked at job fairs/interviews. "Describe this position" is more formal. "Tell me about" is a very common interview-style phrase.', difficulty:'easy', type:'translation', tags:['can','interview','job'], usageNote:'"Can you tell me about...?" is a standard opening question in interviews and networking.', office:'Can you tell me about this job profile before I submit my application?', conversation:'A: Can you tell me about this job? B: Of course — it is a senior analyst role with travel.' },
  { id:'d16-extra-133', hindi:'वह बिना किसी की मदद के खाना बना सकती है।', english:'She can cook without anyone\'s help.', alternatives:['she can cook on her own.','she can manage cooking independently.'], hint:"Can + cook + without + anyone's help", explanation:'"Without anyone\'s help" specifies complete independence. "On her own" is the idiomatic equivalent. "Independently" is the formal adverb. All convey the same meaning.', difficulty:'easy', type:'translation', tags:['can','cooking','independence'], usageNote:'"On her own" and "independently" are strong, natural alternatives to "without anyone\'s help."', office:"She can cook without anyone's help — a self-sufficient team player.", conversation:"A: Does she need help in the kitchen? B: She can cook without anyone's help — she is trained." },
  { id:'d16-extra-134', hindi:'मैं एक साथ दो काम नहीं कर सकता।', english:"I can't do two things at once.", alternatives:["I cannot multitask.","I am unable to do two things simultaneously."], hint:"Can't + do + two things + at once", explanation:'"At once" means simultaneously. "At the same time" is the expanded equivalent. "Multitask" is the single-verb replacement. All are correct.', difficulty:'easy', type:'translation', tags:['can','multitasking','honesty'], usageNote:'"At once" and "at the same time" are interchangeable. "Multitask" is the professional verb.', office:"I can't do two things at once — should I finish this report or take the client call first?", conversation:"A: Can you do both? B: I can't do two things at once — which is more urgent?" },
  { id:'d16-extra-135', hindi:'क्या वे इस नीति को समझ सकते हैं?', english:'Can they understand this policy?', alternatives:['are they able to comprehend this policy?','can they follow this policy?'], hint:'Can + they + understand + this policy', explanation:'"Understand" and "comprehend" are synonyms — "comprehend" is more formal. "Follow this policy" shifts the meaning slightly from understanding to compliance.', difficulty:'medium', type:'translation', tags:['can','policy','compliance'], usageNote:'"Comprehend" is formal; "follow" implies understanding AND compliance. Choose based on meaning.', office:'Can they understand this policy after the HR briefing session?', conversation:'A: The new policy is quite detailed. B: Can they understand this policy without a walkthrough?' },
  { id:'d16-extra-136', hindi:'वह बहुत अच्छी पावर पॉइंट बना सकता है।', english:'He can create excellent PowerPoint presentations.', alternatives:['he can make great PowerPoint slides.','he is skilled at creating PowerPoint presentations.'], hint:'Can + create + excellent + PowerPoint presentations', explanation:'"Create PowerPoint presentations" is the formal phrasing. "Make slides" is informal. "Skilled at creating" converts it to an adjective phrase suitable for resumes.', difficulty:'easy', type:'translation', tags:['can','powerpoint','office-skill'], usageNote:'Resume phrasing: "skilled at creating PowerPoint presentations" is more professional than "can make PPTs."', office:'He can create excellent PowerPoint presentations for board-level reporting.', conversation:'A: We need a deck for Friday. B: He can create excellent PowerPoint presentations — he\'s the best.' },
  { id:'d16-extra-137', hindi:'मैं इस डेटा का विश्लेषण कर सकती हूँ।', english:'I can analyze this data.', alternatives:['I am able to interpret this data.','I can work with this dataset.'], hint:'Can + analyze + this data', explanation:'"Analyze" (AmE) / "Analyse" (BrE) — both spellings are correct. "Interpret data" focuses on drawing conclusions. "Work with a dataset" is the modern data science phrasing.', difficulty:'medium', type:'translation', tags:['can','data-analysis','technical'], usageNote:'"Analyze" (American spelling) and "analyse" (British spelling) are both standard.', office:'I can analyze this data and prepare a summary report by tomorrow morning.', conversation:'A: We have all this sales data. B: I can analyze this data and spot the trends.' },
  { id:'d16-extra-138', hindi:'क्या तुम इस गलती को सुधार सकते हो?', english:'Can you correct this mistake?', alternatives:['can you fix this error?','could you rectify this mistake?'], hint:'Can you + correct + this mistake', explanation:'"Correct a mistake" and "fix an error" are both standard. "Rectify" is more formal and legal. "Amend" is used for formal documents. Choose based on the context.', difficulty:'easy', type:'translation', tags:['can','correction','quality'], usageNote:'"Correct" (general), "rectify" (formal/legal), "amend" (documents) — different registers.', office:'Can you correct this mistake in the invoice before sending it to the client?', conversation:'A: There is an error in the report. B: Can you correct this mistake and resend it?' },
  { id:'d16-extra-139', hindi:'वह बिना किसी गाइड के पहाड़ पर चढ़ सकता है।', english:'He can climb a mountain without a guide.', alternatives:['he can trek up a mountain alone.'], hint:'Can + climb + a mountain + without a guide', explanation:'"Climb a mountain" is the standard phrase. "Trek up" is more informal and specific to hiking. "Without a guide" = independently. "Without any guide" is slightly more emphatic.', difficulty:'medium', type:'translation', tags:['can','adventure','independence'], usageNote:'"Without a guide" vs. "without any guide" — both correct; "any" adds emphasis on totality.', office:'He can climb a mountain without a guide — the same independence he brings to projects.', conversation:'A: He went alone? B: Yes, he can climb a mountain without a guide — very experienced.' },
  { id:'d16-extra-140', hindi:'मैं इसे आपको बाद में समझा सकती हूँ।', english:'I can explain this to you later.', alternatives:['I can walk you through this later.','I can clarify this for you later.'], hint:'Can + explain + this + to you + later', explanation:'"Explain this to you" requires "to." "Explain you this" is an Indian English error — never correct. "Walk you through" is idiomatic for step-by-step explanation. "Clarify" is formal.', difficulty:'medium', type:'translation', tags:['can','explanation','deferral'], usageNote:'"Explain to" always needs the preposition. "Walk through" is idiomatic for detailed explanation.', office:'I can explain this to you later after today\'s stand-up meeting.', conversation:'A: I do not understand this graph. B: I can explain this to you later — I have five minutes after lunch.' },
  { id:'d16-extra-141', hindi:'क्या तुम यहाँ से पाँच किलोमीटर की दूरी तय कर सकते हो?', english:'Can you cover five kilometres from here?', alternatives:['can you walk five kilometres from here?','are you able to travel five kilometres?'], hint:'Can you + cover + distance + from here', explanation:'"Cover a distance" is the standard sporting/travel expression. "Cover five kilometres" means to travel that distance. "Walk five kilometres" specifies the mode of travel.', difficulty:'medium', type:'translation', tags:['can','distance','physical'], usageNote:'"Cover a distance" is standard for measuring ability to travel a certain distance.', office:'Can you cover five kilometres from here to the client site on foot?', conversation:'A: Can you cover five kilometres from here? B: Yes, I walk that distance every day.' },
  { id:'d16-extra-142', hindi:'वह अपने सभी काम समय पर पूरे कर सकती है।', english:'She can complete all her work on time.', alternatives:['she can finish all her tasks on schedule.','she always meets her deadlines.'], hint:'Can + complete + all her work + on time', explanation:'"Complete work on time" is a professional virtue phrase. "On schedule" is more formal. "Meet deadlines" is the strongest professional phrase for this concept.', difficulty:'medium', type:'translation', tags:['can','time-management','reliability'], usageNote:'"Meet deadlines" is the most professional expression for completing work on time.', office:'She can complete all her work on time — she has never missed a single deadline.', conversation:'A: Is she reliable? B: She can complete all her work on time — always.' },
  { id:'d16-extra-143', hindi:'मैं इस पत्र को आज ही पोस्ट कर सकता हूँ।', english:'I can post this letter today itself.', alternatives:['I can mail this letter today.','I can send this letter out today.'], hint:'Can + post + this letter + today', explanation:'"Post this letter" (British/Indian English) and "mail this letter" (American English) mean the same thing. "Today itself" is Indian English — "today" alone or "this very day" is more standard internationally.', difficulty:'easy', type:'translation', tags:['can','postal','communication'], usageNote:'"Post" (British) vs. "mail" (American) for letters. "Today itself" is Indian English; use "today" or "right away."', office:'I can post this letter today and it should arrive by Thursday.', conversation:'A: When can you send it? B: I can post this letter today — it will be at the post office by noon.' },
  { id:'d16-extra-144', hindi:'क्या वह अकेले यह निर्णय ले सकता है?', english:'Can he make this decision alone?', alternatives:['is he authorized to make this decision alone?','can he decide this on his own?'], hint:'Can + subject + make + this decision + alone', explanation:'"Make this decision alone" questions authority or ability. "Authorized" introduces a different dimension — permission vs. ability. Both are contextually valid.', difficulty:'medium', type:'translation', tags:['can','decision-making','authority'], usageNote:'"Can" here can mean both ability and permission depending on context.', office:'Can he make this decision alone, or does it require board approval?', conversation:'A: Can he make this decision alone? B: No, it needs sign-off from the CFO.' },
  { id:'d16-extra-145', hindi:'मैं किसी भी परिस्थिति में अपना धैर्य नहीं खोता।', english:"I can keep my patience in any situation.", alternatives:["I can remain patient in any situation.","I don't lose my patience easily."], hint:'Can + keep + my patience + in any situation', explanation:'"Keep my patience" means to maintain calmness. "Remain patient" uses an adjective. "Lose my patience" is the negative form. All three are natural and correct.', difficulty:'medium', type:'translation', tags:['can','patience','emotional-intelligence'], usageNote:'"Keep/maintain patience" (positive) vs. "lose patience" (negative) are the key collocations.', office:'I can keep my patience in any situation — essential for client-facing roles.', conversation:'A: The client was very difficult. B: I can keep my patience in any situation — I handled it well.' },
  { id:'d16-extra-146', hindi:'वे एक दूसरे को अच्छे से समझ सकते हैं।', english:'They can understand each other well.', alternatives:['they have good mutual understanding.'], hint:'Can + understand + each other + well', explanation:'"Each other" is the reciprocal pronoun for two people. "One another" is used for three or more (though both are interchangeable today). "Well" is the adverb — not "good."', difficulty:'medium', type:'translation', tags:['can','mutual-understanding','relationship'], usageNote:'"Each other" (two people), "one another" (three or more) — traditional rule. Modern English uses both interchangeably.', office:'They can understand each other well — excellent for a co-leadership arrangement.', conversation:'A: How is their working relationship? B: They can understand each other well — very compatible.' },
  { id:'d16-extra-147', hindi:'मैं बिना शोर के काम कर सकती हूँ।', english:'I can work in silence.', alternatives:['I can work without making noise.','I am comfortable working quietly.'], hint:'Can + work + in silence', explanation:'"Work in silence" is the natural idiom for working quietly. "Without making noise" is more literal. "Work quietly" uses an adverb. All are correct, with idiom being most natural.', difficulty:'easy', type:'translation', tags:['can','silence','focus'], usageNote:'"Work in silence" is idiomatic; "work quietly" is descriptive. Both are natural.', office:'I can work in silence — perfect for open-plan offices that require concentration.', conversation:'A: The library has a strict silence rule. B: That is fine — I can work in silence.' },
  { id:'d16-extra-148', hindi:'क्या आप यह रिपोर्ट कल तक दे सकते हैं?', english:'Can you submit this report by tomorrow?', alternatives:['can you send this report by tomorrow?','can you have this report ready by tomorrow?'], hint:'Can you + submit + report + by tomorrow', explanation:'"Submit by tomorrow" means the deadline is tomorrow. "By" signals a deadline. "Send" is more informal. "Have it ready by" focuses on preparation rather than submission.', difficulty:'easy', type:'translation', tags:['can','deadline','report'], usageNote:'"By" is the deadline preposition. "Submit by" = official delivery; "send by" = casual delivery.', office:'Can you submit this report by tomorrow EOD so we can review it over the weekend?', conversation:'A: When is the deadline? B: Can you submit this report by tomorrow? The client is waiting.' },
  { id:'d16-extra-149', hindi:'वह किसी भी सवाल का जवाब आसानी से दे सकती है।', english:'She can answer any question easily.', alternatives:['she can respond to any question effortlessly.'], hint:'Can + answer + any question + easily', explanation:'"Answer any question easily" shows both breadth of knowledge and confidence. "Respond to any question" is slightly more formal. "Effortlessly" is a more vivid adverb for formal writing.', difficulty:'medium', type:'translation', tags:['can','knowledge','confidence'], usageNote:'"Effortlessly" is more vivid and formal than "easily" in professional/formal writing.', office:'She can answer any question easily — the ideal spokesperson for the product launch.', conversation:'A: The press conference will be tough. B: She can answer any question easily — do not worry.' },
  { id:'d16-extra-150', hindi:'मैं इस परियोजना को समय से पहले पूरा कर सकता हूँ।', english:'I can complete this project ahead of schedule.', alternatives:['I can finish this project before the deadline.'], hint:'Can + complete + project + ahead of schedule', explanation:'"Ahead of schedule" is the professional phrase for before the planned time. "Before the deadline" is more specific. Both are strong positive phrases in professional communication.', difficulty:'medium', type:'translation', tags:['can','project-management','efficiency'], usageNote:'"Ahead of schedule" is professional jargon for early completion. Stronger than "before deadline."', office:'I can complete this project ahead of schedule if we approve the resources this week.', conversation:'A: When will this be done? B: I can complete this project ahead of schedule — by Friday.' },
  { id:'d16-extra-151', hindi:'क्या तुम दूसरों को प्रेरित कर सकते हो?', english:'Can you motivate others?', alternatives:['are you able to inspire others?','can you encourage your team members?'], hint:'Can you + motivate + others', explanation:'"Motivate others" is a leadership skill question. "Inspire" suggests a deeper, more transformational influence. "Encourage" is gentler. All are valid in different leadership contexts.', difficulty:'medium', type:'translation', tags:['can','leadership','motivation'], usageNote:'"Motivate" (drive to act), "inspire" (vision-based change), "encourage" (emotional support) — nuanced differences.', office:'Can you motivate others? That is a key skill for the team lead position.', conversation:'A: Can you motivate others? B: Yes, I believe in leading by example and positive reinforcement.' },
  { id:'d16-extra-152', hindi:'वह रात को अच्छे से नहीं सो सकता।', english:"He can't sleep well at night.", alternatives:["he cannot sleep properly at night.","he has trouble sleeping at night."], hint:"Can't + sleep well + at night", explanation:'"Can\'t sleep well" describes poor sleep quality. "Cannot sleep properly" is slightly more formal. "Has trouble sleeping" is idiomatic. All express difficulty with sleep.', difficulty:'easy', type:'translation', tags:['can','sleep','health'], usageNote:'"Have trouble sleeping" is the idiomatic phrase for insomnia or poor sleep.', office:"He can't sleep well at night due to work stress — we should review his workload.", conversation:"A: He looks tired. B: He can't sleep well at night. It's been weeks." },
  { id:'d16-extra-153', hindi:'मैं इस नई भूमिका में बहुत कुछ सीख सकती हूँ।', english:'I can learn a great deal in this new role.', alternatives:['I can grow a lot in this position.','there is much I can learn in this role.'], hint:'Can + learn + a great deal + in this role', explanation:'"Learn a great deal" is formal and impressive. "Grow a lot" is more informal but shows personal development. Both are excellent answers to "What do you hope to gain from this role?"', difficulty:'medium', type:'translation', tags:['can','learning','career-growth'], usageNote:'"A great deal" is formal for "a lot." "Grow" suggests broader development beyond just learning.', office:'I can learn a great deal in this new role — especially in cross-functional collaboration.', conversation:'A: Why do you want this position? B: I can learn a great deal in this new role.' },
  { id:'d16-extra-154', hindi:'क्या हम कल की बैठक रद्द कर सकते हैं?', english:"Can we cancel tomorrow's meeting?", alternatives:["can we call off tomorrow's meeting?","shall we postpone tomorrow's meeting?"], hint:"Can we + cancel + tomorrow's meeting", explanation:'"Cancel" means to stop entirely; "postpone" means to reschedule for later. "Call off" is informal for cancel. Make sure to choose the right word based on whether you want to stop or reschedule.', difficulty:'easy', type:'translation', tags:['can','meeting','cancellation'], usageNote:'"Cancel" (stop entirely) vs. "postpone/reschedule" (move to later time) — important distinction.', office:"Can we cancel tomorrow's meeting? The agenda can be covered over email.", conversation:"A: Can we cancel tomorrow's meeting? B: Yes, but let's reschedule for next Monday." },
  { id:'d16-extra-155', hindi:'वह एक साथ तीन प्रोजेक्ट संभाल सकता है।', english:'He can handle three projects at once.', alternatives:['he can manage three projects simultaneously.'], hint:'Can + handle + three projects + at once', explanation:'"Handle three projects at once" uses "at once" for simultaneity. "Simultaneously" is the formal adverb equivalent. Both are powerful multitasking claims.', difficulty:'medium', type:'translation', tags:['can','multitasking','project-management'], usageNote:'"At once" (casual) and "simultaneously" (formal) both express the same simultaneous handling.', office:'He can handle three projects at once — we rely on him for complex multi-track delivery.', conversation:'A: We have three urgent projects. B: He can handle three projects at once — trust him.' },
  { id:'d16-extra-156', hindi:'मैं अपने विचार स्पष्ट रूप से व्यक्त कर सकती हूँ।', english:'I can express my thoughts clearly.', alternatives:['I can communicate my ideas clearly.','I am able to articulate my thoughts.'], hint:'Can + express + thoughts + clearly', explanation:'"Express thoughts clearly" is direct. "Articulate" is the formal, impressive verb for verbal expression. "Communicate ideas" broadens the scope beyond just thoughts.', difficulty:'medium', type:'translation', tags:['can','communication','clarity'], usageNote:'"Articulate" is a strong formal verb meaning to express thoughts clearly and effectively.', office:'I can express my thoughts clearly in both written and verbal communication.', conversation:'A: How do you handle presentations? B: I can express my thoughts clearly — no nervousness.' },
  { id:'d16-extra-157', hindi:'क्या वे इस मुद्दे को बिना मेरी मदद के सुलझा सकते हैं?', english:'Can they resolve this issue without my help?', alternatives:['are they able to handle this issue independently?'], hint:'Can + they + resolve + issue + without my help', explanation:'"Resolve an issue" is the standard business phrase. "Handle an issue" is more general. "Without my help" specifies independence. All are natural in office contexts.', difficulty:'hard', type:'translation', tags:['can','independence','problem-solving'], usageNote:'"Resolve an issue" is more specific than "handle a problem" — implies finding a solution.', office:'Can they resolve this issue without my help, or do they need escalation?', conversation:'A: Should we call you in? B: Can they resolve this issue without my help first? Give them an hour.' },
  { id:'d16-extra-158', hindi:'वह पूरे दिन मुस्कुराते हुए काम कर सकती है।', english:'She can work with a smile all day.', alternatives:['she maintains a positive attitude all day.'], hint:'Can + work + with a smile + all day', explanation:'"Work with a smile" is a phrase emphasizing positive attitude during work. "All day" means throughout the entire day. Both phrases together show impressive emotional resilience.', difficulty:'medium', type:'translation', tags:['can','positivity','attitude'], usageNote:'"Work with a smile" is an expression of positive attitude, not just physical smiling.', office:'She can work with a smile all day — perfect for customer-facing positions.', conversation:'A: Is she good with clients? B: She can work with a smile all day — clients love her.' },
  { id:'d16-extra-159', hindi:'मैं किसी भी टीम के साथ काम कर सकता हूँ।', english:'I can work with any team.', alternatives:['I can collaborate with any team.','I adapt well to different teams.'], hint:'Can + work with + any team', explanation:'"Work with any team" shows adaptability. "Collaborate with" is more formal. "Adapt to different teams" specifically highlights the adaptability dimension.', difficulty:'easy', type:'translation', tags:['can','teamwork','adaptability'], usageNote:'"Work with" (general), "collaborate with" (formal), "adapt to" (emphasizes flexibility).', office:'I can work with any team — cross-functional collaboration is one of my strengths.', conversation:'A: The team composition changes frequently. B: That is fine — I can work with any team.' },
  { id:'d16-extra-160', hindi:'क्या तुम इस जानकारी को संगठित कर सकते हो?', english:'Can you organize this information?', alternatives:['can you sort out this data?','can you put this information in order?'], hint:'Can you + organize + this information', explanation:'"Organize information" is standard in data/research contexts. "Sort out" is informal. "Put in order" is more descriptive. "Arrange" and "structure" are also valid alternatives.', difficulty:'medium', type:'translation', tags:['can','organization','information'], usageNote:'"Organize" (formal), "sort out" (informal), "structure" (formal, implies framework) — choose by register.', office:'Can you organize this information into a clear presentation for the board?', conversation:'A: The data is all over the place. B: Can you organize this information? I will format it after.' },
  { id:'d16-extra-161', hindi:'वह पाँच साल की उम्र में पढ़ना सीख सकता था।', english:'He could read at the age of five.', alternatives:['he was able to read at age five.'], hint:'Could + read + at the age of five (past ability)', explanation:'This uses "could" not "can" because it refers to past ability. "At the age of five" is the standard age-reference phrase. "When he was five" is equally natural.', difficulty:'medium', type:'translation', tags:['can','past-ability','childhood'], usageNote:'For past ability, use "could" or "was/were able to" — not "can."', office:'He could read technical manuals at the age of five — extraordinarily gifted.', conversation:'A: Was he always smart? B: He could read at the age of five — remarkable child.' },
  { id:'d16-extra-162', hindi:'मैं यहाँ से समुद्र देख सकती हूँ।', english:'I can see the sea from here.', alternatives:['the sea is visible from here.','I have a view of the sea from here.'], hint:'Can + see + the sea + from here', explanation:'"Can see" uses can for sensory perception — a special use of can with sense verbs (see, hear, smell, feel). "The sea is visible from here" converts it to a passive description.', difficulty:'easy', type:'translation', tags:['can','perception','view'], usageNote:'Can + sense verbs (see, hear, smell, feel) describes current sensory perception, not just ability.', office:'I can see the sea from here — this office has a wonderful view.', conversation:'A: What a beautiful spot! B: I can see the sea from here — incredible, isn\'t it?' },
  { id:'d16-extra-163', hindi:'क्या तुम बिना शोर किए काम कर सकते हो?', english:'Can you work without making noise?', alternatives:['can you work quietly?','are you able to work without creating disturbance?'], hint:'Can you + work + without + making noise', explanation:'"Without making noise" is a gerund phrase. "Work quietly" is the adverb simplification. "Without creating disturbance" is more formal. All are correct.', difficulty:'easy', type:'translation', tags:['can','silence','consideration'], usageNote:'"Without + gerund" always correct. "Quietly" compresses the same meaning into one adverb.', office:'Can you work without making noise? The senior partner is on an important call next door.', conversation:'A: Can you work without making noise? B: Of course — I use headphones.' },
  { id:'d16-extra-164', hindi:'वे एक दूसरे की मदद कर सकते हैं।', english:'They can help each other.', alternatives:['they can support one another.'], hint:'Can + help + each other (reciprocal)', explanation:'"Each other" (two people) and "one another" (three or more) are both used for reciprocal actions. Modern grammar accepts both regardless of number.', difficulty:'easy', type:'translation', tags:['can','collaboration','mutual-help'], usageNote:'"Each other" vs. "one another" — traditional grammar distinguishes by number; modern grammar does not.', office:'They can help each other — pair them together on the same account.', conversation:'A: They always seem to struggle alone. B: They can help each other if they just communicate.' },
  { id:'d16-extra-165', hindi:'मैं इस बैठक को प्रभावी ढंग से चला सकता हूँ।', english:'I can run this meeting effectively.', alternatives:['I can facilitate this meeting effectively.','I can lead this meeting productively.'], hint:'Can + run + this meeting + effectively', explanation:'"Run a meeting" is standard informal business English. "Facilitate" is more formal and implies a neutral guiding role. "Lead a meeting" implies directing. All are used in professional contexts.', difficulty:'medium', type:'translation', tags:['can','meeting','leadership'], usageNote:'"Facilitate" (neutral guide), "run" (general chair), "lead" (directive chair) — different leadership roles.', office:'I can run this meeting effectively — I have prepared a clear agenda with time slots.', conversation:'A: Who should chair the session? B: I can run this meeting effectively — let me take over.' },
  { id:'d16-extra-166', hindi:'क्या वह अपनी गलती मान सकता है?', english:'Can he admit his mistake?', alternatives:['is he able to accept his error?','can he acknowledge his mistake?'], hint:'Can + admit + his mistake', explanation:'"Admit a mistake" is direct and honest. "Acknowledge" is slightly more formal. "Accept" is also used but "acknowledge" is more specific to owning the mistake formally.', difficulty:'medium', type:'translation', tags:['can','honesty','accountability'], usageNote:'"Admit" (direct), "acknowledge" (formal acceptance), "accept" (broader ownership) — all valid.', office:'Can he admit his mistake and present a corrective plan to the client?', conversation:'A: He made a serious error. B: Can he admit his mistake? That is the first step forward.' },
  { id:'d16-extra-167', hindi:'मैं इस काम में अपना योगदान दे सकता हूँ।', english:'I can contribute to this work.', alternatives:['I can add value to this project.','I can play a part in this.'], hint:'Can + contribute + to this work', explanation:'"Contribute to" uses the preposition "to." "Add value to" is the business idiom equivalent. "Play a part in" is more general. All are strong professional expressions.', difficulty:'medium', type:'translation', tags:['can','contribution','teamwork'], usageNote:'"Add value" is a strong business idiom for making meaningful contributions.', office:'I can contribute to this work through my expertise in supply chain management.', conversation:'A: Can you contribute to this work? B: Yes, I can contribute significantly — I have the relevant experience.' },
  { id:'d16-extra-168', hindi:'वह बिना आराम के कई घंटे काम कर सकती है।', english:'She can work for several hours without rest.', alternatives:['she can work for hours without a break.'], hint:'Can + work + for several hours + without rest', explanation:'"Without rest" and "without a break" are interchangeable. "Several hours" is vague but implies many. "For hours on end" is an idiomatic alternative meaning for a long continuous time.', difficulty:'medium', type:'translation', tags:['can','endurance','dedication'], usageNote:'"Hours on end" is idiomatic for very long continuous hours. "Without rest/break" — both natural.', office:'She can work for several hours without rest when the project requires it.', conversation:'A: The production will run overnight. B: She can work for several hours without rest — she is incredible.' },
  { id:'d16-extra-169', hindi:'क्या तुम इस परियोजना की अगुवाई कर सकते हो?', english:'Can you lead this project?', alternatives:['can you head this project?','are you able to take the lead on this project?'], hint:'Can you + lead + this project', explanation:'"Lead a project" is standard. "Head a project" means to be in charge. "Take the lead" is idiomatic meaning to take responsibility. All are natural in professional contexts.', difficulty:'medium', type:'translation', tags:['can','leadership','project'], usageNote:'"Lead," "head," and "take the lead on" — from verb to idiom, all express project leadership.', office:'Can you lead this project? We need someone with your technical background.', conversation:'A: We need a project lead. B: Can you lead this project? You have the most experience.' },
  { id:'d16-extra-170', hindi:'मैं अपनी टीम को प्रेरित कर सकता हूँ।', english:'I can motivate my team.', alternatives:['I can inspire my team.','I have the ability to keep my team motivated.'], hint:'Can + motivate + my team', explanation:'"Motivate my team" is a direct leadership claim. "Inspire" implies a deeper influence. "Keep motivated" maintains motivation over time. All are strong interview phrases.', difficulty:'medium', type:'translation', tags:['can','leadership','motivation'], usageNote:'"Motivate" (drive to act) vs. "inspire" (transformational change) — important leadership nuance.', office:'I can motivate my team even during the most challenging quarters.', conversation:'A: The team looks demoralized. B: I can motivate my team — give me a week.' },
  { id:'d16-extra-171', hindi:'वह बहुत कम खर्च में अच्छे परिणाम दे सकता है।', english:'He can deliver good results with very little budget.', alternatives:['he can achieve great outcomes on a tight budget.'], hint:'Can + deliver + results + with little budget', explanation:'"Deliver results" is the standard business phrase. "Achieve outcomes" is more formal. "On a tight budget" is the idiomatic phrase for limited financial resources.', difficulty:'hard', type:'translation', tags:['can','efficiency','budget'], usageNote:'"Deliver results" and "achieve outcomes" are business KPI-related expressions.', office:'He can deliver good results with very little budget — invaluable for our lean team.', conversation:'A: We have limited funding. B: He can deliver good results with very little budget — trust him.' },
  { id:'d16-extra-172', hindi:'क्या तुम इस काम को आज ही खत्म कर सकते हो?', english:'Can you finish this work today itself?', alternatives:['can you complete this today?','are you able to wrap this up today?'], hint:'Can you + finish + this work + today', explanation:'"Today itself" is Indian English — "today" alone or "by end of day" is more standard internationally. "Wrap up" is informal but very natural in spoken business English.', difficulty:'easy', type:'translation', tags:['can','deadline','urgency'], usageNote:'"Today itself" is Indian English. Prefer "today," "by EOD," or "before you leave."', office:'Can you finish this work today? The client needs it before their board meeting tomorrow.', conversation:'A: Can you finish this work today? B: Yes, I will have it done by 5 PM.' },
  { id:'d16-extra-173', hindi:'वे सभी एक साथ नाच सकते हैं।', english:'They can all dance together.', alternatives:['all of them can dance together.'], hint:'They can + all + dance + together', explanation:'"They can all" places "all" after the subject pronoun. "All of them can" places it in the subject noun phrase. Both are grammatically correct. "Together" emphasizes coordination.', difficulty:'easy', type:'translation', tags:['can','dance','group'], usageNote:'"They can all" and "all of them can" are equally natural — word order preference only.', office:'They can all dance together at the annual company cultural event.', conversation:'A: They can all dance together? B: Yes, they have been practicing for the performance.' },
  { id:'d16-extra-174', hindi:'मैं बिना किसी की परवाह किए अपना काम कर सकता हूँ।', english:"I can do my work without worrying about others' opinions.", alternatives:['I can focus on my work regardless of others.'], hint:"Can + do my work + without worrying + about others'", explanation:'"Without worrying about others\' opinions" uses a gerund phrase with a possessive. It expresses independence and focus. "Regardless of others" is more concise.', difficulty:'hard', type:'translation', tags:['can','focus','independence'], usageNote:'"Without worrying about" is a gerund phrase. The possessive "others\'" is required for the opinion.', office:"I can do my work without worrying about others' opinions — I stay focused on results.", conversation:"A: Do you care what colleagues think? B: I can do my work without worrying about others' opinions." },
  { id:'d16-extra-175', hindi:'क्या वह इस परियोजना में नया दृष्टिकोण ला सकती है?', english:'Can she bring a fresh perspective to this project?', alternatives:['can she offer a new viewpoint for this project?'], hint:'Can + bring + a fresh perspective + to this project', explanation:'"Bring a fresh perspective" is an excellent business phrase for introducing new thinking. "Fresh perspective" = new, unbiased view. "Viewpoint" is slightly less idiomatic here.', difficulty:'hard', type:'translation', tags:['can','creativity','innovation'], usageNote:'"Bring a fresh perspective" is a strong business idiom for innovative thinking.', office:'Can she bring a fresh perspective to this project? We have been too close to the problem.', conversation:'A: We are stuck. B: Can she bring a fresh perspective to this project? She is new to this domain.' },
  { id:'d16-extra-176', hindi:'मैं इस संकट को संभाल सकता हूँ।', english:'I can handle this crisis.', alternatives:['I can manage this emergency.','I can deal with this crisis.'], hint:'Can + handle + this crisis', explanation:'"Handle a crisis" is standard. "Manage an emergency" is formal. "Deal with a crisis" is slightly less formal. "Contain the crisis" focuses on limiting damage. Choose based on context.', difficulty:'medium', type:'translation', tags:['can','crisis-management','leadership'], usageNote:'"Handle" (general), "manage" (formal), "contain" (limit damage) — different crisis management actions.', office:'I can handle this crisis — please authorize me to contact the client directly.', conversation:'A: Everything is falling apart. B: Stay calm. I can handle this crisis.' },
  { id:'d16-extra-177', hindi:'वह हमेशा सही समय पर सही काम कर सकती है।', english:'She can always do the right thing at the right time.', alternatives:['she always knows what to do and when to do it.'], hint:'Can + always + do the right thing + at the right time', explanation:'"Do the right thing at the right time" is a well-known expression of good judgment. "Always" strengthens it. The phrase "right person, right place, right time" follows the same pattern.', difficulty:'hard', type:'translation', tags:['can','judgment','reliability'], usageNote:'"Do the right thing at the right time" expresses perfect situational judgment — powerful in performance reviews.', office:'She can always do the right thing at the right time — exceptional leadership quality.', conversation:'A: How does she manage so well? B: She can always do the right thing at the right time.' },
  { id:'d16-extra-178', hindi:'मैं बड़े से बड़े लक्ष्य हासिल कर सकता हूँ।', english:'I can achieve even the biggest goals.', alternatives:['I can reach the highest targets.','I can accomplish great things.'], hint:'Can + achieve + even the biggest goals', explanation:'"Even the biggest goals" uses "even" to emphasize the extremity of the achievement. "Even" adds surprising emphasis. "Highest targets" is more measurable/business-specific.', difficulty:'hard', type:'translation', tags:['can','ambition','achievement'], usageNote:'"Even" adds emphasis: "even the most difficult task" = regardless of how difficult.', office:'I can achieve even the biggest goals when given the resources and support.', conversation:'A: Is he ambitious? B: I can achieve even the biggest goals — that is my personal motto.' },
  { id:'d16-extra-179', hindi:'क्या हम इस कंपनी को आगे बढ़ा सकते हैं?', english:'Can we take this company forward?', alternatives:['can we grow this company?','can we propel this company forward?'], hint:'Can we + take + this company + forward', explanation:'"Take forward" is a business phrase meaning to advance or develop. "Grow" is more specific to expansion. "Propel" is dramatic and motivational. All are acceptable.', difficulty:'medium', type:'translation', tags:['can','leadership','business-growth'], usageNote:'"Take forward" is a business idiom for advancing something. "Propel" adds dramatic emphasis.', office:'Can we take this company forward by leveraging our combined expertise?', conversation:'A: What is our vision? B: Can we take this company forward to be the industry leader?' },
  { id:'d16-extra-180', hindi:'वह सुबह पाँच बजे उठ सकता है।', english:'He can wake up at five in the morning.', alternatives:['he can get up at 5 AM.'], hint:'Can + wake up + at five in the morning', explanation:'"At five in the morning" is the natural time expression. "5 AM" is more formal/written. "Get up" and "wake up" are both standard. In British English, "at 5 o\'clock in the morning" is also used.', difficulty:'easy', type:'translation', tags:['can','morning','routine'], usageNote:'"Wake up" (stop sleeping), "get up" (leave the bed) — subtle difference; both common.', office:'He can wake up at five in the morning for the early client calls from Europe.', conversation:'A: The call is at 6 AM. B: He can wake up at five in the morning easily.' },
  { id:'d16-extra-181', hindi:'मैं इस तकनीक को बहुत जल्दी सीख सकता हूँ।', english:'I can learn this technology very quickly.', alternatives:['I can get up to speed on this technology fast.'], hint:'Can + learn + this technology + very quickly', explanation:'"Get up to speed" is an excellent business idiom meaning to quickly reach a required level of knowledge. "Learn this technology" is the more direct phrasing.', difficulty:'medium', type:'translation', tags:['can','technology','learning'], usageNote:'"Get up to speed" is a business idiom for quickly becoming competent. Excellent for interviews.', office:'I can learn this technology very quickly — I have already reviewed the documentation.', conversation:'A: Have you used this platform before? B: No, but I can learn this technology very quickly.' },
  { id:'d16-extra-182', hindi:'क्या तुम यह जानकारी उनके साथ साझा कर सकते हो?', english:'Can you share this information with them?', alternatives:['could you forward this information to them?'], hint:'Can you + share + this information + with them', explanation:'"Share information with" is the standard phrasing. "Forward" is email-specific. "Distribute" is more formal and formal presentations. All are correct depending on context.', difficulty:'easy', type:'translation', tags:['can','sharing','communication'], usageNote:'"Share with" (general), "forward to" (email), "distribute to" (formal mass sharing) — context matters.', office:'Can you share this information with them before the vendor meeting?', conversation:'A: They need the details. B: Can you share this information with them? I have the document.' },
  { id:'d16-extra-183', hindi:'वह किसी को भी भरोसे में ले सकती है।', english:'She can gain anyone\'s trust.', alternatives:['she can earn the trust of anyone.','she can win people over easily.'], hint:"Can + gain + anyone's trust", explanation:'"Gain someone\'s trust" is standard. "Earn trust" is more deliberate and effort-based. "Win someone over" is idiomatic meaning to persuade or charm. All are natural.', difficulty:'hard', type:'translation', tags:['can','trust','interpersonal'], usageNote:'"Gain trust" and "earn trust" are slightly different — "earn" implies more effort/deservingness.', office:"She can gain anyone's trust quickly — essential for her role in client relationship management.", conversation:"A: Is she good with new clients? B: She can gain anyone's trust within a single meeting." },
  { id:'d16-extra-184', hindi:'मैं ज़रूरत पड़ने पर तुरंत निर्णय ले सकता हूँ।', english:'I can make immediate decisions when needed.', alternatives:['I can decide instantly when required.'], hint:'Can + make + immediate decisions + when needed', explanation:'"Immediate decisions" are made without delay. "When needed" is a conditional adverbial clause. "When required" is slightly more formal. "Instantly" is the adverb equivalent.', difficulty:'medium', type:'translation', tags:['can','decision-making','urgency'], usageNote:'"When needed" and "when required" are interchangeable. "Required" is slightly more formal.', office:'I can make immediate decisions when needed — critical for our fast-paced trading environment.', conversation:'A: Can you make immediate decisions when needed? B: Yes — I am trained to act quickly under pressure.' },
  { id:'d16-extra-185', hindi:'क्या वे हमारे साथ इस समझौते पर हस्ताक्षर कर सकते हैं?', english:'Can they sign this agreement with us?', alternatives:['are they able to execute this agreement?','can they enter into this agreement with us?'], hint:'Can + they + sign + this agreement + with us', explanation:'"Sign an agreement" is the standard business phrase. "Execute an agreement" is legal jargon for the same. "Enter into an agreement" is the formal legal phrase for establishing a contractual relationship.', difficulty:'hard', type:'translation', tags:['can','legal','agreement'], usageNote:'"Execute" (legal: sign and activate) vs. "sign" (physical action) — "execute" is more legally precise.', office:'Can they sign this agreement with us before the end of the financial year?', conversation:'A: Have they confirmed? B: Can they sign this agreement with us at Friday\'s meeting?' },
  { id:'d16-extra-186', hindi:'वह कभी भी हार नहीं मान सकता।', english:'He can never give up.', alternatives:['he is incapable of giving up.','he never gives up.'], hint:"Can + never + give up (can't / capability)", explanation:'"Can never give up" uses "can" with "never" to express absolute incapacity to surrender. "Never gives up" is present simple. "Incapable of" is formal. All express the same resilience.', difficulty:'medium', type:'translation', tags:['can','resilience','motivation'], usageNote:'"Can never" emphasizes impossibility of the action — stronger than "does not."', office:'He can never give up on a client account — his persistence has saved deals others abandoned.', conversation:'A: He keeps trying despite the failures. B: He can never give up — that is just who he is.' },
  { id:'d16-extra-187', hindi:'मैं इस स्थिति में शांत रह सकती हूँ।', english:'I can remain calm in this situation.', alternatives:['I can stay composed in this situation.','I can keep my cool in this situation.'], hint:'Can + remain calm + in this situation', explanation:'"Remain calm" is formal and professional. "Stay composed" is equally professional. "Keep my cool" is idiomatic and slightly informal. All express emotional control.', difficulty:'medium', type:'translation', tags:['can','composure','emotional-intelligence'], usageNote:'"Keep cool" is idiomatic; "remain composed" and "stay calm" are formal equivalents.', office:'I can remain calm in this situation and give you a rational analysis.', conversation:'A: Everyone is panicking. B: I can remain calm in this situation — let me think this through.' },
  { id:'d16-extra-188', hindi:'क्या हम इस परियोजना को मिलकर खत्म कर सकते हैं?', english:'Can we finish this project together?', alternatives:['can we complete this project as a team?'], hint:'Can we + finish + this project + together', explanation:'"Finish this project together" emphasizes joint effort. "As a team" specifies the collaborative structure. Both are natural and motivating in team communication.', difficulty:'easy', type:'translation', tags:['can','teamwork','collaboration'], usageNote:'"Together" (general collaboration) vs. "as a team" (structured team effort) — slight emphasis difference.', office:'Can we finish this project together before the management review on Monday?', conversation:'A: This is a big task. B: Can we finish this project together? I will take the data analysis part.' },
  { id:'d16-extra-189', hindi:'वह अपने भाई को पढ़ाई में मदद कर सकती है।', english:'She can help her brother with his studies.', alternatives:['she can assist her brother with his studies.'], hint:'Can + help + someone + with + studies', explanation:'"Help someone with studies" uses "with" as the linking preposition. "Assist" is more formal. "With his studies" specifies the area of help. Never say "help to studies."', difficulty:'easy', type:'translation', tags:['can','education','family'], usageNote:'"Help with" is the standard structure. "Help to + verb" is also correct: help to study.', office:'She can help her brother with his studies — she has a tutoring certificate.', conversation:'A: His grades are poor. B: She can help her brother with his studies — she is excellent at math.' },
  { id:'d16-extra-190', hindi:'मैं इस टीम का नेतृत्व कर सकता हूँ।', english:'I can lead this team.', alternatives:['I am capable of leading this team.','I can head this team.'], hint:'Can + lead + this team', explanation:'"Lead a team" is the standard leadership phrase. "Head a team" means to be in charge. "Captain a team" is used for sports. "Manage a team" focuses on administration. Choose based on context.', difficulty:'medium', type:'translation', tags:['can','leadership','team'], usageNote:'"Lead" (directional), "manage" (administrative), "head" (in charge), "captain" (sports) — leadership words.', office:'I can lead this team through the product launch — I have done it twice before.', conversation:'A: Who should lead the initiative? B: I can lead this team — I have the experience and the trust of the members.' },
  { id:'d16-extra-191', hindi:'क्या वह इस विषय पर व्याख्यान दे सकती है?', english:'Can she give a lecture on this topic?', alternatives:['is she able to speak on this subject?','can she deliver a talk on this topic?'], hint:'Can + give a lecture + on this topic', explanation:'"Give a lecture" is the standard academic/formal phrase. "Deliver a talk" is equally formal. "Speak on a topic" is slightly less formal. All are appropriate.', difficulty:'medium', type:'translation', tags:['can','public-speaking','academic'], usageNote:'"Give a lecture" (academic), "deliver a talk" (formal event), "speak on" (general) — register varies.', office:'Can she give a lecture on this topic at the industry conference next month?', conversation:'A: We need a speaker for the seminar. B: Can she give a lecture on this topic? She is the domain expert.' },
  { id:'d16-extra-192', hindi:'मैं किसी के साथ भी अच्छे से बात कर सकता हूँ।', english:'I can talk well with anyone.', alternatives:['I can communicate effectively with anyone.','I am easy to talk to.'], hint:'Can + talk well + with anyone', explanation:'"Talk well with anyone" shows interpersonal ease. "Communicate effectively" is the formal equivalent. "Easy to talk to" is a passive construction that others would use to describe you.', difficulty:'medium', type:'translation', tags:['can','communication','interpersonal'], usageNote:'"Talk well with anyone" (first-person ability) vs. "easy to talk to" (what others perceive).', office:'I can talk well with anyone — from factory workers to board members.', conversation:'A: You seem to get on with everyone. B: I can talk well with anyone — I enjoy connecting with people.' },
  { id:'d16-extra-193', hindi:'वे बिना किसी रुकावट के काम कर सकते हैं।', english:'They can work without any interruptions.', alternatives:['they can work without being disturbed.','they can work uninterrupted.'], hint:'Can + work + without any interruptions', explanation:'"Without any interruptions" is a complete phrase. "Uninterrupted" is the single-adjective equivalent. "Without being disturbed" uses a passive gerund. All are correct.', difficulty:'medium', type:'translation', tags:['can','focus','productivity'], usageNote:'"Uninterrupted" is the adjective form. "Without interruption" (singular) is also standard.', office:'They can work without any interruptions in the dedicated project room.', conversation:'A: They need quiet. B: They can work without any interruptions in the back office.' },
  { id:'d16-extra-194', hindi:'क्या तुम इस सवाल का सही जवाब दे सकते हो?', english:'Can you give the correct answer to this question?', alternatives:['can you answer this question correctly?'], hint:'Can you + give + the correct answer + to this question', explanation:'"Give the correct answer to this question" is explicit and formal. "Answer this question correctly" is more concise. In exams/formal settings, the first version is more precise.', difficulty:'medium', type:'translation', tags:['can','knowledge','accuracy'], usageNote:'"Give the correct answer to" is formal; "answer correctly" is concise. Both are standard.', office:'Can you give the correct answer to this question from the client about our service?', conversation:'A: Can you give the correct answer to this question? B: Yes — the answer is Section 5 of the contract.' },
  { id:'d16-extra-195', hindi:'वह इस दौड़ में सबसे आगे निकल सकता है।', english:'He can come out ahead in this race.', alternatives:['he can win this race.','he can finish first in this race.'], hint:'Can + come out ahead + in this race', explanation:'"Come out ahead" is an idiomatic phrase meaning to finish in a leading position. "Win" is direct. "Finish first" is specific. In business, "come out ahead" is used for competitive scenarios.', difficulty:'hard', type:'translation', tags:['can','competition','winning'], usageNote:'"Come out ahead" is idiomatic for winning or leading in competitive situations.', office:'He can come out ahead in this race for the regional sales award.', conversation:'A: It is a tough competition. B: He can come out ahead in this race — he always delivers.' },
  { id:'d16-extra-196', hindi:'मैं हर दिन कुछ नया सीख सकती हूँ।', english:'I can learn something new every day.', alternatives:['I learn something new every day.','I can discover something new each day.'], hint:'Can + learn + something new + every day', explanation:'"Learn something new every day" is both a statement of ability and a growth mindset phrase. "Every day" is two words (adverb). "Everyday" (adjective) would be incorrect here.', difficulty:'easy', type:'translation', tags:['can','learning','growth-mindset'], usageNote:'"Every day" (adverb, two words) vs. "everyday" (adjective, one word). "Every day" is correct here.', office:'I can learn something new every day in this role — it is intellectually stimulating.', conversation:'A: Do you get bored? B: I can learn something new every day here — never boring.' },
  { id:'d16-extra-197', hindi:'क्या हम इस बजट में काम चला सकते हैं?', english:'Can we manage within this budget?', alternatives:['can we work with this budget?','are we able to operate within this budget?'], hint:'Can we + manage + within this budget', explanation:'"Manage within a budget" is the professional phrase. "Work with a budget" is more casual. "Operate within" is formal financial language. All are correct.', difficulty:'medium', type:'translation', tags:['can','budget','finance'], usageNote:'"Operate within budget" is formal financial language; "manage within budget" is professional general.', office:'Can we manage within this budget if we cut the travel expenses by half?', conversation:'A: The budget has been reduced. B: Can we manage within this budget? We need to reprioritize.' },
  { id:'d16-extra-198', hindi:'वह पूरे विश्वास के साथ बोल सकती है।', english:'She can speak with full confidence.', alternatives:['she speaks with great confidence.','she can communicate confidently.'], hint:'Can + speak + with full confidence', explanation:'"With full confidence" is a strong adverbial phrase. "Confidently" converts it to a single adverb. "With great confidence" is also correct. All are appropriate for professional profiles.', difficulty:'medium', type:'translation', tags:['can','confidence','public-speaking'], usageNote:'"With confidence" (moderate) vs. "with full confidence" (absolute) — degree matters.', office:'She can speak with full confidence in front of the entire board — impressive composure.', conversation:'A: Is she nervous? B: She can speak with full confidence — she has given dozens of talks.' },
  { id:'d16-extra-199', hindi:'मैं अपनी ज़िंदगी में एक बड़ा बदलाव ला सकता हूँ।', english:'I can bring a big change to my life.', alternatives:['I can make a major change in my life.','I can transform my life.'], hint:'Can + bring + a big change + to my life', explanation:'"Bring a change to" and "make a change in" — both prepositions are correct. "Transform" is more dramatic and implies complete overhaul. All are motivational phrasing.', difficulty:'medium', type:'translation', tags:['can','personal-growth','transformation'], usageNote:'"Bring a change to" and "make a change in" — both correct with slightly different prepositions.', office:'I can bring a big change to my life by enrolling in this professional development program.', conversation:'A: Are you making any changes? B: I can bring a big change to my life this year — I am committed.' },
  { id:'d16-extra-200', hindi:'क्या वे हमसे ज़्यादा तेज़ काम कर सकते हैं?', english:'Can they work faster than us?', alternatives:['are they able to outperform us in speed?'], hint:'Can + they + work + faster than + us', explanation:'"Faster than us" is a comparative construction. "Outperform us in speed" is more formal. "Than us" is the correct object pronoun form (though "than we" is formal grammar, "than us" is universally accepted).', difficulty:'medium', type:'translation', tags:['can','competition','speed'], usageNote:'"Faster than us" is natural spoken English; "faster than we" is formal written grammar. Both acceptable.', office:'Can they work faster than us? Let us look at the comparative metrics from last quarter.', conversation:'A: Can they work faster than us? B: Maybe in quantity, but not in quality.' },
  { id:'d16-extra-201', hindi:'मैं आज आपकी ज़रूर मदद कर सकता हूँ।', english:'I can definitely help you today.', alternatives:['I am certainly able to assist you today.'], hint:'Can + definitely + help + you + today', explanation:'"Definitely" strengthens the affirmation. It can appear after "can" or at the end. "Certainly" is the formal equivalent. Both add a confident, helpful tone.', difficulty:'easy', type:'translation', tags:['can','help','affirmation'], usageNote:'"Definitely" and "certainly" both add strong affirmation. "Definitely" is more casual.', office:'I can definitely help you today with the client proposal.', conversation:'A: Can you help me with this? B: I can definitely help you today — when would you like to start?' },
  { id:'d16-extra-202', hindi:'वह इस भूमिका के लिए सबसे उपयुक्त है।', english:'She can be the best fit for this role.', alternatives:['she is the most suitable candidate for this role.'], hint:'Can + be + the best fit + for this role', explanation:'"Best fit" is a modern HR phrase for the most suitable candidate. "Most suitable" is more formal. Both work in professional contexts. "Can be" suggests potential/possibility.', difficulty:'medium', type:'translation', tags:['can','hiring','suitability'], usageNote:'"Best fit" is HR/recruitment jargon. "Most suitable" is formal English. Both are standard.', office:'She can be the best fit for this role given her background in data science.', conversation:'A: Who should we hire? B: She can be the best fit for this role — look at her portfolio.' },
  { id:'d16-extra-203', hindi:'क्या तुम इस घर को सजा सकते हो?', english:'Can you decorate this house?', alternatives:['are you able to decorate this home?'], hint:'Can you + decorate + this house', explanation:'"Decorate a house" means to arrange/beautify the interior. "Design" is more professional. "Furnish" is more specific to adding furniture. "Decorate" is the general term.', difficulty:'easy', type:'translation', tags:['can','decoration','home'], usageNote:'"Decorate" (general), "design" (professional), "furnish" (furniture-specific) — progressive levels of formality.', office:'Can you decorate this house for the company\'s client entertainment event?', conversation:'A: Can you decorate this house for the party? B: Yes, I have great ideas for the theme.' },
  { id:'d16-extra-204', hindi:'वह बहुत जल्दी दोस्त बना लेता है।', english:'He can make friends very quickly.', alternatives:['he is very good at making friends.','he befriends people easily.'], hint:'Can + make friends + very quickly', explanation:'"Make friends quickly" shows strong social skills. "Befriend" is a formal single verb. "Good at making friends" converts it to an adjective phrase.', difficulty:'easy', type:'translation', tags:['can','social-skills','interpersonal'], usageNote:'"Befriend" is formal; "make friends" is natural conversational English.', office:'He can make friends very quickly — perfect for the business development role.', conversation:'A: He just joined but knows everyone already. B: He can make friends very quickly.' },
  { id:'d16-extra-205', hindi:'मैं इस महीने में अपना लक्ष्य पूरा कर सकती हूँ।', english:'I can achieve my goal this month.', alternatives:['I can reach my target this month.','I can accomplish my objective this month.'], hint:'Can + achieve + my goal + this month', explanation:'"Achieve a goal" is the standard phrase. "Reach a target" is more business-specific. "Accomplish an objective" is more formal. All are correct.', difficulty:'easy', type:'translation', tags:['can','goals','achievement'], usageNote:'"Goal" (general), "target" (measurable), "objective" (formal/strategic) — different registers.', office:'I can achieve my goal this month if we maintain the current sales momentum.', conversation:'A: How are you tracking? B: I can achieve my goal this month — I am 80% there.' },
  { id:'d16-extra-206', hindi:'क्या वे इस चुनौती से पार पा सकते हैं?', english:'Can they overcome this challenge?', alternatives:['can they get through this challenge?','are they able to rise above this challenge?'], hint:'Can + they + overcome + this challenge', explanation:'"Overcome a challenge" is the most common and natural phrasing. "Get through" is idiomatic for completing a difficult experience. "Rise above" is more elevated/inspirational.', difficulty:'medium', type:'translation', tags:['can','challenge','resilience'], usageNote:'"Rise above" is inspirational/metaphorical. "Overcome" is direct and professional.', office:'Can they overcome this challenge and deliver the project despite the team reduction?', conversation:'A: This seems impossible. B: Can they overcome this challenge? They have done harder things before.' },
  { id:'d16-extra-207', hindi:'वह हिंदी, अंग्रेज़ी और बंगाली बोल सकता है।', english:'He can speak Hindi, English, and Bengali.', alternatives:['he is fluent in Hindi, English, and Bengali.'], hint:'Can + speak + multiple languages (list)', explanation:'"Can speak + list of languages" is the standard structure. In formal contexts, use "fluent in" for languages you speak at a high level. "Conversational in" is used for moderate fluency.', difficulty:'easy', type:'translation', tags:['can','languages','multilingual'], usageNote:'"Fluent in" implies high proficiency; "conversational in" implies moderate; "basic in" implies beginner.', office:'He can speak Hindi, English, and Bengali — excellent for our multilingual client base.', conversation:'A: How many languages does he know? B: He can speak Hindi, English, and Bengali fluently.' },
  { id:'d16-extra-208', hindi:'मैं बिना गाइड के भी यह जगह ढूंढ सकती हूँ।', english:'I can find this place without a guide.', alternatives:['I can navigate to this place on my own.'], hint:'Can + find + this place + without a guide', explanation:'"Find this place without a guide" expresses navigational independence. "Navigate to" is more formal/technical. "On my own" emphasizes self-reliance.', difficulty:'medium', type:'translation', tags:['can','navigation','independence'], usageNote:'"Without a guide" specifies the condition; "on my own" emphasizes self-reliance.', office:'I can find this place without a guide — I visited the venue last year.', conversation:'A: We do not have a guide. B: I can find this place without a guide — I know the area.' },
  { id:'d16-extra-209', hindi:'क्या तुम मुझे एक उदाहरण दे सकते हो?', english:'Can you give me an example?', alternatives:['could you provide an example?','can you illustrate this with an example?'], hint:'Can you + give + me + an example', explanation:'"Give me an example" is very natural in both classrooms and business. "Provide an example" is more formal. "Illustrate with an example" emphasizes the purpose of clarifying through demonstration.', difficulty:'easy', type:'translation', tags:['can','clarification','example'], usageNote:'"Illustrate with an example" is academic language; "give me an example" is natural in all settings.', office:'Can you give me an example of how this feature works in practice?', conversation:'A: I do not understand the concept. B: Can you give me an example? That will help.' },
  { id:'d16-extra-210', hindi:'वह बहुत मुश्किल प्रश्नों का उत्तर दे सकती है।', english:'She can answer very difficult questions.', alternatives:['she can tackle the toughest questions.'], hint:'Can + answer + very difficult questions', explanation:'"Answer very difficult questions" is direct and impressive. "Tackle the toughest questions" uses the informal verb "tackle" which is strong and energetic. Both are natural.', difficulty:'medium', type:'translation', tags:['can','knowledge','expertise'], usageNote:'"Tackle" is informal but energetic — great for spoken communication; "answer" is universally appropriate.', office:'She can answer very difficult questions from regulators without any preparation.', conversation:'A: The press will ask tough questions. B: She can answer very difficult questions — she knows every detail.' },
  { id:'d16-extra-211', hindi:'मैं यहाँ आकर बहुत खुश हूँ।', english:'I am very happy to be here.', alternatives:['I am delighted to be here.'], hint:'I am + happy + to be here', explanation:'This sentence does not actually use "can" — it tests whether the student knows when NOT to use can. "I am happy to be here" is correct. "I can be very happy to be here" would be incorrect.', difficulty:'easy', type:'translation', tags:['can','state-verb','to-be'], usageNote:'State verbs like "be happy" do not use "can" — do not say "I can be happy to be here."', office:'I am very happy to be here for the product launch ceremony.', conversation:'A: Welcome! B: Thank you — I am very happy to be here.' },
  { id:'d16-extra-212', hindi:'क्या आप इस मुद्दे पर विचार कर सकते हैं?', english:'Can you think about this issue?', alternatives:['could you consider this issue?','would you please look into this matter?'], hint:'Can you + think about + this issue', explanation:'"Think about" uses "about" as a preposition. "Consider" is more formal and concise. "Look into" suggests investigation. "Think over" means to consider carefully.', difficulty:'medium', type:'translation', tags:['can','consideration','analysis'], usageNote:'"Think about" (reflect), "consider" (formal deliberation), "look into" (investigate), "think over" (careful reflection).', office:'Can you think about this issue and provide your recommendation by Friday?', conversation:'A: Can you think about this issue? B: Yes, I will give you my thoughts by end of day.' },
  { id:'d16-extra-213', hindi:'वह बहुत लंबे समय तक ध्यान केंद्रित कर सकता है।', english:'He can focus for a very long time.', alternatives:['he has excellent concentration.','he can concentrate for extended periods.'], hint:'Can + focus + for a very long time', explanation:'"Focus for a long time" describes sustained attention. "Concentrate for extended periods" is more formal. "Excellent concentration" converts it to an adjective phrase for profiles/resumes.', difficulty:'medium', type:'translation', tags:['can','focus','concentration'], usageNote:'"Focus for a long time" vs. "excellent concentration" — verb phrase vs. noun phrase for the same quality.', office:'He can focus for a very long time — zero distractions during deep-work sessions.', conversation:'A: Does he get distracted? B: He can focus for a very long time — very disciplined.' },
  { id:'d16-extra-214', hindi:'मैं अपने लक्ष्य को कभी नहीं भूल सकती।', english:'I can never forget my goal.', alternatives:['I will never forget my goal.','I never lose sight of my goal.'], hint:"Can + never + forget + my goal", explanation:'"Can never forget" expresses absolute inability to forget — stronger than "will never forget." "Never lose sight of" is idiomatic meaning to always keep something in focus.', difficulty:'medium', type:'translation', tags:['can','goals','determination'], usageNote:'"Can never" (inability) is stronger than "will never" (choice). "Never lose sight of" is idiomatic.', office:'I can never forget my goal of becoming a certified project manager.', conversation:'A: Do you ever get demotivated? B: I can never forget my goal — it keeps me going.' },
  { id:'d16-extra-215', hindi:'क्या वे मिलकर यह काम कर सकते हैं?', english:'Can they do this work together?', alternatives:['can they collaborate on this work?'], hint:'Can + they + do this work + together', explanation:'"Do this work together" is direct and simple. "Collaborate on this work" is more formal and specifically implies joint contribution. Both are natural in professional settings.', difficulty:'easy', type:'translation', tags:['can','teamwork','collaboration'], usageNote:'"Collaborate" is more formal and implies structured joint contribution, not just working in proximity.', office:'Can they do this work together? Combining their skills would produce better results.', conversation:'A: Can they do this work together? B: Yes, they work very well as a pair.' },
  { id:'d16-extra-216', hindi:'वह घर से ऑफिस चला सकती है।', english:'She can run the office from home.', alternatives:['she can manage the office remotely.'], hint:'Can + run + the office + from home', explanation:'"Run the office from home" is idiomatic, meaning to manage operations remotely. "Manage remotely" is the formal equivalent. Both are natural in the context of remote work.', difficulty:'medium', type:'translation', tags:['can','remote-work','management'], usageNote:'"Run the office" is idiomatic for managing operations. "From home" makes it remote work.', office:'She can run the office from home during the renovation period.', conversation:'A: The office will be closed for a week. B: She can run the office from home.' },
  { id:'d16-extra-217', hindi:'मैं इस मशीन को बिना मैन्युअल के चला सकता हूँ।', english:'I can operate this machine without a manual.', alternatives:['I can use this machine without instructions.'], hint:'Can + operate + this machine + without a manual', explanation:'"Without a manual" means without written instructions. "Without instructions" is broader. "Manual" can also be "user guide" or "handbook." The preposition "without" is followed by a noun, not a verb.', difficulty:'medium', type:'translation', tags:['can','technical','self-reliance'], usageNote:'"Without a manual" = independently. Other options: user guide, handbook, instructions.', office:'I can operate this machine without a manual — I have used it for three years.', conversation:'A: The manual is missing. B: No problem — I can operate this machine without a manual.' },
  { id:'d16-extra-218', hindi:'क्या हम इस स्थान पर बैठक कर सकते हैं?', english:'Can we hold a meeting at this place?', alternatives:['can we have a meeting here?','can we convene here?'], hint:'Can we + hold a meeting + at this place', explanation:'"Hold a meeting" is standard. "Have a meeting" is more casual but equally correct. "Convene" is formal and is usually used in official/legal contexts.', difficulty:'medium', type:'translation', tags:['can','meeting','venue'], usageNote:'"Hold a meeting" (professional), "have a meeting" (casual), "convene" (formal/official).', office:'Can we hold a meeting at this place? The ambiance will set a relaxed tone for negotiations.', conversation:'A: Can we hold a meeting at this place? B: Yes, I will book the conference room.' },
  { id:'d16-extra-219', hindi:'वह किसी भी विषय पर शोध कर सकता है।', english:'He can research any topic.', alternatives:['he can conduct research on any topic.'], hint:'Can + research + any topic', explanation:'"Research a topic" uses research as a verb — standard in modern English. "Conduct research on" uses research as a noun — more formal. Both are correct.', difficulty:'medium', type:'translation', tags:['can','research','academia'], usageNote:'"Research a topic" (verb) is modern and natural. "Conduct research on" (noun) is formal/academic.', office:'He can research any topic and deliver a comprehensive report within 24 hours.', conversation:'A: We need background on this competitor. B: He can research any topic — give him the brief.' },
  { id:'d16-extra-220', hindi:'मैं बहुत कठिन परिस्थितियों में भी ध्यान केंद्रित रख सकती हूँ।', english:'I can stay focused even in very difficult situations.', alternatives:['I can maintain focus even under pressure.'], hint:'Can + stay focused + even in difficult situations', explanation:'"Stay focused even in difficult situations" combines resilience with concentration. "Maintain focus under pressure" is the business idiom equivalent. Both are strong interview phrases.', difficulty:'hard', type:'translation', tags:['can','focus','resilience'], usageNote:'"Maintain focus under pressure" is a strong professional phrase for high-stress environments.', office:'I can stay focused even in very difficult situations — critical for our fast-paced trading floor.', conversation:'A: Do you get flustered? B: No, I can stay focused even in very difficult situations.' },
  { id:'d16-extra-221', hindi:'क्या वह इस पद के लिए योग्य है?', english:'Can she qualify for this position?', alternatives:['is she qualified for this position?','does she meet the requirements for this role?'], hint:'Can she + qualify for + this position', explanation:'"Qualify for" means to meet the requirements. "Is qualified" is a state (already qualified). "Can qualify" suggests the potential to meet the requirements. Different tenses, different meanings.', difficulty:'hard', type:'translation', tags:['can','qualification','hiring'], usageNote:'"Can qualify" (potential) vs. "is qualified" (current state) — important distinction for HR contexts.', office:'Can she qualify for this position if she completes the certification?', conversation:'A: Can she qualify for this position? B: Yes, once she finishes the training.' },
  { id:'d16-extra-222', hindi:'वह खुद ही अपनी समस्याएँ सुलझा सकता है।', english:'He can solve his own problems himself.', alternatives:['he can sort out his own problems.','he resolves his own issues independently.'], hint:'Can + solve + his own problems + himself', explanation:'"His own problems himself" uses both the possessive "own" and the reflexive "himself" for double emphasis. "His own" alone is sufficient. "Sort out" is idiomatic for solving problems.', difficulty:'medium', type:'translation', tags:['can','independence','problem-solving'], usageNote:'"Sort out" is idiomatic for resolving issues. "His own...himself" = double emphasis — "own" is enough.', office:'He can solve his own problems without escalating to management — very self-sufficient.', conversation:'A: Does he ask for help often? B: No, he can solve his own problems — very independent.' },
  { id:'d16-extra-223', hindi:'मैं इस काम को ईमानदारी से कर सकता हूँ।', english:'I can do this work honestly.', alternatives:['I can carry out this work with integrity.'], hint:'Can + do + this work + honestly', explanation:'"Honestly" is the adverb form of honest. "With integrity" is a more formal phrase that includes broader ethical principles. Both are powerful in professional contexts.', difficulty:'easy', type:'translation', tags:['can','integrity','ethics'], usageNote:'"With integrity" is broader than "honestly" — it includes fairness, ethics, and accountability.', office:'I can do this work honestly and deliver results without cutting corners.', conversation:'A: Can we trust you with this sensitive data? B: I can do this work honestly — integrity is my core value.' },
  { id:'d16-extra-224', hindi:'क्या आप यह दस्तावेज़ मुझे ईमेल कर सकते हैं?', english:'Can you email this document to me?', alternatives:['could you send this document to me by email?'], hint:'Can you + email + this document + to me', explanation:'"Email" can be used as a verb: "email a document to someone." This is standard in modern business English. "Send by email" is the more traditional phrasing. Both are correct.', difficulty:'easy', type:'translation', tags:['can','email','office'], usageNote:'"Email" as a verb is modern and standard: "email the document to me" is concise and natural.', office:'Can you email this document to me before the 3 PM meeting?', conversation:'A: I need the file. B: Can you email this document to me? My download is not working.' },
  { id:'d16-extra-225', hindi:'वह पूरे विश्वास के साथ इंटरव्यू दे सकता है।', english:'He can face an interview with full confidence.', alternatives:['he can attend an interview confidently.','he can handle interviews with ease.'], hint:'Can + face + an interview + with full confidence', explanation:'"Face an interview" is natural in Indian English and is understood globally. "Attend an interview" is slightly unusual (attend = be present at). "Give an interview" is also Indian English. "Go for an interview" is the most globally natural phrasing.', difficulty:'medium', type:'translation', tags:['can','interview','confidence'], usageNote:'"Appear for" or "go for" an interview is globally natural; "face" is understood; "give" is Indian English.', office:'He can face an interview with full confidence after six months of preparation.', conversation:'A: Is he ready? B: He can face an interview with full confidence — he is very well prepared.' },
  { id:'d16-extra-226', hindi:'मैं हिंदी को रोमन लिपि में लिख सकती हूँ।', english:'I can write Hindi in Roman script.', alternatives:['I can transliterate Hindi into Roman script.'], hint:'Can + write + language + in + script', explanation:'"Write Hindi in Roman script" means using Roman/Latin letters for Hindi sounds (Romanization/transliteration). "Transliterate" is the technical term for converting text from one script to another.', difficulty:'medium', type:'translation', tags:['can','language','script'], usageNote:'"Transliterate" means to convert text into a different script, not to translate the meaning.', office:'I can write Hindi in Roman script, which is useful for international teams who cannot read Devanagari.', conversation:'A: Can the foreign team read this? B: I can write Hindi in Roman script so they can read it.' },
  { id:'d16-extra-227', hindi:'क्या वे समय पर डिलीवरी कर सकते हैं?', english:'Can they deliver on time?', alternatives:['are they able to deliver on schedule?'], hint:'Can + they + deliver + on time', explanation:'"Deliver on time" is a standard business expression. "On schedule" is equivalent and slightly more formal. "Meet the delivery timeline" is the most formal version.', difficulty:'easy', type:'translation', tags:['can','delivery','punctuality'], usageNote:'"On time," "on schedule," and "within the timeline" — increasingly formal expressions for punctual delivery.', office:'Can they deliver on time? The client has zero tolerance for delays.', conversation:'A: Can they deliver on time? B: Yes, they have a perfect track record.' },
  { id:'d16-extra-228', hindi:'वह बहुत कम समय में बड़े फ़ैसले ले सकती है।', english:'She can make major decisions in very little time.', alternatives:['she can take critical decisions quickly.'], hint:'Can + make + major decisions + in very little time', explanation:'"Make major decisions in very little time" emphasizes both the magnitude and speed of decision-making. "Critical decisions quickly" is the condensed professional version.', difficulty:'hard', type:'translation', tags:['can','decision-making','speed'], usageNote:'"Major / critical / significant decisions" — all suitable for high-stakes decision-making contexts.', office:'She can make major decisions in very little time — essential for our real-time trading desk.', conversation:'A: The window for decision is tiny. B: She can make major decisions in very little time.' },
  { id:'d16-extra-229', hindi:'मैं इस नई भूमिका की ज़िम्मेदारियाँ संभाल सकता हूँ।', english:'I can handle the responsibilities of this new role.', alternatives:['I am capable of managing this new role\'s duties.'], hint:'Can + handle + responsibilities + of this role', explanation:'"Handle the responsibilities" is standard professional language. "Manage the duties" is equally correct. "Capable of managing" converts it to an adjective phrase.', difficulty:'medium', type:'translation', tags:['can','responsibility','career'], usageNote:'"Handle responsibilities" (dynamic), "manage duties" (administrative), "take on the role" (ownership) — different angles.', office:'I can handle the responsibilities of this new role — I have prepared extensively for this transition.', conversation:'A: It is a demanding position. B: I can handle the responsibilities of this new role — I am ready.' },
  { id:'d16-extra-230', hindi:'क्या हम इस सप्ताह में अपना लक्ष्य पूरा कर सकते हैं?', english:'Can we achieve our target this week?', alternatives:['can we meet our goal this week?'], hint:'Can + we + achieve + our target + this week', explanation:'"Achieve our target" is standard business language. "Meet our goal" is slightly more casual. Both are appropriate in professional settings.', difficulty:'easy', type:'translation', tags:['can','target','business'], usageNote:'"Target" (measurable), "goal" (broader) — both used in business, with "target" being more specific.', office:'Can we achieve our target this week given the current pipeline?', conversation:'A: Can we achieve our target this week? B: If we push for two more deals, yes.' },
  { id:'d16-extra-231', hindi:'वह एक अच्छे नेता के गुण रखती है।', english:'She can be a good leader.', alternatives:['she has the qualities of a good leader.','she is capable of being a great leader.'], hint:'Can + be + a good leader (potential)', explanation:'"Can be a good leader" uses can for potential. "Has the qualities of a leader" is a factual statement. Both are appropriate for performance reviews or recommendations.', difficulty:'medium', type:'translation', tags:['can','leadership','potential'], usageNote:'"Can be" (potential/future) vs. "is" (current state) — choose based on whether potential or reality.', office:'She can be a good leader — she already demonstrates all the right qualities.', conversation:'A: Is she management material? B: She can be a good leader — she needs the right opportunity.' },
  { id:'d16-extra-232', hindi:'मैं इस कार्यक्रम का प्रबंध कर सकता हूँ।', english:'I can manage this event.', alternatives:['I can organize this event.','I can coordinate this program.'], hint:'Can + manage + this event', explanation:'"Manage an event" covers all aspects of running it. "Organize" focuses on preparation. "Coordinate" focuses on multiple parties working together. Choose based on scope.', difficulty:'easy', type:'translation', tags:['can','event-management','organization'], usageNote:'"Manage" (all aspects), "organize" (plan and prepare), "coordinate" (align multiple parties).', office:'I can manage this event from start to finish — I have a solid team.', conversation:'A: We need an event manager. B: I can manage this event — I have done it three times.' },
  { id:'d16-extra-233', hindi:'क्या वे इस लक्ष्य को हासिल कर सकते हैं?', english:'Can they achieve this target?', alternatives:['are they able to reach this goal?'], hint:'Can + they + achieve + this target', explanation:'"Achieve this target" is standard professional language. "Reach this goal" is slightly more casual but equally correct. "Hit the target" is an informal idiom used in sales/business.', difficulty:'easy', type:'translation', tags:['can','target','business'], usageNote:'"Hit the target" is a sales idiom; "achieve the target" is the formal equivalent.', office:'Can they achieve this target by end of quarter with the current resources?', conversation:'A: Can they achieve this target? B: It is ambitious, but I think they can.' },
  { id:'d16-extra-234', hindi:'वह इस कंपनी की कल्चर में आसानी से फ़िट हो सकता है।', english:'He can easily fit into this company\'s culture.', alternatives:['he can adapt easily to this company\'s culture.'], hint:"Can + fit into + company's culture + easily", explanation:'"Fit into a culture" is a natural phrase meaning to adapt and blend naturally. "Adapt to a culture" emphasizes the active process of adjustment. Both are excellent hiring/onboarding phrases.', difficulty:'hard', type:'translation', tags:['can','culture-fit','adaptability'], usageNote:'"Culture fit" is the HR term. "Fit into" (natural blend) vs. "adapt to" (active process).', office:"He can easily fit into this company's culture — he shares our core values.", conversation:"A: Is he a good culture fit? B: He can easily fit into this company's culture — trust me." },
  { id:'d16-extra-235', hindi:'मैं अपनी ताकत और कमज़ोरियाँ अच्छे से जानती हूँ।', english:'I can identify my strengths and weaknesses clearly.', alternatives:['I am well aware of my strengths and weaknesses.'], hint:'Can + identify + strengths and weaknesses + clearly', explanation:'"Identify my strengths and weaknesses clearly" is a self-aware, interview-ready statement. "Well aware of" is the adjective equivalent. Self-awareness is a highly valued professional skill.', difficulty:'hard', type:'translation', tags:['can','self-awareness','interview'], usageNote:'"Strengths and weaknesses" is a classic interview topic. "Identify clearly" shows self-awareness.', office:'I can identify my strengths and weaknesses clearly — I do quarterly self-reviews.', conversation:'A: Can you assess your own performance? B: I can identify my strengths and weaknesses clearly.' },
  { id:'d16-extra-236', hindi:'क्या आप इस फ़ॉर्म को भर सकते हैं?', english:'Can you fill out this form?', alternatives:['could you complete this form?'], hint:'Can you + fill out + this form', explanation:'"Fill out" (AmE) and "fill in" (BrE) are both correct for completing a form. "Fill up" is Indian English and should be avoided in international contexts. "Complete this form" is the most formal option.', difficulty:'easy', type:'translation', tags:['can','forms','documentation'], usageNote:'"Fill out" (AmE), "fill in" (BrE), "complete" (formal) — avoid "fill up" in international settings.', office:'Can you fill out this form and submit it to HR before you leave today?', conversation:'A: Can you fill out this form? B: Of course — do I need to sign it as well?' },
  { id:'d16-extra-237', hindi:'वह किसी भी मुश्किल काम को आसान बना सकती है।', english:'She can make any difficult task seem easy.', alternatives:['she can simplify any complex task.'], hint:'Can + make + difficult task + seem easy', explanation:'"Make any difficult task seem easy" uses "seem" to describe perception. "Simplify complex tasks" is the formal equivalent. "Seem" can be replaced by "look" or "appear" — all are correct.', difficulty:'hard', type:'translation', tags:['can','expertise','simplification'], usageNote:'"Make X seem easy" uses "seem" for perception of ease. "Simplify" is the formal single-verb equivalent.', office:'She can make any difficult task seem easy — her expertise is immediately apparent.', conversation:'A: This project is so complex. B: She can make any difficult task seem easy — you will see.' },
  { id:'d16-extra-238', hindi:'मैं अपने दोस्तों के साथ अच्छे से घुल-मिल सकता हूँ।', english:'I can mix well with my friends.', alternatives:['I blend in well with my friends.','I get along well with my friends.'], hint:'Can + mix well + with my friends', explanation:'"Mix well with" is standard for social compatibility. "Blend in with" is idiomatic. "Get along well with" is the most widely used phrase for having good relationships.', difficulty:'medium', type:'translation', tags:['can','social','friendship'], usageNote:'"Get along with" is the most natural phrase for good relationships. "Mix with" is slightly formal.', office:'I can mix well with my friends and colleagues — strong interpersonal skills.', conversation:'A: How are you settling in? B: I can mix well with everyone here — great team.' },
  { id:'d16-extra-239', hindi:'क्या तुम यह काम शाम तक पूरा कर सकते हो?', english:'Can you complete this work by evening?', alternatives:['can you finish this by evening?'], hint:'Can you + complete + this work + by evening', explanation:'"By evening" uses "by" as a deadline preposition. "By evening" = before evening ends. "Until evening" would mean continuing up to evening, not finishing before it.', difficulty:'easy', type:'translation', tags:['can','deadline','evening'], usageNote:'"By" = deadline (complete by evening = before evening). "Until" = duration (work until evening = stop at evening).', office:'Can you complete this work by evening so we can review it in tomorrow\'s morning meeting?', conversation:'A: Can you complete this work by evening? B: Yes, I am almost done.' },
  { id:'d16-extra-240', hindi:'वह हर काम में पूरी मेहनत लगा सकता है।', english:'He can put his full effort into every task.', alternatives:['he gives 100% to everything he does.'], hint:'Can + put + full effort + into every task', explanation:'"Put full effort into" is a strong professional phrase. "Give 100%" is the idiomatic equivalent. Both express complete dedication. "Into" is the correct preposition after "put effort."', difficulty:'medium', type:'translation', tags:['can','dedication','work-ethic'], usageNote:'"Put effort into" (professional) vs. "give 100%" (idiomatic) — same meaning, different registers.', office:'He can put his full effort into every task — the quality of his work speaks for itself.', conversation:'A: Is he committed? B: He can put his full effort into every task — extremely dedicated.' },
  { id:'d16-extra-241', hindi:'मैं इस टीम के साथ बहुत कुछ हासिल कर सकती हूँ।', english:'I can achieve a great deal with this team.', alternatives:['I can accomplish a lot working with this team.'], hint:'Can + achieve + a great deal + with this team', explanation:'"A great deal" is a formal/neutral phrase for "a lot." "This team" emphasizes the collective power. "With this team" specifies the collaboration.', difficulty:'medium', type:'translation', tags:['can','teamwork','achievement'], usageNote:'"A great deal" is formal. "A lot" is informal. Both are natural in different registers.', office:'I can achieve a great deal with this team — they are talented and motivated.', conversation:'A: What do you think of the team? B: I can achieve a great deal with this team.' },
  { id:'d16-extra-242', hindi:'क्या वह इस परियोजना में अपना 100% दे सकता है?', english:'Can he give his 100% to this project?', alternatives:['can he commit fully to this project?'], hint:'Can + give + 100% + to this project', explanation:'"Give 100%" is an idiomatic expression for full commitment and effort. "Commit fully" is more formal. "Give his all" is another natural idiom.', difficulty:'medium', type:'translation', tags:['can','commitment','dedication'], usageNote:'"Give 100%" and "give his all" are idioms for total commitment. "Commit fully" is formal.', office:'Can he give his 100% to this project? We cannot afford half-measures here.', conversation:"A: Can he give his 100% to this project? B: Absolutely — he is fully committed." },
  { id:'d16-extra-243', hindi:'वे बिना किसी समस्या के इस काम को कर सकते हैं।', english:'They can do this work without any problem.', alternatives:['they can handle this work easily.','they can do this work with no difficulty.'], hint:'Can + do this work + without any problem', explanation:'"Without any problem" is a confidence-expressing phrase. "With no difficulty" is its formal equivalent. "Easily" compresses the same meaning into one adverb.', difficulty:'easy', type:'translation', tags:['can','confidence','ease'], usageNote:'"Without any problem" (spoken), "with no difficulty" (formal), "easily" (concise) — same meaning.', office:'They can do this work without any problem — they have done it multiple times before.', conversation:'A: Is this too complex for them? B: They can do this work without any problem.' },
  { id:'d16-extra-244', hindi:'मैं इस चुनौती से सीख सकती हूँ।', english:'I can learn from this challenge.', alternatives:['I can grow from this experience.','I can take away lessons from this challenge.'], hint:'Can + learn + from this challenge', explanation:'"Learn from a challenge" shows a growth mindset. "Take away lessons" is more specific. "Grow from this experience" is more personal development-oriented. All are strong interview phrases.', difficulty:'medium', type:'translation', tags:['can','growth-mindset','challenges'], usageNote:'"Growth mindset" responses: "learn from challenge," "grow from experience," "take away lessons" — all excellent.', office:'I can learn from this challenge and apply those lessons to future projects.', conversation:'A: This project did not go well. B: I can learn from this challenge — every failure teaches something.' },
  { id:'d16-extra-245', hindi:'क्या तुम इस मुद्दे को सुलझाने में मेरी मदद कर सकते हो?', english:'Can you help me resolve this issue?', alternatives:['can you assist me in resolving this issue?'], hint:'Can you + help me + resolve + this issue', explanation:'"Help me resolve" uses the bare infinitive (help + object + bare infinitive). "Assist me in resolving" uses a gerund after "in." Both are grammatically correct.', difficulty:'medium', type:'translation', tags:['can','help','problem-solving'], usageNote:'"Help someone resolve" (bare infinitive) and "assist someone in resolving" (gerund) are both correct.', office:'Can you help me resolve this issue with the vendor before the board meeting?', conversation:'A: Can you help me resolve this issue? B: Yes, let us look at it together.' },
  { id:'d16-extra-246', hindi:'वह इस प्रतियोगिता में जीत सकता है।', english:'He can win this competition.', alternatives:['he is capable of winning this competition.','he has what it takes to win this competition.'], hint:'Can + win + this competition', explanation:'"Can win" expresses current potential ability. "Has what it takes" is an idiomatic phrase meaning possessing all necessary qualities. Both are motivating and confident.', difficulty:'medium', type:'translation', tags:['can','competition','winning'], usageNote:'"Has what it takes" is an idiomatic phrase meaning to possess the required qualities for success.', office:'He can win this competition — his preparation has been thorough and strategic.', conversation:'A: Is he ready? B: He can win this competition — I have complete faith in him.' },
  { id:'d16-extra-247', hindi:'मैं पाँच साल में अपना व्यवसाय शुरू कर सकता हूँ।', english:'I can start my own business in five years.', alternatives:['I can launch my own company within five years.'], hint:'Can + start + my own business + in five years', explanation:'"Start my own business in five years" sets a time frame for a goal. "Launch a company" is slightly more formal. "Within five years" suggests anytime before the five-year mark.', difficulty:'medium', type:'translation', tags:['can','entrepreneurship','goals'], usageNote:'"In five years" (at the end of five years) vs. "within five years" (before five years pass) — nuanced.', office:'I can start my own business in five years — that is part of my long-term career plan.', conversation:'A: What is your five-year plan? B: I can start my own business in five years.' },
  { id:'d16-extra-248', hindi:'क्या वह इस पद पर काम कर सकती है?', english:'Can she work in this position?', alternatives:['is she suitable for this position?','can she perform in this role?'], hint:'Can she + work + in this position', explanation:'"Work in this position" questions suitability or ability. "Perform in this role" focuses on performance. "Suitable for" questions fit. Each has a slightly different emphasis.', difficulty:'medium', type:'translation', tags:['can','suitability','position'], usageNote:'"Work in a position" (ability/suitability), "perform in a role" (performance quality) — subtle difference.', office:'Can she work in this position while the department head is on sabbatical?', conversation:'A: Can she work in this position? B: Yes — she is very capable and experienced.' },
  { id:'d16-extra-249', hindi:'वह पूरी ज़िम्मेदारी अपने कंधों पर उठा सकता है।', english:'He can take on full responsibility.', alternatives:['he can shoulder full responsibility.'], hint:'Can + take on + full responsibility', explanation:'"Take on responsibility" uses the phrasal verb "take on" meaning to accept. "Shoulder responsibility" is idiomatic (shoulder = bear/carry). Both are natural and strong in professional contexts.', difficulty:'hard', type:'translation', tags:['can','responsibility','leadership'], usageNote:'"Shoulder responsibility" is metaphorical (like carrying a burden). "Take on" is the standard phrasal verb.', office:'He can take on full responsibility for the project when the director is travelling.', conversation:'A: Who will be accountable? B: He can take on full responsibility — he is experienced enough.' },
  { id:'d16-extra-250', hindi:'मैं इस काम में बहुत अच्छे परिणाम दे सकती हूँ।', english:'I can deliver excellent results in this work.', alternatives:['I can produce great outcomes in this role.'], hint:'Can + deliver + excellent results + in this work', explanation:'"Deliver excellent results" is powerful business language. "Deliver" is stronger than "provide" or "give" in this context — it implies full execution and completion.', difficulty:'medium', type:'translation', tags:['can','results','performance'], usageNote:'"Deliver results" is a strong business phrase implying both effort and achievement.', office:'I can deliver excellent results in this work — my track record speaks for itself.', conversation:'A: Why should we choose you? B: I can deliver excellent results in this work — consistently.' },
  { id:'d16-extra-251', hindi:'क्या वे इस कार्य को बेहतर तरीके से कर सकते हैं?', english:'Can they do this task better?', alternatives:['can they improve on this task?','is there a way they can do this better?'], hint:'Can + they + do + this task + better (comparative)', explanation:'"Do this task better" uses "better" as a comparative adverb. "Improve on this task" is more specific. "Is there a way they can do this better?" is a softer, more constructive phrasing.', difficulty:'medium', type:'translation', tags:['can','improvement','performance'], usageNote:'"Better" as an adverb (do better) vs. "well" (do well) — "better" is comparative; "well" is positive degree.', office:'Can they do this task better if we provide clearer specifications?', conversation:'A: The output was mediocre. B: Can they do this task better? Let me brief them again.' },
  { id:'d16-extra-252', hindi:'वह किसी भी काम को जल्दी और सही तरीके से कर सकती है।', english:'She can do any work quickly and correctly.', alternatives:['she can complete any task accurately and efficiently.'], hint:'Can + do + any work + quickly and correctly (two adverbs)', explanation:'"Quickly and correctly" are two adverbs joined by "and." They both modify "do." In formal writing, "accurately and efficiently" is preferred. The key is using adverbs (-ly form) not adjectives.', difficulty:'medium', type:'translation', tags:['can','efficiency','accuracy'], usageNote:'"Accurately and efficiently" is formal; "quickly and correctly" is natural and direct.', office:'She can do any work quickly and correctly — no need for multiple revisions.', conversation:'A: Is she good? B: She can do any work quickly and correctly — very impressive.' },
  { id:'d16-extra-253', hindi:'मैं इस रिपोर्ट को जल्दी से पढ़ सकता हूँ।', english:'I can read this report quickly.', alternatives:['I can go through this report quickly.','I can skim this report quickly.'], hint:'Can + read + this report + quickly', explanation:'"Read quickly" is natural. "Go through" is slightly more informal — it suggests reviewing. "Skim" means to read quickly without full attention to detail. Choose based on how thoroughly you read.', difficulty:'easy', type:'translation', tags:['can','reading','speed'], usageNote:'"Read" (full), "go through" (review), "skim" (quick overview), "scan" (looking for specific info).', office:'I can read this report quickly and give you my feedback before the meeting.', conversation:'A: It is a 50-page report. B: I can read this report quickly — give me half an hour.' },
  { id:'d16-extra-254', hindi:'क्या हम इस समस्या का हल ढूंढ सकते हैं?', english:'Can we find a solution to this problem?', alternatives:['can we resolve this problem?','is there a solution we can find?'], hint:'Can we + find + a solution + to this problem', explanation:'"Find a solution to" uses "to" after solution. "Resolve this problem" is the single-verb equivalent. "Is there a solution?" makes it more exploratory rather than a claim of ability.', difficulty:'medium', type:'translation', tags:['can','problem-solving','teamwork'], usageNote:'"Find a solution to" is the standard collocation. "Resolve" is more action-oriented and definitive.', office:'Can we find a solution to this problem before the client escalates further?', conversation:'A: We are stuck. B: Can we find a solution to this problem? Let us brainstorm together.' },
  { id:'d16-extra-255', hindi:'वह अपनी बात को बहुत प्रभावशाली ढंग से रख सकता है।', english:'He can present his point very effectively.', alternatives:['he can make his point very persuasively.'], hint:'Can + present + his point + very effectively', explanation:'"Present his point effectively" shows clear communication skills. "Make his point persuasively" adds the element of convincing others. Both are strong for interviews/presentations.', difficulty:'hard', type:'translation', tags:['can','communication','persuasion'], usageNote:'"Present effectively" (clarity), "make the point persuasively" (persuasion) — two aspects of communication.', office:'He can present his point very effectively — clear, concise, and data-driven.', conversation:'A: Is he a good communicator? B: He can present his point very effectively — always compelling.' },
  { id:'d16-extra-256', hindi:'मैं अपने कमज़ोर क्षेत्रों में सुधार कर सकती हूँ।', english:'I can improve in my weak areas.', alternatives:['I can work on my weaknesses.','I can develop in areas where I need improvement.'], hint:'Can + improve + in my weak areas', explanation:'"Improve in my weak areas" shows self-awareness and commitment to growth. "Work on my weaknesses" is the conversational equivalent. "Develop in areas of improvement" is formal and interview-ready.', difficulty:'hard', type:'translation', tags:['can','self-improvement','interview'], usageNote:'"Work on weaknesses" and "develop in areas of improvement" are both excellent interview phrases.', office:'I can improve in my weak areas through targeted training and mentoring.', conversation:'A: What is your weakness? B: I can improve in my weak areas — I am already working on my public speaking.' },
  { id:'d16-extra-257', hindi:'क्या वह इस परियोजना को समय पर पूरा कर सकती है?', english:'Can she complete this project on time?', alternatives:['is she able to deliver this project on schedule?'], hint:'Can she + complete + this project + on time', explanation:'"Complete on time" is standard. "Deliver on schedule" is more formal and specific to output. Both are natural in professional project management communication.', difficulty:'easy', type:'translation', tags:['can','deadline','project-management'], usageNote:'"Complete on time" (general) and "deliver on schedule" (project-specific) are equivalent.', office:'Can she complete this project on time given the current scope and resources?', conversation:'A: Can she complete this project on time? B: Yes, she has never missed a deadline.' },
  { id:'d16-extra-258', hindi:'वे हर मुश्किल काम को अपनी मेहनत से हल कर सकते हैं।', english:'They can solve every difficult task with their hard work.', alternatives:['they can overcome any difficult task through sheer hard work.'], hint:'Can + solve + every difficult task + with hard work', explanation:'"With their hard work" is an instrumental phrase showing means. "Through sheer hard work" adds emphasis ("sheer" means nothing but). Both are motivating and professional.', difficulty:'hard', type:'translation', tags:['can','hard-work','perseverance'], usageNote:'"Through sheer hard work" is emphatic — "sheer" emphasizes that hard work alone is the reason.', office:'They can solve every difficult task with their hard work — outstanding team.', conversation:'A: This is a very hard assignment. B: They can solve every difficult task with their hard work.' },
  { id:'d16-extra-259', hindi:'मैं इस देश में कहीं भी नौकरी कर सकता हूँ।', english:'I can work anywhere in this country.', alternatives:['I am willing to work anywhere in this country.'], hint:'Can + work + anywhere + in this country', explanation:'"Work anywhere in this country" shows geographic flexibility. "Willing to work" adds a motivational element — you want to, not just can. Both are strong in job applications.', difficulty:'medium', type:'translation', tags:['can','flexibility','job-search'], usageNote:'"Can work anywhere" (ability/flexibility) vs. "willing to work anywhere" (motivation/readiness).', office:'I can work anywhere in this country — relocation is not an issue for me.', conversation:'A: The posting is in a remote location. B: I can work anywhere in this country — I am flexible.' },
  { id:'d16-extra-260', hindi:'क्या तुम बिना किसी के सहारे यह काम कर सकते हो?', english:'Can you do this work without any support?', alternatives:['can you manage this independently?','are you able to handle this without help?'], hint:'Can you + do this work + without any support', explanation:'"Without any support" emphasizes complete independence. "Independently" is the single-adverb equivalent. "Without help" is more casual. All three are natural.', difficulty:'medium', type:'translation', tags:['can','independence','self-reliance'], usageNote:'"Without any support," "independently," and "on your own" — from phrase to adverb to idiom.', office:'Can you do this work without any support? Our team capacity is very limited right now.', conversation:'A: Can you do this work without any support? B: Yes, I have all the resources I need.' },
  { id:'d16-extra-261', hindi:'वह रात को देर तक पढ़ सकती है।', english:'She can study late into the night.', alternatives:['she can study until late at night.'], hint:'Can + study + late into the night', explanation:'"Late into the night" is more vivid than "late at night" — it suggests extending deep into the night hours. "Until late at night" is cleaner and equally correct.', difficulty:'medium', type:'translation', tags:['can','studying','dedication'], usageNote:'"Late into the night" is more evocative/literary than the simpler "until late at night."', office:'She can study late into the night for the professional certification exam.', conversation:'A: The exam is tomorrow. B: She can study late into the night — she always does before exams.' },
  { id:'d16-extra-262', hindi:'मैं इस समस्या को एक नए दृष्टिकोण से देख सकता हूँ।', english:'I can look at this problem from a new perspective.', alternatives:['I can approach this problem differently.'], hint:'Can + look at + this problem + from a new perspective', explanation:'"Look at from a new perspective" is a classic innovation phrase. "Approach differently" is more action-oriented. "New perspective" = fresh viewpoint uncontaminated by existing assumptions.', difficulty:'hard', type:'translation', tags:['can','innovation','perspective'], usageNote:'"Bring a fresh perspective" and "look at from a new angle" are both business innovation phrases.', office:'I can look at this problem from a new perspective — sometimes outsider views reveal solutions.', conversation:'A: We are stuck on this. B: I can look at this problem from a new perspective.' },
  { id:'d16-extra-263', hindi:'क्या वे अपनी गलतियों से सीख सकते हैं?', english:'Can they learn from their mistakes?', alternatives:['are they able to grow from their mistakes?'], hint:'Can + they + learn + from their mistakes', explanation:'"Learn from mistakes" is a growth mindset phrase. "Grow from mistakes" adds a personal development dimension. Both are excellent for performance reviews and coaching conversations.', difficulty:'medium', type:'translation', tags:['can','growth-mindset','mistakes'], usageNote:'"Learn from mistakes" (knowledge) and "grow from mistakes" (development) — slightly different emphases.', office:'Can they learn from their mistakes and apply those insights to the next project?', conversation:'A: They made many errors this quarter. B: Can they learn from their mistakes? That matters more.' },
  { id:'d16-extra-264', hindi:'वह बहुत जल्दी नई चीज़ें सीख सकती है।', english:'She can learn new things very quickly.', alternatives:['she picks up new things very quickly.'], hint:'Can + learn + new things + very quickly', explanation:'"Learn new things quickly" shows adaptability. "Pick up new things" is idiomatic — "pick up" means to learn informally/naturally. Both are excellent interview phrases.', difficulty:'easy', type:'translation', tags:['can','learning','adaptability'], usageNote:'"Pick up" is an idiomatic phrasal verb meaning to learn casually and quickly.', office:'She can learn new things very quickly — minimal training time needed.', conversation:'A: Our system is quite unique. B: She can learn new things very quickly — no worries.' },
  { id:'d16-extra-265', hindi:'मैं अपने काम की गुणवत्ता से कोई समझौता नहीं कर सकता।', english:"I can't compromise on the quality of my work.", alternatives:["I won't compromise on quality.","quality is non-negotiable for me."], hint:"Can't + compromise + on + quality of my work", explanation:'"Can\'t compromise on quality" is a strong professional statement. "Won\'t compromise" shows willpower. "Quality is non-negotiable" is the declarative business version. All are powerful.', difficulty:'hard', type:'translation', tags:['can','quality','standards'], usageNote:'"Non-negotiable" is a strong business term for something that cannot be changed or reduced.', office:"I can't compromise on the quality of my work — let's request an extension if needed.", conversation:"A: Can we cut some corners? B: I can't compromise on the quality of my work. Let's think of another way." },
  { id:'d16-extra-266', hindi:'क्या हम मिलकर कुछ बड़ा हासिल कर सकते हैं?', english:'Can we achieve something big together?', alternatives:['can we accomplish great things as a team?'], hint:'Can we + achieve + something big + together', explanation:'"Achieve something big together" is motivational and team-oriented. "Accomplish great things as a team" is more formal. Both are excellent for team meetings and speeches.', difficulty:'medium', type:'translation', tags:['can','teamwork','ambition'], usageNote:'"Together" is powerful for motivation. "As a team" adds structural emphasis to the collaboration.', office:'Can we achieve something big together this year? I believe this team has the potential.', conversation:'A: Can we achieve something big together? B: Absolutely — let us set an ambitious goal.' },
  { id:'d16-extra-267', hindi:'वह किसी भी ग्राहक की समस्या हल कर सकती है।', english:'She can solve any client\'s problem.', alternatives:['she can resolve any customer issue.'], hint:"Can + solve + any client's problem", explanation:'"Solve a client\'s problem" is standard for customer-facing roles. "Resolve a customer issue" is slightly more formal and process-oriented. Both are natural in CRM/service contexts.', difficulty:'medium', type:'translation', tags:['can','customer-service','problem-solving'], usageNote:'"Client" (B2B), "customer" (B2C) — the distinction matters in professional communication.', office:"She can solve any client's problem — she is our best relationship manager.", conversation:"A: The client is upset. B: She can solve any client's problem — put her on the call." },
  { id:'d16-extra-268', hindi:'मैं इस प्रोजेक्ट को बेहतरीन तरीके से पूरा कर सकता हूँ।', english:'I can complete this project in the best possible way.', alternatives:['I can deliver this project to the highest standard.'], hint:'Can + complete + project + in the best possible way', explanation:'"In the best possible way" means as well as it can be done. "To the highest standard" is the formal business equivalent. "Best possible" and "highest standard" both express maximum quality.', difficulty:'medium', type:'translation', tags:['can','quality','project'], usageNote:'"To the highest standard" is a powerful quality commitment phrase in professional communication.', office:'I can complete this project in the best possible way if given the right resources.', conversation:'A: What can we expect from you? B: I can complete this project in the best possible way.' },
  { id:'d16-extra-269', hindi:'क्या तुम इस जानकारी को सुरक्षित रख सकते हो?', english:'Can you keep this information safe?', alternatives:['can you safeguard this information?','can you keep this confidential?'], hint:'Can you + keep + this information + safe', explanation:'"Keep information safe" means to protect it. "Safeguard" is more formal. "Keep it confidential" specifically means not sharing it. The right choice depends on the type of protection needed.', difficulty:'medium', type:'translation', tags:['can','confidentiality','security'], usageNote:'"Safe" (physical/digital security), "confidential" (secrecy/non-disclosure), "safeguard" (formal protection).', office:'Can you keep this information safe? It contains sensitive financial data.', conversation:'A: This is classified. B: Can you keep this information safe? C: Yes, I understand the sensitivity.' },
  { id:'d16-extra-270', hindi:'वे आपस में बहुत अच्छे से बात कर सकते हैं।', english:'They can communicate very well with each other.', alternatives:['they have excellent communication with each other.'], hint:'Can + communicate + very well + with each other', explanation:'"Communicate very well with each other" emphasizes the quality of mutual communication. "Excellent communication between them" converts it to a noun phrase for formal reports.', difficulty:'medium', type:'translation', tags:['can','communication','teamwork'], usageNote:'"Communicate with each other" (verb) and "excellent communication between them" (noun phrase) — both professional.', office:'They can communicate very well with each other — this co-leadership arrangement will work.', conversation:'A: Do they get along? B: They can communicate very well with each other — a great team.' },
  { id:'d16-extra-271', hindi:'मैं किसी भी मंच पर बोल सकता हूँ।', english:'I can speak on any platform.', alternatives:['I can address any audience.','I can present at any forum.'], hint:'Can + speak + on any platform', explanation:'"Speak on any platform" can mean any stage/medium. "Address any audience" focuses on the listeners. "Present at any forum" is formal and conference-specific. All are strong.', difficulty:'medium', type:'translation', tags:['can','public-speaking','confidence'], usageNote:'"Platform" (medium/stage), "audience" (listeners), "forum" (formal discussion event) — different emphases.', office:'I can speak on any platform — boardrooms, conferences, or virtual webinars.', conversation:'A: Can you handle the keynote? B: I can speak on any platform — just tell me the topic.' },
  { id:'d16-extra-272', hindi:'क्या वह अपने काम की खुद समीक्षा कर सकती है?', english:'Can she review her own work?', alternatives:['is she able to self-review her work?'], hint:'Can she + review + her own work', explanation:'"Review her own work" = self-editing/proofreading. "Self-review" is the compound noun used in performance management. Both are appropriate in professional contexts.', difficulty:'medium', type:'translation', tags:['can','self-review','quality'], usageNote:'"Self-review" and "review one\'s own work" — the former is the HR/performance management term.', office:'Can she review her own work before submitting? That will reduce revision cycles.', conversation:'A: Who will proofread this? B: Can she review her own work first? Then we can do a final check.' },
  { id:'d16-extra-273', hindi:'वह खुद को बाज़ार में स्थापित कर सकता है।', english:'He can establish himself in the market.', alternatives:['he can make a name for himself in the market.','he can build his brand in the market.'], hint:'Can + establish himself + in the market', explanation:'"Establish himself" means to build a strong, recognized position. "Make a name for himself" is idiomatic. "Build his brand" is the modern marketing/personal brand equivalent.', difficulty:'hard', type:'translation', tags:['can','entrepreneurship','branding'], usageNote:'"Make a name for oneself" is an idiom for becoming recognized and respected in a field.', office:'He can establish himself in the market within two years given his networking skills.', conversation:'A: He wants to go independent. B: He can establish himself in the market — he already has many contacts.' },
  { id:'d16-extra-274', hindi:'मैं इस जगह का सारा काम संभाल सकती हूँ।', english:'I can handle all the work here.', alternatives:['I can manage all the operations here.'], hint:'Can + handle + all the work + here', explanation:'"Handle all the work here" shows confidence in managing the full workload. "Manage all operations" is more formal and specific to operational management.', difficulty:'medium', type:'translation', tags:['can','management','responsibility'], usageNote:'"Handle work" (tasks/workload) vs. "manage operations" (processes/systems) — different aspects of responsibility.', office:'I can handle all the work here while the manager is on maternity leave.', conversation:'A: Who will look after things? B: I can handle all the work here — do not worry.' },
  { id:'d16-extra-275', hindi:'क्या तुम इस मामले में मुझे सलाह दे सकते हो?', english:'Can you advise me on this matter?', alternatives:['could you give me advice on this?','can you guide me on this issue?'], hint:'Can you + advise + me + on this matter', explanation:'"Advise someone on something" is the standard professional phrasing. "Give me advice on" separates the verb and noun. "Guide me on" is slightly less formal. "Counsel" is used in legal/therapeutic contexts.', difficulty:'medium', type:'translation', tags:['can','advice','professional'], usageNote:'"Advise on" (professional), "counsel on" (legal/therapeutic), "guide on" (mentoring) — different registers.', office:'Can you advise me on this matter before I send the proposal to the client?', conversation:'A: Can you advise me on this matter? B: Of course — sit down and walk me through it.' },
  { id:'d16-extra-276', hindi:'वह बिना किसी की परवाह किए सच बोल सकता है।', english:'He can speak the truth without caring what others think.', alternatives:['he can be honest regardless of others\' opinions.'], hint:'Can + speak the truth + without caring + what others think', explanation:'"Without caring what others think" uses a gerund clause after without. "Regardless of others\' opinions" is more concise and formal. Both express honest independence.', difficulty:'hard', type:'translation', tags:['can','honesty','courage'], usageNote:'"Regardless of others\' opinions" is formal. "Without caring what others think" is more vivid and natural.', office:'He can speak the truth without caring what others think — invaluable in senior advisory roles.', conversation:"A: Does he ever hold back? B: He can speak the truth without caring what others think — very direct." },
  { id:'d16-extra-277', hindi:'मैं इस काम को बहुत ध्यान से कर सकती हूँ।', english:'I can do this work with great care.', alternatives:['I can handle this work very carefully.'], hint:'Can + do this work + with great care', explanation:'"With great care" is a formal adverbial phrase. "Very carefully" converts it to a simple adverb form. Both express the same quality of careful attention.', difficulty:'easy', type:'translation', tags:['can','care','attention-to-detail'], usageNote:'"With great care" (formal phrase) and "very carefully" (adverb) — same meaning, different structure.', office:'I can do this work with great care — quality documentation is my specialty.', conversation:'A: This is delicate data. B: I can do this work with great care — you can trust me.' },
  { id:'d16-extra-278', hindi:'क्या वह इस विभाग को चला सकती है?', english:'Can she run this department?', alternatives:['is she able to manage this department?'], hint:'Can she + run + this department', explanation:'"Run a department" is the standard informal business phrase. "Manage" is more neutral/formal. "Head" means to be in charge. All three are correct in different registers.', difficulty:'medium', type:'translation', tags:['can','management','department'], usageNote:'"Run" (informal, dynamic), "manage" (formal, administrative), "head" (in charge) — leadership levels.', office:'Can she run this department during the restructuring period?', conversation:'A: Who will lead while the HOD is away? B: Can she run this department? She is the senior-most.' },
  { id:'d16-extra-279', hindi:'वे इस काम में एक दूसरे के पूरक हो सकते हैं।', english:'They can complement each other in this work.', alternatives:['they can support each other\'s strengths in this work.'], hint:'Can + complement + each other + in this work', explanation:'"Complement" means to add qualities the other lacks — different from "compliment" (to praise). "Complementary skills" is a powerful HR/team phrase. Never confuse complement and compliment.', difficulty:'hard', type:'translation', tags:['can','teamwork','complementary-skills'], usageNote:'"Complement" (add to each other\'s strengths) vs. "compliment" (praise) — do not confuse spelling or meaning.', office:'They can complement each other in this work — one has technical skills, the other has client skills.', conversation:'A: Why pair them? B: They can complement each other in this work — very different but balanced skill sets.' },
  { id:'d16-extra-280', hindi:'मैं इस जगह काम करके बहुत आगे बढ़ सकता हूँ।', english:'I can grow a lot by working here.', alternatives:['working here will help me grow significantly.'], hint:'Can + grow + a lot + by working here', explanation:'"Grow a lot by working here" shows career aspiration and motivation. "By working here" is a gerund phrase showing method. This is an excellent answer to "Why do you want this job?"', difficulty:'medium', type:'translation', tags:['can','career-growth','motivation'], usageNote:'"By + gerund" explains the means/method. "Grow" here means professional development.', office:'I can grow a lot by working here — this is the most innovative team in the industry.', conversation:'A: Why do you want this job? B: I can grow a lot by working here — your projects are cutting-edge.' },
  { id:'d16-extra-281', hindi:'क्या वह खुद को साबित कर सकता है?', english:'Can he prove himself?', alternatives:['is he able to demonstrate his abilities?','can he show what he is capable of?'], hint:'Can + prove + himself (reflexive)', explanation:'"Prove himself" uses the reflexive pronoun — proving one\'s own worth. "Demonstrate his abilities" is more formal. "Show what he is capable of" is the most elaborate version.', difficulty:'medium', type:'translation', tags:['can','self-proof','capability'], usageNote:'"Prove oneself" is a standard phrase for demonstrating one\'s value or worth.', office:'Can he prove himself in this stretch assignment? It will be an excellent test.', conversation:'A: Is he ready for the senior role? B: Can he prove himself? Give him a challenging project.' },
  { id:'d16-extra-282', hindi:'वे इस नई तकनीक का उपयोग कर सकते हैं।', english:'They can use this new technology.', alternatives:['they are able to work with this new technology.'], hint:'Can + use + this new technology', explanation:'"Use technology" is standard. "Work with technology" is slightly more active. "Leverage technology" is a business buzzword meaning to use it to gain advantage.', difficulty:'easy', type:'translation', tags:['can','technology','digital-skills'], usageNote:'"Use" (standard), "work with" (active), "leverage" (strategic advantage) — use "leverage" for business contexts.', office:'They can use this new technology to automate repetitive tasks and save time.', conversation:'A: Do they know the new system? B: They can use this new technology — we trained them last month.' },
  { id:'d16-extra-283', hindi:'मैं इस बैठक में सबके विचार सुन सकता हूँ।', english:'I can listen to everyone\'s ideas in this meeting.', alternatives:['I can hear out everyone in this meeting.'], hint:"Can + listen to + everyone's ideas + in this meeting", explanation:'"Listen to everyone\'s ideas" shows openness and inclusiveness. "Hear out everyone" is idiomatic — "hear someone out" means to listen to the complete point without interrupting.', difficulty:'medium', type:'translation', tags:['can','listening','meeting'], usageNote:'"Hear someone out" means to listen completely without interrupting — a strong leadership quality.', office:"I can listen to everyone's ideas in this meeting — all voices matter to our decision.", conversation:"A: The team has different opinions. B: I can listen to everyone's ideas in this meeting — let's go around the table." },
  { id:'d16-extra-284', hindi:'क्या वे इस बड़े प्रोजेक्ट को संभाल सकते हैं?', english:'Can they handle this large project?', alternatives:['are they equipped to manage this major project?'], hint:'Can + they + handle + this large project', explanation:'"Handle a large project" is direct and standard. "Equipped to manage" adds the idea that they have the necessary tools/skills. "Major project" is more formal than "large project."', difficulty:'medium', type:'translation', tags:['can','project-management','capacity'], usageNote:'"Large project" vs. "major project" — "major" implies importance and complexity; "large" implies size.', office:'Can they handle this large project with the current team size and resources?', conversation:'A: Can they handle this large project? B: Yes, they have done something similar before.' },
  { id:'d16-extra-285', hindi:'वह इस कंपनी में अपनी पहचान बना सकती है।', english:'She can make a name for herself in this company.', alternatives:['she can establish her reputation in this company.'], hint:'Can + make a name + for herself + in this company', explanation:'"Make a name for oneself" is an idiom meaning to become recognized and respected. "Establish her reputation" is the formal equivalent. Both are strong for career discussions.', difficulty:'hard', type:'translation', tags:['can','career','reputation'], usageNote:'"Make a name for oneself" is an idiomatic expression for building a professional reputation.', office:'She can make a name for herself in this company if given the right opportunities.', conversation:'A: She is very talented. B: She can make a name for herself in this company — watch this space.' },
  { id:'d16-extra-286', hindi:'मैं इस क्षेत्र में विशेषज्ञता हासिल कर सकता हूँ।', english:'I can gain expertise in this field.', alternatives:['I can become an expert in this domain.'], hint:'Can + gain expertise + in this field', explanation:'"Gain expertise" means to build specialized knowledge. "Become an expert" is the end-state description. "Domain" is more specific than "field" in tech/academic contexts.', difficulty:'medium', type:'translation', tags:['can','expertise','career'], usageNote:'"Field" (general area) and "domain" (specialized area, often technical) — "domain" is more specific.', office:'I can gain expertise in this field within a year with the right mentors and projects.', conversation:'A: Do you know this area well? B: Not yet, but I can gain expertise in this field quickly.' },
  { id:'d16-extra-287', hindi:'क्या वह इस पद की ज़िम्मेदारियाँ निभा सकती है?', english:'Can she fulfill the responsibilities of this position?', alternatives:['can she carry out the duties of this role?'], hint:'Can she + fulfill + responsibilities + of this position', explanation:'"Fulfill responsibilities" is standard formal phrasing. "Carry out duties" is slightly more action-oriented. "Fulfill" implies meeting both the letter and spirit of the role requirements.', difficulty:'hard', type:'translation', tags:['can','responsibility','position'], usageNote:'"Fulfill responsibilities" (meet requirements), "carry out duties" (perform tasks) — complementary meanings.', office:'Can she fulfill the responsibilities of this position, especially the client-facing aspects?', conversation:"A: She's quite junior. B: Can she fulfill the responsibilities of this position? She is very capable." },
  { id:'d16-extra-288', hindi:'वह अपनी भावनाओं पर नियंत्रण रख सकता है।', english:'He can control his emotions.', alternatives:['he can manage his emotions.','he has good emotional control.'], hint:'Can + control + his emotions', explanation:'"Control emotions" is direct. "Manage emotions" is the modern emotional intelligence (EQ) phrase. "Emotional control" or "emotional regulation" are the formal psychological terms.', difficulty:'medium', type:'translation', tags:['can','emotional-intelligence','self-control'], usageNote:'"Emotional regulation" and "emotional intelligence (EQ)" are professional/psychological terms for managing emotions.', office:'He can control his emotions under pressure — a key quality for client negotiations.', conversation:'A: The client was very rude. B: He can control his emotions — he handled it professionally.' },
  { id:'d16-extra-289', hindi:'मैं इस बाज़ार को अच्छे से समझ सकती हूँ।', english:'I can understand this market well.', alternatives:['I have a good understanding of this market.','I can read this market effectively.'], hint:'Can + understand + this market + well', explanation:'"Understand this market well" is direct. "Have a good understanding of" converts it to a noun phrase. "Read the market" is idiomatic for interpreting market trends.', difficulty:'medium', type:'translation', tags:['can','market-knowledge','business'], usageNote:'"Read the market" is a business idiom for interpreting and predicting market trends.', office:'I can understand this market well — I have been analyzing it for five years.', conversation:'A: What do you know about this sector? B: I can understand this market well — I worked in it for years.' },
  { id:'d16-extra-290', hindi:'क्या तुम इस काम को नई सोच के साथ कर सकते हो?', english:'Can you do this work with a fresh mindset?', alternatives:['can you approach this work with new thinking?'], hint:'Can you + do this work + with a fresh mindset', explanation:'"With a fresh mindset" is a modern business phrase. "Fresh" implies unencumbered by old assumptions. "New thinking" is the simpler equivalent. Both suggest innovation and openness.', difficulty:'hard', type:'translation', tags:['can','innovation','mindset'], usageNote:'"Fresh mindset" and "new perspective" are business phrases for unbiased, innovative thinking.', office:'Can you do this work with a fresh mindset? We have been too close to this problem.', conversation:'A: Can you do this work with a fresh mindset? B: Yes — I will approach it without any preconceptions.' },
  { id:'d16-extra-291', hindi:'वह इस उद्योग में लंबे समय तक टिक सकता है।', english:'He can sustain in this industry for a long time.', alternatives:['he can have a long career in this industry.'], hint:'Can + sustain + in this industry + for a long time', explanation:'"Sustain in an industry" means to remain successful over time. "Have a long career" is more explicit about the duration. "Thrive in an industry" goes further — not just surviving but excelling.', difficulty:'hard', type:'translation', tags:['can','career','industry'], usageNote:'"Sustain" (maintain position), "survive" (continue despite challenges), "thrive" (excel) — progression of success.', office:'He can sustain in this industry for a long time — adaptable and always learning.', conversation:'A: It is a very competitive field. B: He can sustain in this industry for a long time.' },
  { id:'d16-extra-292', hindi:'मैं इस टीम को सही दिशा में ले जा सकता हूँ।', english:'I can lead this team in the right direction.', alternatives:['I can guide this team toward the right goals.'], hint:'Can + lead + this team + in the right direction', explanation:'"Lead in the right direction" is a motivational, directional phrase. "Guide toward the right goals" adds goal orientation. "Steer in the right direction" is also natural — "steer" implies navigating through complexity.', difficulty:'hard', type:'translation', tags:['can','leadership','direction'], usageNote:'"Steer in the right direction" is idiomatic for navigating (from steering a ship/vehicle).', office:'I can lead this team in the right direction — I have a clear vision and strategy.', conversation:'A: The team seems lost. B: I can lead this team in the right direction — let me step in.' },
  { id:'d16-extra-293', hindi:'क्या वे इस नई प्रणाली को अपना सकते हैं?', english:'Can they adopt this new system?', alternatives:['can they adapt to this new system?'], hint:'Can + they + adopt + this new system', explanation:'"Adopt" means to take up and use something new. "Adapt to" means to adjust to it. Both are correct but different — adoption is the decision; adaptation is the process. They are often confused.', difficulty:'hard', type:'translation', tags:['can','adoption','change-management'], usageNote:'"Adopt" (take up/use) vs. "adapt to" (adjust/get used to) — do not confuse these.', office:'Can they adopt this new system within the first month of rollout?', conversation:'A: Can they adopt this new system? B: Yes, but they will need some training first.' },
  { id:'d16-extra-294', hindi:'वह नए विचार लाकर इस व्यवसाय को बेहतर बना सकती है।', english:'She can improve this business by bringing new ideas.', alternatives:['she can add value to this business with fresh ideas.'], hint:'Can + improve + business + by + bringing new ideas', explanation:'"Improve by bringing new ideas" uses a gerund phrase to show method. "Add value with fresh ideas" uses the business idiom "add value." Both are excellent for innovation roles.', difficulty:'hard', type:'translation', tags:['can','innovation','business'], usageNote:'"Add value" is a central business idiom meaning to contribute meaningfully. "Fresh ideas" = new thinking.', office:'She can improve this business by bringing new ideas from her diverse background.', conversation:"A: What value will she add? B: She can improve this business by bringing new ideas — she's very creative." },
  { id:'d16-extra-295', hindi:'मैं हर हाल में काम कर सकता हूँ।', english:'I can work in any circumstances.', alternatives:['I can work under any conditions.','I am adaptable to all work environments.'], hint:'Can + work + in any circumstances', explanation:'"In any circumstances" is slightly more formal. "Under any conditions" is more commonly used in professional contexts. "Adaptable to all environments" converts it to an adjective phrase.', difficulty:'medium', type:'translation', tags:['can','adaptability','resilience'], usageNote:'"Under any conditions" is the professional standard. "Circumstances" is broader and more formal.', office:'I can work in any circumstances — remote, field, or high-pressure office environments.', conversation:'A: The conditions are very challenging here. B: I can work in any circumstances — no problem.' },
  { id:'d16-extra-296', hindi:'क्या वह अपनी टीम के साथ इस परियोजना को पूरा कर सकता है?', english:'Can he complete this project with his team?', alternatives:['is he able to deliver this project with his team?'], hint:'Can + subject + complete + project + with his team', explanation:'"Complete a project with his team" emphasizes collaboration. "Deliver a project" is more result-oriented. Both are appropriate for project management contexts.', difficulty:'medium', type:'translation', tags:['can','project','teamwork'], usageNote:'"Complete" (finish) vs. "deliver" (produce and hand over) — "deliver" is stronger in client-facing contexts.', office:'Can he complete this project with his team before the Q4 board review?', conversation:'A: Can he complete this project with his team? B: Yes — they are a very capable group.' },
  { id:'d16-extra-297', hindi:'वे अपनी कंपनी को नई ऊँचाइयों पर ले जा सकते हैं।', english:'They can take their company to new heights.', alternatives:['they can elevate their company to new levels.'], hint:'Can + take + company + to new heights', explanation:'"Take to new heights" is an idiomatic phrase for achieving unprecedented success. "Elevate to new levels" is the formal equivalent. Both are powerful in business and motivational contexts.', difficulty:'hard', type:'translation', tags:['can','business-growth','leadership'], usageNote:'"Take to new heights" is a classic motivational business idiom for exceptional achievement.', office:'They can take their company to new heights with this merger strategy.', conversation:'A: What is their potential? B: They can take their company to new heights — visionary leaders.' },
  { id:'d16-extra-298', hindi:'मैं अपनी आदतें बदल सकती हूँ।', english:'I can change my habits.', alternatives:['I can transform my habits.','I am capable of changing my habits.'], hint:'Can + change + my habits', explanation:'"Change habits" is natural. "Transform habits" implies a deeper, more complete change. "Break habits" is used for negative habits you want to stop. "Build habits" is for forming new positive ones.', difficulty:'easy', type:'translation', tags:['can','self-improvement','habits'], usageNote:'"Change habits" (general), "break habits" (stop bad ones), "build habits" (form new ones), "transform habits" (deep change).', office:'I can change my habits to better align with the company\'s work culture.', conversation:'A: You seem to always procrastinate. B: I know — I can change my habits. I am working on it.' },
  { id:'d16-extra-299', hindi:'क्या वह इस संगठन में बड़े बदलाव ला सकती है?', english:'Can she bring major changes to this organization?', alternatives:['can she drive significant change in this organization?'], hint:'Can + bring + major changes + to this organization', explanation:'"Bring changes to" and "drive change in" — both are standard business phrases. "Drive change" is more dynamic and suggests actively pushing for transformation.', difficulty:'hard', type:'translation', tags:['can','change-management','leadership'], usageNote:'"Drive change" is a powerful business phrase for actively leading organizational transformation.', office:'Can she bring major changes to this organization? That is exactly what we need.', conversation:'A: Can she bring major changes to this organization? B: Yes — she is a transformational leader.' },
  { id:'d16-extra-300', hindi:'वे मिलकर इस दुनिया को बेहतर बना सकते हैं।', english:'They can make this world a better place together.', alternatives:['together, they can improve the world.'], hint:'Can + make + this world + a better place + together', explanation:'"Make this world a better place" is an iconic phrase often used in inspirational, CSR, and leadership contexts. "Together" at the end adds emphasis on collective power.', difficulty:'hard', type:'translation', tags:['can','inspiration','impact'], usageNote:'"Make the world a better place" is a classic inspirational phrase used in CSR, leadership, and mission statements.', office:'They can make this world a better place together through sustainable business practices.', conversation:'A: What is your mission? B: They can make this world a better place together — that is the vision.' },
];
